export interface SystemRegistry {
  manifests: SystemManifest[];
  actorSheets: ActorSheetRegistration[];
  diceFormulas: DiceFormulaRegistration[];
}

export function createSystemRegistry(): SystemRegistry {
  return { manifests: [], actorSheets: [], diceFormulas: [] };
}

export function registerSystem(registry: SystemRegistry, manifest: SystemManifest): SystemRegistry {
  validateSystemManifest(manifest);
  if (registry.manifests.some((item) => item.id === manifest.id)) throw new Error(`System id is already registered: ${manifest.id}`);
  if (registry.manifests.some((item) => item.name.toLocaleLowerCase() === manifest.name.toLocaleLowerCase())) throw new Error(`System name is already registered: ${manifest.name}`);
  return { ...registry, manifests: [...registry.manifests, manifest] };
}

export function registerActorSheet(registry: SystemRegistry, sheet: ActorSheetRegistration): SystemRegistry {
  return { ...registry, actorSheets: [...registry.actorSheets, sheet] };
}

export function registerDiceFormula(registry: SystemRegistry, formula: DiceFormulaRegistration): SystemRegistry {
  return { ...registry, diceFormulas: [...registry.diceFormulas, formula] };
}

export function validateSystemManifest(manifest: SystemManifest, options: { coreVersion?: string } = {}): void {
  const issues: string[] = [];
  if (!manifest || typeof manifest !== "object") {
    throw new SystemManifestValidationError(["System manifest must be an object"]);
  }
  const manifestKeys = new Set(["id", "name", "version", "compatibleCore", "entrypoints", "schemas", "permissions", "capabilities"]);
  const unknownManifestKeys = Object.keys(manifest).filter((key) => !manifestKeys.has(key));
  if (unknownManifestKeys.length) issues.push(`System manifest contains unknown fields: ${unknownManifestKeys.join(", ")}`);
  if (typeof manifest.id !== "string" || !/^[a-z0-9]+(?:-[a-z0-9]+)*$/.test(manifest.id) || manifest.id.length > 64) issues.push("System manifest id must be a lowercase kebab-case identifier of 64 characters or fewer");
  if (typeof manifest.name !== "string" || !manifest.name.trim() || manifest.name.trim().length > 120) issues.push("System manifest name must contain 1 to 120 characters");
  if (typeof manifest.version !== "string" || !parseSystemSemver(manifest.version)) issues.push("System manifest version must be a semantic version such as 1.0.0");
  if (typeof manifest.compatibleCore !== "string" || !manifest.compatibleCore.trim()) issues.push("System manifest requires a compatible core version range");
  else if (!systemCoreCompatibility(manifest.compatibleCore, options.coreVersion ?? OPEN_TABLETOP_CORE_VERSION).valid) issues.push("System manifest compatible core version range is invalid");
  else if (!systemCoreCompatibility(manifest.compatibleCore, options.coreVersion ?? OPEN_TABLETOP_CORE_VERSION).satisfied) issues.push(`System manifest is incompatible with OpenTabletop core ${options.coreVersion ?? OPEN_TABLETOP_CORE_VERSION}`);
  if (!manifest.entrypoints || typeof manifest.entrypoints !== "object" || Array.isArray(manifest.entrypoints)) {
    issues.push("System manifest requires entrypoints");
  } else {
    for (const [kind, path] of Object.entries(manifest.entrypoints)) {
      if (kind !== "client" && kind !== "server") issues.push(`Unknown system entrypoint: ${kind}`);
      if (path !== undefined && !safeSystemManifestPath(path)) issues.push(`System ${kind} entrypoint must be a safe relative package path`);
    }
  }
  if (!manifest.schemas || typeof manifest.schemas !== "object" || Array.isArray(manifest.schemas) || typeof manifest.schemas.actor !== "string" || !manifest.schemas.actor.trim() || typeof manifest.schemas.item !== "string" || !manifest.schemas.item.trim()) {
    issues.push("System manifest requires actor and item schemas");
  } else {
    const unknownSchemaKeys = Object.keys(manifest.schemas).filter((key) => key !== "actor" && key !== "item");
    if (unknownSchemaKeys.length) issues.push(`System manifest schemas contain unknown fields: ${unknownSchemaKeys.join(", ")}`);
    if (!safeSystemManifestPath(manifest.schemas.actor) || !safeSystemManifestPath(manifest.schemas.item)) issues.push("System actor and item schemas must use safe relative package paths");
  }
  if (!Array.isArray(manifest.permissions) || manifest.permissions.some((permission) => typeof permission !== "string" || !permission)) {
    issues.push("System manifest permissions must be an array of permission names");
  } else {
    const invalidPermissions = manifest.permissions.filter((permission) => !systemManifestPermissions.has(permission));
    if (invalidPermissions.length) issues.push(`System manifest requests unsupported permissions: ${[...new Set(invalidPermissions)].join(", ")}`);
    if (new Set(manifest.permissions).size !== manifest.permissions.length) issues.push("System manifest permissions must not contain duplicates");
  }
  if (!Array.isArray(manifest.capabilities) || manifest.capabilities.length === 0) issues.push("System manifest capabilities must be a non-empty array");
  else {
    const invalidCapabilities = manifest.capabilities.filter((capability) => !systemCapabilities.has(capability));
    if (invalidCapabilities.length) issues.push(`System manifest declares unknown capabilities: ${[...new Set(invalidCapabilities)].join(", ")}`);
    if (new Set(manifest.capabilities).size !== manifest.capabilities.length) issues.push("System manifest capabilities must not contain duplicates");
  }
  if (issues.length) throw new SystemManifestValidationError(issues);
}

export function systemCoreCompatibility(range: string, coreVersion = OPEN_TABLETOP_CORE_VERSION): { valid: boolean; satisfied: boolean } {
  if (typeof range !== "string" || range.length > 512) return { valid: false, satisfied: false };
  const current = parseSystemSemver(coreVersion);
  if (!current || !range.trim() || range.includes("||")) return { valid: false, satisfied: false };
  const comparators = range.trim().split(/\s+/);
  let valid = true;
  const satisfied = comparators.map((comparator) => {
    if (comparator === "*" || comparator.toLowerCase() === "x") return true;
    const match = /^(\^|~|>=|<=|>|<|=)?(.+)$/.exec(comparator);
    if (!match) {
      valid = false;
      return false;
    }
    const target = parseSystemSemver(match[2]!);
    if (!target) {
      valid = false;
      return false;
    }
    const operator = match[1] ?? "=";
    const comparison = compareSystemSemver(current, target);
    if (operator === ">=") return comparison >= 0;
    if (operator === "<=") return comparison <= 0;
    if (operator === ">") return comparison > 0;
    if (operator === "<") return comparison < 0;
    if (operator === "~") return comparison >= 0 && current.major === target.major && current.minor === target.minor;
    if (operator === "^") {
      if (target.major > 0n) return comparison >= 0 && current.major === target.major;
      if (target.minor > 0n) return comparison >= 0 && current.major === 0n && current.minor === target.minor;
      return comparison >= 0 && current.major === 0n && current.minor === 0n && current.patch === target.patch;
    }
    return comparison === 0;
  }).every(Boolean);
  return { valid, satisfied: valid && satisfied };
}

function safeSystemManifestPath(value: unknown): value is string {
  if (typeof value !== "string" || !value.trim() || value.length > 512 || value.includes("\\")) return false;
  if (/^[a-z][a-z0-9+.-]*:/i.test(value)) return false;
  const segments = value.split("/");
  return !segments.includes("..") && (value.startsWith("./") || value.startsWith("/systems/") || !value.startsWith("/"));
}

interface ParsedSystemSemver {
  major: bigint;
  minor: bigint;
  patch: bigint;
  prerelease: string[];
}

function parseSystemSemver(value: string): ParsedSystemSemver | undefined {
  if (value.length > 256) return undefined;
  const match = /^(0|[1-9]\d*)\.(0|[1-9]\d*)\.(0|[1-9]\d*)(?:-([0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*))?(?:\+[0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*)?$/.exec(value.trim());
  if (!match) return undefined;
  const prerelease = match[4]?.split(".") ?? [];
  if (prerelease.some((identifier) => /^\d+$/.test(identifier) && identifier.length > 1 && identifier.startsWith("0"))) return undefined;
  return { major: BigInt(match[1]!), minor: BigInt(match[2]!), patch: BigInt(match[3]!), prerelease };
}

function compareSystemSemver(left: ParsedSystemSemver, right: ParsedSystemSemver): number {
  for (const key of ["major", "minor", "patch"] as const) {
    if (left[key] < right[key]) return -1;
    if (left[key] > right[key]) return 1;
  }
  if (left.prerelease.length === 0 && right.prerelease.length === 0) return 0;
  if (left.prerelease.length === 0) return 1;
  if (right.prerelease.length === 0) return -1;
  const length = Math.max(left.prerelease.length, right.prerelease.length);
  for (let index = 0; index < length; index += 1) {
    const leftIdentifier = left.prerelease[index];
    const rightIdentifier = right.prerelease[index];
    if (leftIdentifier === undefined) return -1;
    if (rightIdentifier === undefined) return 1;
    const leftNumeric = /^\d+$/.test(leftIdentifier);
    const rightNumeric = /^\d+$/.test(rightIdentifier);
    if (leftNumeric && rightNumeric) {
      const leftNumber = BigInt(leftIdentifier);
      const rightNumber = BigInt(rightIdentifier);
      if (leftNumber < rightNumber) return -1;
      if (leftNumber > rightNumber) return 1;
      continue;
    }
    if (leftNumeric) return -1;
    if (rightNumeric) return 1;
    if (leftIdentifier < rightIdentifier) return -1;
    if (leftIdentifier > rightIdentifier) return 1;
  }
  return 0;
}

export function summarizeActor(actor: Actor): string {
  const hp = actor.data.hp as { current?: number; max?: number } | undefined;
  return `${actor.name}${hp ? ` (${hp.current ?? "?"}/${hp.max ?? "?"} HP)` : ""}`;
}

export function summarizeItem(item: Item): string {
  return `${item.name} [${item.type}]`;
}

export function abilityModifier(score: number): number {
  return Math.floor((score - 10) / 2);
}

function formatSignedNumber(value: number): string {
  return value >= 0 ? `+${value}` : String(value);
}

function appendFormulaBonus(formula: string, bonus: number): string {
  return `${formula}${formatSignedNumber(bonus)}`;
}

function appendFormulaTerm(formula: string, term: string): string {
  return term.startsWith("-") ? `${formula}${term}` : `${formula}+${term}`;
}

function slugId(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || "action";
}

function itemBelongsToActor(actor: Actor, item: Item): boolean {
  return item.actorId === actor.id;
}

export function genericFantasyAbilityCheck(actor: Actor, ability: string): QuickRoll {
  const modifier = genericFantasyAttributeModifier(actor, ability);
  const label = `${ability.charAt(0).toUpperCase()}${ability.slice(1)} Check`;
  const conditions = genericFantasyActorConditions(actor);
  const d20 = conditions.some((condition) => condition.id === "poisoned") ? "2d20kl1" : "1d20";
  const bonus = conditions.some((condition) => condition.id === "blessed") ? "+1d4" : "";
  return {
    id: `ability-${ability}`,
    label,
    formula: `${d20}${formatSignedNumber(modifier)}${bonus}`
  };
}

function genericFantasyActionMetadata(data: Record<string, unknown>, actionType: string, ability?: string): Record<string, unknown> | undefined {
  const metadata: Record<string, unknown> = { actionType };
  if (ability) metadata.ability = ability;
  let hasActionMetadata = false;
  const resourceCost = recordValue(data.resourceCost);
  const resource = stringValue(resourceCost.resource);
  const amount = Math.floor(numericValue(resourceCost.amount, 0));
  if (resource && amount > 0) {
    metadata.resourceCost = { resource, amount };
    hasActionMetadata = true;
  }
  const clearsCondition = stringValue(data.clearsCondition);
  if (clearsCondition) {
    metadata.clearsCondition = clearsCondition;
    hasActionMetadata = true;
  }
  const appliesCondition = stringValue(data.appliesCondition);
  if (appliesCondition) {
    metadata.appliesCondition = appliesCondition;
    hasActionMetadata = true;
  }
  if (booleanValue(data.consumable)) {
    metadata.consumable = true;
    hasActionMetadata = true;
  }
  const tags = normalizeStringArray(data.tags);
  if (tags.length > 0) {
    metadata.tags = tags;
    hasActionMetadata = true;
  }
  return hasActionMetadata ? metadata : undefined;
}

export function genericFantasyActionRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  return items.filter((item) => itemBelongsToActor(actor, item)).flatMap((item) => {
    const data = recordValue(item.data);
    const rolls: QuickRoll[] = [];
    const prefix = item.type === "spell" ? "spell" : "item";
    const damage = stringValue(data.damage);
    const ability = stringValue(data.ability);
    if (damage && ability) {
      const damageBonus = numericValue(data.damageBonus, 0);
      const metadata = genericFantasyActionMetadata(data, "damage", ability);
      rolls.push({
        id: `${prefix}-${item.id}-damage`,
        label: `${item.name} Damage`,
        formula: appendFormulaBonus(damage, genericFantasyAttributeModifier(actor, ability) + damageBonus),
        ...(metadata ? { metadata } : {})
      });
    }
    const damageFormula = stringValue(data.damageFormula);
    if (damageFormula) {
      const metadata = genericFantasyActionMetadata(data, "damage");
      rolls.push({
        id: `${prefix}-${item.id}-damage`,
        label: `${item.name} Damage`,
        formula: genericFantasyDamageFormula(actor, data),
        ...(metadata ? { metadata } : {})
      });
    }
    const secondaryDamageFormula = stringValue(data.secondaryDamageFormula);
    if (secondaryDamageFormula) {
      const metadata = genericFantasyActionMetadata(data, "secondary-damage");
      rolls.push({
        id: `${prefix}-${item.id}-secondary-damage`,
        label: `${item.name} Secondary Damage`,
        formula: genericFantasyDamageFormula(actor, data, undefined, "secondaryDamageFormula", "secondaryUpcastFormula"),
        ...(metadata ? { metadata } : {})
      });
    }
    const versatileDamage = stringValue(data.versatileDamage);
    if (versatileDamage && ability) {
      const damageBonus = numericValue(data.damageBonus, 0);
      const metadata = genericFantasyActionMetadata(data, "versatile-damage", ability);
      rolls.push({
        id: `${prefix}-${item.id}-versatile-damage`,
        label: `${item.name} Versatile Damage`,
        formula: appendFormulaBonus(versatileDamage, genericFantasyAttributeModifier(actor, ability) + damageBonus),
        ...(metadata ? { metadata } : {})
      });
    }
    const healingFormula = stringValue(data.healingFormula);
    if (healingFormula) {
      const metadata = genericFantasyActionMetadata(data, "healing");
      rolls.push({
        id: `${prefix}-${item.id}-healing`,
        label: `${item.name} Healing`,
        formula: genericFantasyHealingFormula(actor, data),
        ...(metadata ? { metadata } : {})
      });
    }
    const saveDcAbility = stringValue(data.saveDcAbility);
    const effectFormula = stringValue(data.effectFormula);
    if (saveDcAbility && effectFormula) {
      const metadata = genericFantasyActionMetadata(data, "effect", saveDcAbility);
      rolls.push({
        id: `${prefix}-${item.id}-effect`,
        label: `${item.name} Effect`,
        formula: appendFormulaBonus(effectFormula, genericFantasyAttributeModifier(actor, saveDcAbility)),
        ...(metadata ? { metadata } : {})
      });
    }
    return rolls;
  });
}

export function genericFantasyQuickRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  const attributes = actor.data.attributes as Record<string, number> | undefined;
  return [
    ...Object.keys(attributes ?? { strength: 10, dexterity: 10, constitution: 10, intelligence: 10, wisdom: 10, charisma: 10 }).map((ability) =>
      genericFantasyAbilityCheck(actor, ability)
    ),
    ...genericFantasyActionRolls(actor, items)
  ];
}

export function dnd5eSrdQuickRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  const abilities = dnd5eSrdAbilityKeys();
  return [
    ...abilities.map((ability) => dnd5eSrdAbilityCheck(actor, ability)),
    ...abilities.map((ability) => dnd5eSrdSavingThrow(actor, ability, items)),
    dnd5eSrdInitiativeRoll(actor),
    ...dnd5eSrdCoreCombatRolls(actor, items),
    ...dnd5eSrdSkills().map((skill) => dnd5eSrdSkillCheck(actor, skill.id)),
    ...dnd5eSrdToolProficiencies(actor, "toolProficiencies").map((toolId) => dnd5eSrdToolCheck(actor, toolId)),
    ...dnd5eSrdClassFeatureRolls(actor),
    ...dnd5eSrdSpeciesTraitRolls(actor),
    ...dnd5eSrdMonsterActionRolls(actor),
    ...dnd5eSrdActionRolls(actor, items)
  ];
}

