export function genericFantasyEncounterPlan(party: Actor[], selections: EncounterThreatSelection[]): EncounterPlan {
  return buildEncounterPlan({
    systemId: "generic-fantasy",
    partyRating: party.reduce((total, actor) => total + numericValue(actor.data.level, 1) * 100, 0) || 100,
    threats: genericFantasyEncounterThreats(),
    selections
  });
}

export function dnd5eSrdEncounterPlan(party: Actor[], selections: EncounterThreatSelection[]): EncounterPlan {
  const difficultyBudgets = dnd5eSrdEncounterXpBudgets(party);
  return buildEncounterPlan({
    systemId: DND_5E_SRD_SYSTEM_ID,
    partyRating: difficultyBudgets.hard || 100,
    threats: dnd5eSrdEncounterThreats(),
    selections,
    difficultyBudgets,
    difficultyForBudget: (budget) => dnd5eSrdEncounterDifficulty(budget, difficultyBudgets),
    budgetLabel: "XP"
  });
}


export function dnd5eSrdEncounterXpBudgets(party: Actor[]): { easy: number; standard: number; hard: number } {
  const levels = party.length > 0 ? party.map((actor) => numericValue(actor.data.level, 1)) : [1];
  return levels.reduce(
    (total, levelValue) => {
      const level = Math.min(20, Math.max(1, Math.floor(levelValue)));
      const budget = DND_5E_SRD_ENCOUNTER_XP_BUDGETS_BY_LEVEL[level] ?? DND_5E_SRD_ENCOUNTER_XP_BUDGETS_BY_LEVEL[1]!;
      return {
        easy: total.easy + budget.easy,
        standard: total.standard + budget.standard,
        hard: total.hard + budget.hard
      };
    },
    { easy: 0, standard: 0, hard: 0 }
  );
}

function dnd5eSrdEncounterDifficulty(threatBudget: number, budgets: { easy: number; standard: number; hard: number }): EncounterPlan["difficulty"] {
  if (threatBudget <= 0 || threatBudget < budgets.easy) return "trivial";
  if (threatBudget < budgets.standard) return "easy";
  if (threatBudget < budgets.hard) return "standard";
  if (threatBudget <= budgets.hard) return "hard";
  return "deadly";
}

export function genericFantasyAdvancementOptions(actor: Actor): AdvancementOption[] {
  const level = Math.max(1, Math.floor(numericValue(actor.data.level, 1)));
  if (level >= 20) return [];
  return [
    {
      id: "level-up",
      systemId: "generic-fantasy",
      name: `Level ${level + 1}`,
      summary: "Increase level, hit point maximum, proficiency, and the character's primary ability.",
      nextValue: level + 1
    }
  ];
}

export function dnd5eSrdAdvancementOptions(actor: Actor): AdvancementOption[] {
  const classes = dnd5eSrdActorClassLevels(actor);
  const effectiveActor = classes.length > 1
    ? { ...actor, data: { ...actor.data, level: classes.reduce((total, entry) => total + entry.level, 0) } }
    : actor;
  const advancementClassName = dnd5eSrdAdvancementClassName(actor);
  const nextClassLevel = (classes.find((entry) => entry.className.toLowerCase() === advancementClassName.toLowerCase())?.level ?? 0) + 1;
  const featGrant = dnd5eSrdAdvancementFeatGrant(advancementClassName, nextClassLevel, actor);
  return genericFantasyAdvancementOptions(effectiveActor).map((option) => ({
    ...option,
    systemId: DND_5E_SRD_SYSTEM_ID,
    summary: featGrant
      ? `Reach ${advancementClassName} level ${nextClassLevel}: increase hit points and choose ${featGrant === "epic-boon" ? "an Epic Boon" : "an Ability Score Improvement or a feat"}.`
      : "Increase level, hit point maximum, proficiency bonus, and class features for SRD 5.2.1 play."
  }));
}

export function applyGenericFantasyAdvancement(actor: Actor, optionId: string): Record<string, unknown> {
  const option = genericFantasyAdvancementOptions(actor).find((item) => item.id === optionId);
  if (!option) throw new Error(`Unknown advancement: ${optionId}`);
  const hp = actor.data.hp as { current?: number; max?: number } | undefined;
  const attributes = { ...((actor.data.attributes as Record<string, number> | undefined) ?? {}) };
  const className = typeof actor.data.class === "string" ? actor.data.class : "";
  const primaryAbility = className === "Mender" ? "wisdom" : "strength";
  attributes[primaryAbility] = numericValue(attributes[primaryAbility], 10) + 1;
  const features = normalizeStringArray(actor.data.features);
  const featureName = `${className || "Character"} Level ${option.nextValue}`;
  if (!features.includes(featureName)) features.push(featureName);
  const hitDice = actor.data.hitDice as { current?: number; max?: number; size?: string } | undefined;
  const spellSlots = normalizeResourcePools(actor.data.spellSlots, defaultGenericFantasySpellSlots(className, option.nextValue), { raiseMaxToDefault: true });
  const resources = normalizeResourcePools(actor.data.resources, defaultGenericFantasyResources(className));
  return {
    ...actor.data,
    level: option.nextValue,
    hp: {
      current: numericValue(hp?.current, numericValue(hp?.max, 10)) + 5,
      max: numericValue(hp?.max, 10) + 5
    },
    hitDice: {
      current: numericValue(hitDice?.current, numericValue(hitDice?.max, 1)) + 1,
      max: numericValue(hitDice?.max, 1) + 1,
      size: stringValue(hitDice?.size) ?? (className === "Mender" ? "d8" : "d10")
    },
    resources,
    spellSlots,
    attributes,
    proficiencyBonus: Math.max(2, 2 + Math.floor((option.nextValue - 1) / 4)),
    features
  };
}

export function applyDnd5eSrdAdvancement(actor: Actor, optionId: string, choices: Dnd5eSrdAdvancementChoices = {}): Record<string, unknown> {
  const option = dnd5eSrdAdvancementOptions(actor).find((item) => item.id === optionId);
  if (!option) throw new Error(`Unknown advancement: ${optionId}`);
  // A multiclass character's plain level-up advances its primary class through
  // the class-array recompute so features/resources stay per-class correct.
  const existingClasses = dnd5eSrdActorClassLevels(actor);
  if (existingClasses.length > 1) {
    const primary = dnd5eSrdAdvancementClassName(actor);
    const leveled = existingClasses.map((entry) => (entry.className === primary ? { ...entry, level: entry.level + 1 } : entry));
    return dnd5eSrdApplyClassLevels(actor, leveled, primary, choices);
  }
  const className = typeof actor.data.class === "string" ? actor.data.class : "Fighter";
  const level = option.nextValue;
  const classes = [{ className, level }];
  const subclasses = dnd5eSrdResolveAdvancementSubclasses(actor, classes, className, choices);
  const selectedSubclass = subclasses[className] ? dnd5eSrdSubclassOptionForActor(actor, className, subclasses[className]!) : undefined;
  const hitDieSize = dnd5eSrdClassHitDieSize(className, actor);
  const hpGain = dnd5eSrdAdvancementHitPointGain(actor, className, choices);
  const hp = normalizePool(actor.data.hp, 1);
  const hitDice = recordValue(actor.data.hitDice);
  const nextHitDice = {
    current: numericValue(hitDice.current, numericValue(hitDice.max, Math.max(1, level - 1))) + 1,
    max: numericValue(hitDice.max, Math.max(1, level - 1)) + 1,
    size: stringValue(hitDice.size) ?? hitDieSize
  };
  const attributes = { ...((actor.data.attributes as Record<string, number> | undefined) ?? {}) };
  const combinedFeatures = dnd5eSrdCombinedClassFeatures(actor, normalizeStringArray(actor.data.features), classes, subclasses);
  const baseData = {
    ...actor.data,
    level,
    classes,
    subclasses,
    ...(selectedSubclass ? { subclass: selectedSubclass.name } : {}),
    hp: { current: hp.current + hpGain, max: hp.max + hpGain },
    hitDice: nextHitDice,
    attributes,
    proficiencyBonus: Math.max(2, 2 + Math.floor((level - 1) / 4)),
    features: combinedFeatures
  };
  const advanced: Record<string, unknown> = {
    ...baseData,
    ruleset: DND_5E_SRD_VERSION,
    features: combinedFeatures,
    combat: dnd5eSrdApplyClassCombat(recordValue(actor.data.combat), className, level, actor.data.speed),
    resources: dnd5eSrdClassAdvancementProfile(actor, className)?.custom
      ? normalizeResourcePools(actor.data.resources)
      : normalizeDnd5eSrdResources(actor.data.resources, className, level, baseData, { raiseMaxToDefault: true }),
    spellSlots: dnd5eSrdAdvancementSpellSlots(actor, classes, className, level)
  };
  if (dnd5eSrdHasDwarvenToughnessData(actor.data)) dnd5eSrdApplyDwarvenToughness(advanced, 1);
  if (choices.weaponMasteryChoices !== undefined || "weaponMasteries" in actor.data || "weaponMasteriesByClass" in actor.data) {
    return applyDnd5eSrdWeaponMasteryAdvancement({ ...actor, data: advanced }, className, level, choices.weaponMasteryChoices);
  }
  return advanced;
}

export function applyGenericFantasyRest(actor: Actor, restType: SystemRestType): SystemRestResult {
  const hp = normalizePool(actor.data.hp, 1);
  const hitDiceRecord = recordValue(actor.data.hitDice);
  const hitDice = normalizePool(actor.data.hitDice, numericValue(actor.data.level, 1));
  const hitDieSize = stringValue(hitDiceRecord.size) ?? "d8";
  const resources = recoverResourcePools(actor.data.resources, restType);
  const spellSlots = restType === "long" ? recoverResourcePools(actor.data.spellSlots, "long") : { value: normalizeResourcePools(actor.data.spellSlots), recovered: {} };
  const recovered: Record<string, unknown> = {};
  let nextHp = hp;
  let nextHitDice = { ...hitDice, size: hitDieSize };
  if (restType === "short" && hp.current < hp.max && hitDice.current > 0) {
    const healAmount = Math.min(hp.max - hp.current, Math.max(1, averageHitDie(hitDieSize) + genericFantasyAttributeModifier(actor, "constitution")));
    nextHp = { ...hp, current: hp.current + healAmount };
    nextHitDice = { ...nextHitDice, current: hitDice.current - 1 };
    recovered.hp = healAmount;
    recovered.hitDiceSpent = 1;
  }
  if (restType === "long") {
    nextHp = { ...hp, current: hp.max };
    nextHitDice = { ...nextHitDice, current: Math.min(hitDice.max, hitDice.current + Math.max(1, Math.ceil(hitDice.max / 2))) };
    recovered.hp = Math.max(0, nextHp.current - hp.current);
    recovered.hitDiceRecovered = nextHitDice.current - hitDice.current;
  }
  const conditionUpdate = conditionsAfterRest(actor, genericFantasyCompendiumEntry, restType);
  const data = {
    ...actor.data,
    hp: nextHp,
    hitDice: nextHitDice,
    resources: resources.value,
    spellSlots: spellSlots.value,
    conditions: conditionUpdate.conditions
  };
  return {
    systemId: "generic-fantasy",
    actorId: actor.id,
    restType,
    summary: `${actor.name} completed a ${restType} rest`,
    recovered: { ...recovered, resources: resources.recovered, spellSlots: spellSlots.recovered },
    removedConditions: conditionUpdate.removed,
    data
  };
}

function dnd5eSrdApplyRestHitDice(
  actor: Actor,
  data: Record<string, unknown>,
  restType: SystemRestType,
  options: SystemRestOptions
): { data: Record<string, unknown>; recovered: Record<string, unknown> } {
  const classes = dnd5eSrdActorClassLevels(actor);
  const primaryClassName = dnd5eSrdPrimaryClassForHitDice(actor, classes);
  const aggregate = normalizePool(actor.data.hitDice, Math.max(1, numericValue(actor.data.level, 1)));
  const aggregateRecord = recordValue(actor.data.hitDice);
  const pools = classes.length > 1
    ? dnd5eSrdHitDicePoolsForClasses(actor, classes).map((pool) => ({ ...pool }))
    : [{
        className: primaryClassName,
        size: stringValue(aggregateRecord.size) ?? dnd5eSrdClassHitDieSize(primaryClassName, actor),
        current: aggregate.current,
        max: aggregate.max
      }];
  const hp = normalizePool(actor.data.hp, 1);
  let currentHp = restType === "long" ? hp.max : hp.current;
  const recovered: Record<string, unknown> = {};

  if (restType === "short") {
    const constitutionModifier = genericFantasyAttributeModifier(actor, "constitution");
    const spent: Array<{ className: string; size: string; roll: number; modifier: number; healed: number }> = [];
    for (const selection of options.hitDice ?? []) {
      if (currentHp >= hp.max) break;
      const selectedClassName = selection.className ?? (classes.length <= 1 ? primaryClassName : undefined);
      if (!selectedClassName) throw new Error("A className is required when spending a multiclass Hit Point Die");
      const pool = pools.find((candidate) => candidate.className.toLowerCase() === selectedClassName.toLowerCase());
      if (!pool) throw new Error(`No Hit Point Dice pool exists for ${selectedClassName}`);
      if (pool.current <= 0) throw new Error(`${pool.className} has no Hit Point Dice remaining`);
      const faces = dnd5eSrdHitDieFaces(pool.size);
      if (!Number.isInteger(selection.roll) || selection.roll < 1 || selection.roll > faces) {
        throw new Error(`${pool.className} ${pool.size} result must be a whole number from 1 to ${faces}`);
      }
      pool.current -= 1;
      const healed = Math.min(hp.max - currentHp, Math.max(0, selection.roll + constitutionModifier));
      currentHp += healed;
      spent.push({ className: pool.className, size: pool.size, roll: selection.roll, modifier: constitutionModifier, healed });
    }
    if (spent.length > 0) {
      recovered.hp = currentHp - hp.current;
      recovered.hitDiceSpent = spent.length;
      recovered.hitDice = spent;
    }
  } else {
    const beforeCurrent = pools.reduce((sum, pool) => sum + pool.current, 0);
    for (const pool of pools) pool.current = pool.max;
    recovered.hp = Math.max(0, currentHp - hp.current);
    recovered.hitDiceRecovered = pools.reduce((sum, pool) => sum + pool.current, 0) - beforeCurrent;
  }

  const nextHitDice = classes.length > 1
    ? dnd5eSrdAggregateHitDiceFromPools(actor, pools, primaryClassName)
    : { current: pools[0]!.current, max: pools[0]!.max, size: pools[0]!.size };
  return {
    data: {
      ...data,
      hp: { ...recordValue(actor.data.hp), current: currentHp, max: hp.max },
      hitDice: { ...aggregateRecord, ...nextHitDice },
      ...(classes.length > 1 ? { hitDicePools: pools } : {})
    },
    recovered
  };
}

function dnd5eSrdApplyLongRestStateRecovery(actor: Actor, dataInput: Record<string, unknown>): {
  data: Record<string, unknown>;
  recovered: Record<string, unknown>;
  removedConditions: AppliedCondition[];
} {
  let data = cloneJsonRecord(dataInput);
  const recovered: Record<string, unknown> = {};
  const removedConditions: AppliedCondition[] = [];
  const temporaryHitPoints = dnd5eSrdTemporaryHitPoints(data);
  if (temporaryHitPoints.current > 0) {
    data[temporaryHitPoints.key] = temporaryHitPoints.record ? { ...temporaryHitPoints.record, current: 0 } : 0;
    recovered.temporaryHitPointsCleared = temporaryHitPoints.current;
  }

  const conditions = normalizeConditionRecords(data.conditions);
  const exhaustion = conditions.find((condition) => condition.id === "exhaustion");
  if (exhaustion) {
    const before = clampInteger(exhaustion.level, 1, 6, 1);
    if (before <= 1) {
      data.conditions = conditions.filter((condition) => condition !== exhaustion);
      removedConditions.push({ id: "exhaustion", name: "Exhaustion", summary: dnd5eSrdCompendiumEntry("exhaustion")?.summary ?? "", appliedAt: exhaustion.appliedAt, level: before });
    } else {
      exhaustion.level = before - 1;
      data.conditions = conditions;
    }
    recovered.exhaustionReducedBy = 1;
  }

  const hp = recordValue(data.hp);
  const hpMaxReduction = Math.max(0, Math.floor(numericValue(hp.maxReduction, numericValue(data.hitPointMaximumReduction, 0))));
  const unreducedMax = numericValue(hp.unreducedMax, numericValue(hp.baseMax, Number.NaN));
  if (hpMaxReduction > 0 || Number.isFinite(unreducedMax)) {
    const currentMax = Math.max(1, Math.floor(numericValue(hp.max, 1)));
    const restoredMax = Number.isFinite(unreducedMax) ? Math.max(currentMax, Math.floor(unreducedMax)) : currentMax + hpMaxReduction;
    // A Long Rest restores the reduced maximum before completing its full-HP
    // recovery. Filling only to the temporary maximum leaves the creature
    // incorrectly wounded after that maximum is restored.
    data.hp = { ...hp, max: restoredMax, current: restoredMax, maxReduction: 0 };
    delete data.hitPointMaximumReduction;
    recovered.hitPointMaximumRestored = Math.max(0, restoredMax - currentMax);
  }

  const abilityReductions = recordValue(data.abilityScoreReductions);
  if (Object.keys(abilityReductions).length > 0) {
    const attributes = { ...recordValue(data.attributes) };
    const restored: Record<string, number> = {};
    for (const ability of dnd5eSrdAbilityNames) {
      const reduction = Math.max(0, Math.floor(numericValue(abilityReductions[ability], 0)));
      if (reduction <= 0) continue;
      attributes[ability] = Math.min(30, numericValue(attributes[ability], 10) + reduction);
      restored[ability] = reduction;
    }
    if (Object.keys(restored).length > 0) {
      data.attributes = attributes;
      data.abilityScoreReductions = {};
      recovered.abilityScoresRestored = restored;
    }
  }

  const rules = dnd5eSrdRulesEngineState(data);
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.map((effect) => cloneJsonRecord(recordValue(effect))) : [];
  const remainingEffects = activeEffects.filter((effect) => effect.endsOnLongRest !== true && stringValue(effect.recovery)?.toLowerCase() !== "long rest");
  if (remainingEffects.length !== activeEffects.length) {
    rules.activeEffects = remainingEffects;
    data = dnd5eSrdDataWithRulesEngineState(data, rules);
    recovered.effectsEnded = activeEffects.length - remainingEffects.length;
  }

  return { data, recovered, removedConditions };
}

export function applyDnd5eSrdRest(actor: Actor, restType: SystemRestType, options: SystemRestOptions = {}): SystemRestResult {
  const hpBeforeRest = normalizePool(actor.data.hp, 1);
  if (hpBeforeRest.current <= 0) throw new Error("A creature at 0 Hit Points cannot start or finish a Short or Long Rest");
  const rest = applyGenericFantasyRest(actor, restType);
  const restHitDice = dnd5eSrdApplyRestHitDice(actor, rest.data, restType, options);
  const { hp: _genericHp, hitDiceSpent: _genericHitDiceSpent, hitDiceRecovered: _genericHitDiceRecovered, ...restRecovered } = rest.recovered;
  const className = stringValue(actor.data.class) || "";
  const level = numericValue(actor.data.level, 1);
  const classes = dnd5eSrdActorClassLevels(actor);
  const multiclass = classes.length > 1;
  const warlockLevel = classes.find((entry) => entry.className === "Warlock")?.level ?? 0;
  const dataWithDefaults = {
    ...restHitDice.data,
    resources: multiclass
      ? dnd5eSrdCombinedClassResources(restHitDice.data.resources, classes, restHitDice.data, Math.floor(level), { raiseMaxToDefault: true })
      : normalizeDnd5eSrdResources(restHitDice.data.resources, className, level, actor.data, { raiseMaxToDefault: true }),
    spellSlots: multiclass
      ? normalizeExactResourcePools(restHitDice.data.spellSlots, dnd5eSrdMulticlassSpellSlots(classes, actor), { raiseMaxToDefault: true })
      : normalizeDnd5eSrdSpellSlots(restHitDice.data.spellSlots, className, level, { raiseMaxToDefault: true }),
    ...(multiclass && warlockLevel > 0
      ? { pactSlots: normalizeExactResourcePools(restHitDice.data.pactSlots, defaultDnd5eSrdWarlockPactMagicSlots(warlockLevel), { raiseMaxToDefault: true }) }
      : {})
  };
  const dataAfterRestLimits = restType === "short" ? dnd5eSrdApplyShortRestResourceLimits(actor, dataWithDefaults) : dnd5eSrdApplyLongRestResourceLimits(actor, dataWithDefaults);
  const pactMagic = dnd5eSrdApplyPactMagicRecovery(actor, dataAfterRestLimits, restType);
  const arcaneRecovery = dnd5eSrdApplyArcaneRecovery(actor, pactMagic.data, restType, options);
  const sorcerousRestoration = dnd5eSrdApplySorcerousRestoration(actor, arcaneRecovery.data, restType);
  const humanResourceful = dnd5eSrdApplyHumanResourceful(actor, sorcerousRestoration.data, restType);
  const longRestState = restType === "long"
    ? dnd5eSrdApplyLongRestStateRecovery(actor, humanResourceful.data)
    : { data: humanResourceful.data, recovered: {}, removedConditions: [] as AppliedCondition[] };
  const rechargeRecovery = dnd5eSrdRecoverRechargeState(longRestState.data, restType);
  const rageEnd = endDnd5eSrdRage(rechargeRecovery.data, "rest");
  const finalData = rageEnd.data;
  const recovered = dnd5eSrdRestRecovered(
    actor,
    finalData,
    {
      ...restRecovered,
      ...restHitDice.recovered,
      ...(pactMagic.recovered ?? {}),
      ...(arcaneRecovery.recovered ?? {}),
      ...(sorcerousRestoration.recovered ?? {}),
      ...(humanResourceful.recovered ?? {}),
      ...longRestState.recovered,
      ...(rageEnd.ended ? { rageEnded: true } : {}),
      ...(rechargeRecovery.recoveredActionIds.length > 0 ? { rechargedActions: rechargeRecovery.recoveredActionIds } : {})
    }
  );
  return {
    ...rest,
    systemId: DND_5E_SRD_SYSTEM_ID,
    summary: `${actor.name} completed a ${restType} rest using ${DND_5E_SRD_VERSION}`,
    recovered,
    removedConditions: [...rest.removedConditions, ...longRestState.removedConditions],
    data: finalData
  };
}

export function genericFantasySheet(actor: Actor, items: Item[] = []): GenericFantasySheet {
  return {
    actorId: actor.id,
    summary: summarizeActor(actor),
    data: actor.data,
    quickRolls: genericFantasyQuickRolls(actor, items),
    conditions: genericFantasyActorConditions(actor),
    inventory: items.filter((item) => item.actorId === actor.id && item.type !== "spell"),
    spells: items.filter((item) => item.actorId === actor.id && item.type === "spell")
  };
}

export function dnd5eSrdSheet(actor: Actor, items: Item[] = []): GenericFantasySheet {
  const sheet = genericFantasySheet(actor, items);
  const armorClassDetails = dnd5eSrdArmorClass(actor, items);
  const armorClassData = dnd5eSrdArmorClassSheetData(actor, armorClassDetails);
  const speedDetails = dnd5eSrdSpeed(actor, items);
  const hitDicePools = dnd5eSrdHitDicePools(actor);
  const hitDicePoolSummary = hitDicePools.length > 0 ? hitDicePools.map((pool) => `${pool.max}${pool.size}`).join(" + ") : undefined;
  return {
    ...sheet,
    data: { ...sheet.data, ...armorClassData, effectiveSpeed: speedDetails.value, speedDetails, ...(hitDicePoolSummary ? { hitDicePoolSummary } : {}) },
    quickRolls: dnd5eSrdQuickRolls(actor, items),
    conditions: dnd5eSrdActorConditions(actor)
  };
}

function dnd5eSrdEquippedItemNumericBonus(actor: Actor, items: Item[], bonusKey: string, options: { hasEquippedArmorOrShield?: boolean } = {}): { total: number; itemIds: string[] } {
  const itemBonuses = items
    .filter((item) => itemBelongsToActor(actor, item))
    .filter((item) => itemQuantity(recordValue(item.data)) > 0)
    .flatMap((item) => {
      const data = recordValue(item.data);
      if (data.equipped === false) return [];
      if (!dnd5eSrdItemModifiersAreActive(actor, item)) return [];
      if (bonusKey === "spellAttackBonus" && booleanValue(data.consumable)) return [];
      if (bonusKey === "armorClassBonus" && options.hasEquippedArmorOrShield && booleanValue(data.requiresNoArmorOrShield)) return [];
      const bonus = numericValue(data[bonusKey], Number.NaN);
      return Number.isFinite(bonus) ? [{ itemId: item.id, bonus }] : [];
    });
  return {
    total: itemBonuses.reduce((sum, item) => sum + item.bonus, 0),
    itemIds: itemBonuses.map((item) => item.itemId)
  };
}

export function dnd5eSrdArmorClass(actor: Actor, items: Item[] = []): Dnd5eSrdArmorClassDetails {
  const dexModifier = genericFantasyAttributeModifier(actor, "dexterity");
  const wisdomModifier = genericFantasyAttributeModifier(actor, "wisdom");
  const constitutionModifier = genericFantasyAttributeModifier(actor, "constitution");
  const strengthScore = numericValue(recordValue(actor.data.attributes).strength, 10);
  const actorItems = items.filter((item) => itemBelongsToActor(actor, item)).filter((item) => itemQuantity(recordValue(item.data)) > 0);
  const hasEquippedArmor = actorItems.some((item) => {
    const data = recordValue(item.data);
    return data.equipped !== false && Number.isFinite(numericValue(data.armorBase, Number.NaN));
  });
  const hasEquippedShield = actorItems.some((item) => {
    const data = recordValue(item.data);
    return data.equipped !== false && Number.isFinite(numericValue(data.armorBonus, Number.NaN));
  });
  const armorCandidates: Dnd5eSrdArmorClassDetails[] = [
    {
      value: 10 + dexModifier,
      base: 10,
      dexModifier,
      armorName: "Unarmored",
      shieldBonus: 0,
      shieldItemIds: [],
      stealthDisadvantage: false,
      speedPenalty: 0
    }
  ];
  if (dnd5eSrdClassLevel(actor, "Monk") >= 1 && !hasEquippedArmor && !hasEquippedShield) {
    armorCandidates.push({
      value: 10 + dexModifier + wisdomModifier,
      base: 10,
      dexModifier,
      armorName: "Unarmored Defense",
      shieldBonus: 0,
      shieldItemIds: [],
      stealthDisadvantage: false,
      speedPenalty: 0
    });
  }
  if (dnd5eSrdClassLevel(actor, "Barbarian") >= 1 && !hasEquippedArmor) {
    armorCandidates.push({
      value: 10 + dexModifier + constitutionModifier,
      base: 10,
      dexModifier,
      armorName: "Unarmored Defense",
      shieldBonus: 0,
      shieldItemIds: [],
      stealthDisadvantage: false,
      speedPenalty: 0
    });
  }
  if (dnd5eSrdHasDraconicResilience(actor) && !hasEquippedArmor) {
    armorCandidates.push({
      value: 10 + dexModifier + genericFantasyAttributeModifier(actor, "charisma"),
      base: 10,
      dexModifier,
      armorName: "Draconic Resilience",
      shieldBonus: 0,
      shieldItemIds: [],
      stealthDisadvantage: false,
      speedPenalty: 0
    });
  }
  for (const item of actorItems) {
    const data = recordValue(item.data);
    if (data.equipped === false) continue;
    const armorBase = numericValue(data.armorBase, Number.NaN);
    if (!Number.isFinite(armorBase)) continue;
    const dexContribution = data.dexBonus === false ? 0 : Math.min(dexModifier, numericValue(data.dexCap, dexModifier));
    const strengthRequirement = numericValue(data.strengthRequirement, Number.NaN);
    const hasStrengthRequirement = Number.isFinite(strengthRequirement);
    armorCandidates.push({
      value: armorBase + dexContribution,
      base: armorBase,
      dexModifier: dexContribution,
      armorName: item.name,
      armorItemId: item.id,
      shieldBonus: 0,
      shieldItemIds: [],
      stealthDisadvantage: booleanValue(data.stealthDisadvantage),
      strengthRequirement: hasStrengthRequirement ? strengthRequirement : undefined,
      speedPenalty: hasStrengthRequirement && strengthScore < strengthRequirement ? -10 : 0
    });
  }
  const armor = armorCandidates.sort((left, right) => right.value - left.value)[0]!;
  const shieldItems = actorItems.filter((item) => {
    const data = recordValue(item.data);
    return data.equipped !== false && Number.isFinite(numericValue(data.armorBonus, Number.NaN));
  });
  const shieldBonus = shieldItems.reduce((max, item) => Math.max(max, numericValue(recordValue(item.data).armorBonus, 0)), 0);
  const armorClassItemBonus = dnd5eSrdEquippedItemNumericBonus(actor, actorItems, "armorClassBonus", { hasEquippedArmorOrShield: hasEquippedArmor || hasEquippedShield });
  return {
    ...armor,
    value: armor.value + shieldBonus + armorClassItemBonus.total,
    shieldBonus,
    shieldItemIds: shieldBonus > 0 ? shieldItems.filter((item) => numericValue(recordValue(item.data).armorBonus, 0) === shieldBonus).map((item) => item.id) : [],
    ...(armorClassItemBonus.total > 0 ? { armorClassBonus: armorClassItemBonus.total, armorClassBonusItemIds: armorClassItemBonus.itemIds } : {})
  };
}

export function dnd5eSrdSpeed(actor: Actor, items: Item[] = []): Dnd5eSrdSpeedDetails {
  const base = Math.max(0, numericValue(actor.data.speed, 30));
  const armorPenalty = dnd5eSrdArmorClass(actor, items).speedPenalty;
  const conditions = normalizeConditionRecords(actor.data.conditions);
  const effects = dnd5eSrdConditionEffects(conditions);
  const exhaustionLevel = dnd5eSrdExhaustionLevel(conditions);
  const exhaustionPenalty = exhaustionLevel > 0 ? exhaustionLevel * -5 : 0;
  const weaponMasteryPenalty = dnd5eSrdWeaponMasterySpeedPenalty(actor);
  let conditionSetTo: number | undefined;
  let conditionMultiplier = 1;
  const conditionSources: string[] = [];
  for (const effect of effects) {
    const speedSetTo = numericValue(effect.data.speedSetTo, Number.NaN);
    if (Number.isFinite(speedSetTo)) {
      conditionSetTo = conditionSetTo === undefined ? speedSetTo : Math.min(conditionSetTo, speedSetTo);
      conditionSources.push(effect.sourceId);
    }
    const multiplier = numericValue(effect.data.speedMultiplier, Number.NaN);
    if (Number.isFinite(multiplier)) {
      conditionMultiplier = Math.min(conditionMultiplier, Math.max(0, multiplier));
      conditionSources.push(effect.sourceId);
    }
  }
  if (exhaustionLevel > 0) conditionSources.push("exhaustion");
  if (weaponMasteryPenalty) conditionSources.push("weapon-mastery-slow");
  const penalizedSpeed = Math.max(0, base + armorPenalty + exhaustionPenalty + weaponMasteryPenalty);
  const multipliedSpeed = Math.floor(penalizedSpeed * conditionMultiplier);
  const value = Math.max(0, conditionSetTo === undefined ? multipliedSpeed : Math.min(conditionSetTo, multipliedSpeed));
  return {
    value,
    base,
    armorPenalty,
    conditionPenalty: exhaustionPenalty,
    ...(weaponMasteryPenalty ? { weaponMasteryPenalty } : {}),
    conditionMultiplier,
    ...(conditionSetTo !== undefined ? { conditionSetTo } : {}),
    conditionSources: uniqueStrings(conditionSources)
  };
}

export function dnd5eSrdCalculationExplanation(actor: Actor, items: Item[] = []): ActorCalculationExplanation {
  const actorItems = items
    .filter((item) => itemBelongsToActor(actor, item) && item.campaignId === actor.campaignId && item.systemId === actor.systemId)
    .sort((left, right) => left.id.localeCompare(right.id));
  const itemById = new Map(actorItems.map((item) => [item.id, item]));
  const actorSource: CalculationSource = { kind: "actor", id: actor.id, name: actor.name };
  const monsterStatBlock = recordValue(recordValue(actor.data.monster).statBlock);
  const monsterStatBlockVersion = stringValue(monsterStatBlock.source) ?? stringValue(actor.data.ruleset);
  const monsterStatBlockSource: CalculationSource = {
    kind: "actor",
    id: actor.id,
    name: `${actor.name} stat block`,
    ...(monsterStatBlockVersion ? { version: monsterStatBlockVersion } : {})
  };
  const systemSource: CalculationSource = {
    kind: "system",
    id: DND_5E_SRD_SYSTEM_ID,
    name: "D&D 5.5e SRD",
    version: DND_5E_SRD_COMPENDIUM_PROVENANCE.systemVersion,
    url: DND_5E_SRD_COMPENDIUM_PROVENANCE.license.url
  };
  const className = stringValue(actor.data.class);
  const classSource: CalculationSource = className
    ? { kind: "class", id: slugId(className), name: className, version: DND_5E_SRD_VERSION }
    : systemSource;
  const itemSource = (itemId: string): CalculationSource => {
    const item = itemById.get(itemId);
    if (!item) return systemSource;
    const provenance = recordValue(item.data.compendiumProvenance);
    const license = recordValue(provenance.license);
    return {
      kind: "item",
      id: item.id,
      name: item.name,
      ...(stringValue(provenance.contentVersion) ? { version: stringValue(provenance.contentVersion) } : {}),
      ...(stringValue(license.url) ? { url: stringValue(license.url) } : {})
    };
  };
  const featureSource = (name: string): CalculationSource => ({ kind: "feature", id: slugId(name), name, version: DND_5E_SRD_VERSION });
  const conditionSource = (conditionId: string): CalculationSource => ({
    kind: "condition",
    id: conditionId,
    name: dnd5eSrdCompendiumEntry(conditionId)?.name ?? titleCaseWords(conditionId),
    version: DND_5E_SRD_VERSION
  });
  const rollModeSource = (automation: Dnd5eSrdD20Automation): CalculationSource => {
    const metadata = recordValue(automation.metadata);
    const feature = stringValue(metadata.feature);
    if (feature) return featureSource(feature);
    const conditionId = normalizeStringArray(metadata.conditionSources)[0];
    return conditionId ? conditionSource(conditionId) : systemSource;
  };
  const d20Term = (automation: Dnd5eSrdD20Automation): CalculationTerm => ({
    label: "d20 roll mode",
    formula: automation.d20,
    source: rollModeSource(automation)
  });
  const adjustmentTerm = (automation: Dnd5eSrdD20Automation): CalculationTerm[] => automation.modifier === 0
    ? []
    : [{ label: "Condition adjustment", signedValue: automation.modifier, source: conditionSource("exhaustion") }];
  const activeNumericItemTerms = (itemIds: string[], key: string, label: string): CalculationTerm[] => itemIds.flatMap((itemId) => {
    const item = itemById.get(itemId);
    const value = numericValue(recordValue(item?.data)[key], Number.NaN);
    return Number.isFinite(value) ? [{ label: `${label}: ${item?.name ?? itemId}`, signedValue: value, source: itemSource(itemId) }] : [];
  });

  const attributes = recordValue(actor.data.attributes);
  const abilities = dnd5eSrdAbilityKeys().map((ability) => ({
    id: ability,
    label: titleCaseWords(ability),
    score: numericValue(attributes[ability], 10),
    modifier: genericFantasyAttributeModifier(actor, ability),
    actorSource,
    systemSource
  }));

  const level = dnd5eSrdCharacterLevel(actor);
  const defaultProficiency = 2 + Math.floor((level - 1) / 4);
  const proficiency = dnd5eSrdProficiencyBonus(actor);
  const explicitProficiency = typeof actor.data.proficiencyBonus === "number" && Number.isFinite(actor.data.proficiencyBonus);
  const storedProficiency = explicitProficiency ? actor.data.proficiencyBonus as number : undefined;
  const proficiencyFlags: Dnd5eSrdCalculationFlagInput = explicitProficiency
    ? {
        override: true,
        reasons: [storedProficiency === proficiency
          ? `Stored proficiency bonus ${storedProficiency} overrides the level-${level} SRD value of ${defaultProficiency}.`
          : `Stored proficiency bonus ${storedProficiency} is normalized by the authoritative helper to ${proficiency}; the level-${level} SRD value is ${defaultProficiency}.`]
      }
    : {};
  const proficiencyInput: Dnd5eSrdScalarCalculationInput = {
    id: "proficiency-bonus",
    label: "Proficiency bonus",
    result: proficiency,
    terms: explicitProficiency
      ? [{ label: "Stored proficiency bonus (normalized)", signedValue: proficiency, source: { kind: "override", id: actor.id, name: actor.name } }]
      : [
          { label: "Base proficiency", signedValue: 2, source: systemSource },
          { label: `Level ${level} scaling`, signedValue: proficiency - 2, source: classSource }
        ],
    flags: proficiencyFlags
  };

  const armor = dnd5eSrdArmorClass(actor, actorItems);
  const storedArmorClass = classifyDnd5eSrdStoredArmorClass(actor, armor.value);
  const armorClassReview = dnd5eSrdArmorClassReview(actor.data);
  const exactMonsterArmorClass = storedArmorClass.kind === "monster-exact" ? storedArmorClass.storedValue : undefined;
  const armorResult = exactMonsterArmorClass ?? armor.value;
  const armorBonus = numericValue(armor.armorClassBonus, 0);
  const armorSource = armor.armorItemId
    ? itemSource(armor.armorItemId)
    : armor.armorName === "Unarmored Defense"
      ? classSource
      : armor.armorName === "Draconic Resilience"
        ? featureSource(armor.armorName)
        : systemSource;
  const shieldIds = [...armor.shieldItemIds].sort((left, right) => left.localeCompare(right));
  const extraArmorContribution = armor.value - armor.base - armor.dexModifier - armor.shieldBonus - armorBonus;
  const armorTerms: CalculationTerm[] = exactMonsterArmorClass !== undefined
    ? [{ label: "Monster stat-block Armor Class", signedValue: armorResult, source: monsterStatBlockSource }]
    : [
        { label: armor.armorName, signedValue: armor.base, source: armorSource },
        { label: "Dexterity modifier", signedValue: armor.dexModifier, source: actorSource },
        ...(extraArmorContribution !== 0 ? [{ label: `${armor.armorName} ability contribution`, signedValue: extraArmorContribution, source: armorSource }] : []),
        ...(armor.shieldBonus !== 0 ? [{ label: `Shield: ${itemById.get(shieldIds[0] ?? "")?.name ?? "equipped shield"}`, signedValue: armor.shieldBonus, source: shieldIds[0] ? itemSource(shieldIds[0]) : systemSource }] : []),
        ...activeNumericItemTerms(armor.armorClassBonusItemIds ?? [], "armorClassBonus", "Armor class bonus")
      ];
  const legacyReviewReason = storedArmorClass.kind === "requires-review"
    ? storedArmorClass.reason
    : armorClassReview
      ? armorClassReview.reason
      : undefined;
  const armorFlags: Dnd5eSrdCalculationFlagInput = legacyReviewReason
    ? { ambiguous: true, manual: true, reasons: [legacyReviewReason] }
    : shieldIds.length > 1
      ? { ambiguous: true, reasons: ["Multiple equipped shields provide the same highest bonus; only one shield bonus is applied."] }
      : {};
  const armorInput: Dnd5eSrdScalarCalculationInput = {
    id: "armor-class",
    label: "Armor class",
    result: armorResult,
    terms: armorTerms,
    flags: armorFlags
  };

  const hp = recordValue(actor.data.hp);
  const hpValue = (key: "max" | "current"): Dnd5eSrdScalarCalculationInput => {
    const value = typeof hp[key] === "number" && Number.isFinite(hp[key]) ? Math.floor(hp[key] as number) : undefined;
    return {
      id: `hit-points-${key === "max" ? "maximum" : "current"}`,
      label: key === "max" ? "Maximum hit points" : "Current hit points",
      result: value ?? "Unavailable",
      terms: value === undefined
        ? [{ label: "Stored hit point value", formula: "not recorded", source: actorSource }]
        : [{ label: "Stored hit point value", signedValue: value, source: actorSource }],
      flags: value === undefined
        ? { manual: true, unsupported: true, reasons: [`Actor data does not contain a finite hp.${key} value.`] }
        : {}
    };
  };
  const temporaryHp = dnd5eSrdTemporaryHitPoints(actor.data);
  const temporaryHpInput: Dnd5eSrdScalarCalculationInput = {
    id: "hit-points-temporary",
    label: "Temporary hit points",
    result: temporaryHp.current,
    terms: [{ label: `Stored ${temporaryHp.key}`, signedValue: temporaryHp.current, source: actorSource }]
  };

  const initiativeAutomation = dnd5eSrdD20Automation(actor, "initiative", "dexterity");
  const initiativeRoll = dnd5eSrdInitiativeRoll(actor);
  const statBlockInitiative = dnd5eSrdExactMonsterInitiativeBonus(actor);
  const remarkableInitiative = dnd5eSrdHasChampionRemarkableAthlete(actor)
    ? dnd5eSrdFeatureAdvantageRoll(initiativeAutomation, "Remarkable Athlete")
    : initiativeAutomation;
  const initiativeTerms: CalculationTerm[] = [
    d20Term(remarkableInitiative),
    statBlockInitiative !== undefined
      ? { label: "Monster stat-block initiative bonus", signedValue: statBlockInitiative, source: monsterStatBlockSource }
      : { label: "Dexterity modifier", signedValue: genericFantasyAttributeModifier(actor, "dexterity"), source: actorSource },
    ...adjustmentTerm(remarkableInitiative)
  ];
  const storedInitiative = typeof actor.data.initiative === "number" && Number.isFinite(actor.data.initiative) ? actor.data.initiative : undefined;
  const initiativeFlags: Dnd5eSrdCalculationFlagInput = statBlockInitiative !== undefined
    ? storedInitiative !== undefined && storedInitiative !== statBlockInitiative
      ? { ambiguous: true, reasons: [`Stored initiative ${storedInitiative} differs from the authoritative stat-block bonus ${statBlockInitiative}; the stat-block value is used.`] }
      : {}
    : storedInitiative !== undefined
      ? { unsupported: true, ambiguous: true, reasons: [`Stored initiative ${storedInitiative} is preserved, but session rolls use the authoritative formula shown here.`] }
      : {};
  const initiativeInput: Dnd5eSrdRollCalculationInput = {
    id: "initiative",
    label: "Initiative",
    result: initiativeRoll.formula,
    formula: initiativeRoll.formula,
    terms: initiativeTerms,
    flags: initiativeFlags
  };

  const savingThrows: Dnd5eSrdRollCalculationInput[] = dnd5eSrdAbilityKeys().map((ability) => {
    const automation = dnd5eSrdD20Automation(actor, "saving-throw", ability, dnd5eSrdSaveFeatureAdvantageSources(actor, ability));
    const roll = dnd5eSrdSavingThrow(actor, ability, actorItems);
    const abilityBonus = genericFantasyAttributeModifier(actor, ability);
    const saveProficiency = dnd5eSrdSaveProficiencies(actor).includes(ability) ? proficiency : 0;
    const statBlockBonus = dnd5eSrdExactMonsterSaveBonus(actor, ability);
    const itemBonus = dnd5eSrdEquippedItemNumericBonus(actor, actorItems, "savingThrowBonus");
    const blessed = dnd5eSrdActorConditions(actor).some((condition) => condition.id === "blessed");
    const terms: CalculationTerm[] = automation.automaticFailure
      ? [{ label: "Automatic failure", formula: "0", source: rollModeSource(automation) }]
      : [
          d20Term(automation),
          ...(statBlockBonus !== undefined
            ? [{ label: `${titleCaseWords(ability)} stat-block save bonus`, signedValue: statBlockBonus, source: monsterStatBlockSource }]
            : [
                { label: `${titleCaseWords(ability)} modifier`, signedValue: abilityBonus, source: actorSource },
                ...(saveProficiency ? [{ label: "Save proficiency", signedValue: saveProficiency, source: classSource }] : [])
              ]),
          ...activeNumericItemTerms(itemBonus.itemIds, "savingThrowBonus", "Saving throw bonus"),
          ...adjustmentTerm(automation),
          ...(blessed ? [{ label: "Blessed", formula: "+1d4", source: conditionSource("blessed") }] : [])
        ];
    return {
      id: `saving-throw.${ability}`,
      label: `${titleCaseWords(ability)} saving throw`,
      result: roll.formula,
      formula: roll.formula,
      terms
    };
  });

  const skillCalculations = dnd5eSrdSkills().map((skill) => {
    const baseAutomation = dnd5eSrdD20Automation(actor, "skill-check", skill.ability);
    const automation = skill.id === "athletics" && dnd5eSrdHasChampionRemarkableAthlete(actor)
      ? dnd5eSrdFeatureAdvantageRoll(baseAutomation, "Remarkable Athlete")
      : baseAutomation;
    const abilityBonus = genericFantasyAttributeModifier(actor, skill.ability);
    const proficiencyMultiplier = dnd5eSrdSkillProficiencyMultiplier(actor, skill.id);
    const proficiencyContribution = proficiencyMultiplier * proficiency;
    const statBlockBonus = dnd5eSrdExactMonsterSkillBonus(actor, skill.id);
    const jackOfAllTrades = statBlockBonus === undefined && proficiencyMultiplier === 0 && dnd5eSrdHasJackOfAllTrades(actor) ? Math.floor(proficiency / 2) : 0;
    const numericModifier = (statBlockBonus ?? abilityBonus + proficiencyContribution + jackOfAllTrades) + automation.modifier;
    const roll = dnd5eSrdSkillCheck(actor, skill.id);
    const terms: CalculationTerm[] = [
      d20Term(automation),
      ...(statBlockBonus !== undefined
        ? [{ label: `${skill.label} stat-block skill bonus`, signedValue: statBlockBonus, source: monsterStatBlockSource }]
        : [
            { label: `${titleCaseWords(skill.ability)} modifier`, signedValue: abilityBonus, source: actorSource },
            ...(proficiencyContribution ? [{ label: proficiencyMultiplier === 2 ? "Expertise" : "Skill proficiency", signedValue: proficiencyContribution, source: classSource }] : []),
            ...(jackOfAllTrades ? [{ label: "Jack of All Trades", signedValue: jackOfAllTrades, source: featureSource("Jack of All Trades") }] : [])
          ]),
      ...adjustmentTerm(automation)
    ];
    return {
      skill,
      automation,
      numericModifier,
      input: {
        id: `skill.${skill.id}`,
        label: skill.label,
        result: roll.formula,
        formula: roll.formula,
        terms
      } satisfies Dnd5eSrdRollCalculationInput
    };
  });
  const perception = skillCalculations.find((entry) => entry.skill.id === "perception")!;
  const perceptionMode = stringValue(recordValue(perception.automation.metadata).conditionRollMode);
  const passivePerceptionInput: Dnd5eSrdScalarCalculationInput = {
    id: "passive-perception",
    label: "Passive Perception",
    result: 10 + perception.numericModifier,
    terms: [
      { label: "Passive base", signedValue: 10, source: systemSource },
      ...perception.input.terms.filter((term) => term.label !== "d20 roll mode")
    ],
    flags: perceptionMode
      ? { ambiguous: true, reasons: [`Active Perception rolls currently use ${perceptionMode}; this passive score does not guess an additional roll-mode adjustment.`] }
      : {}
  };

  const speed = dnd5eSrdSpeed(actor, actorItems);
  const speedTerms: CalculationTerm[] = [
    { label: "Base speed", signedValue: speed.base, source: actorSource },
    ...(speed.armorPenalty ? [{ label: "Armor strength penalty", signedValue: speed.armorPenalty, source: armor.armorItemId ? itemSource(armor.armorItemId) : systemSource }] : []),
    ...(speed.conditionPenalty ? [{ label: "Exhaustion penalty", signedValue: speed.conditionPenalty, source: conditionSource("exhaustion") }] : []),
    ...(speed.weaponMasteryPenalty ? [{ label: "Slow Weapon Mastery", signedValue: speed.weaponMasteryPenalty, source: featureSource("Weapon Mastery: Slow") }] : []),
    ...(speed.conditionMultiplier !== 1 ? [{ label: "Condition multiplier", formula: `× ${speed.conditionMultiplier}`, source: conditionSource(speed.conditionSources[0] ?? "condition") }] : []),
    ...(speed.conditionSetTo !== undefined ? [{ label: "Condition maximum", formula: `min(result, ${speed.conditionSetTo} ft)`, source: conditionSource(speed.conditionSources[0] ?? "condition") }] : [])
  ];
  const speedInput: Dnd5eSrdScalarCalculationInput = {
    id: "speed",
    label: "Speed",
    result: speed.value,
    unit: "ft",
    terms: speedTerms
  };

  const classIsSpellcaster = typeof className === "string" && DND_5E_SRD_SPELLCASTER_CLASSES.has(className.toLowerCase());
  const spellcastingApplicable = classIsSpellcaster || actorItems.some((item) => item.type === "spell") || Object.keys(recordValue(actor.data.spellSlots)).length > 0 || Object.keys(recordValue(actor.data.spellcasting)).length > 0;
  const spellcastingAbility = dnd5eSrdPrimaryAbility(className ?? "");
  const spellAbilityBonus = genericFantasyAttributeModifier(actor, spellcastingAbility);
  const spellAttackItems = dnd5eSrdEquippedItemNumericBonus(actor, actorItems, "spellAttackBonus");
  const spellSaveUnsupportedItems = actorItems.filter((item) => dnd5eSrdItemModifiersAreActive(actor, item) && Number.isFinite(numericValue(recordValue(item.data).spellSaveDcBonus, Number.NaN)));
  const storedSpellSaveDc = typeof actor.data.spellSaveDc === "number" && Number.isFinite(actor.data.spellSaveDc) ? actor.data.spellSaveDc : undefined;
  const spellSaveFlags: Dnd5eSrdCalculationFlagInput = spellSaveUnsupportedItems.length > 0 || storedSpellSaveDc !== undefined
    ? {
        unsupported: true,
        ambiguous: true,
        reasons: [
          ...(storedSpellSaveDc !== undefined ? [`Stored spell save DC ${storedSpellSaveDc} is preserved but is not used by the current class-based action path.`] : []),
          ...(spellSaveUnsupportedItems.length > 0 ? [`Active item spell-save bonuses are preserved but are not applied by the current action path: ${spellSaveUnsupportedItems.map((item) => item.name).join(", ")}.`] : [])
        ]
      }
    : {};
  const spellcasting = spellcastingApplicable
    ? {
        saveDc: {
          id: "spell-save-dc",
          label: "Spell save DC",
          result: dnd5eSrdSpellSaveDc(actor, spellcastingAbility),
          terms: [
            { label: "SRD base", signedValue: 8, source: systemSource },
            { label: "Proficiency bonus", signedValue: proficiency, source: explicitProficiency ? actorSource : classSource },
            { label: `${titleCaseWords(spellcastingAbility)} modifier`, signedValue: spellAbilityBonus, source: actorSource }
          ],
          flags: spellSaveFlags
        } satisfies Dnd5eSrdScalarCalculationInput,
        attackBonus: {
          id: "spell-attack-bonus",
          label: "Spell attack bonus",
          result: proficiency + spellAbilityBonus + spellAttackItems.total,
          terms: [
            { label: "Proficiency bonus", signedValue: proficiency, source: explicitProficiency ? actorSource : classSource },
            { label: `${titleCaseWords(spellcastingAbility)} modifier`, signedValue: spellAbilityBonus, source: actorSource },
            ...activeNumericItemTerms(spellAttackItems.itemIds, "spellAttackBonus", "Spell attack bonus")
          ]
        } satisfies Dnd5eSrdScalarCalculationInput
      }
    : undefined;

  const coreRollIds = new Set([
    "initiative",
    ...dnd5eSrdAbilityKeys().flatMap((ability) => [`ability-${ability}`, `save-${ability}`]),
    ...dnd5eSrdSkills().map((skill) => `skill-${skill.id}`)
  ]);
  const actionRolls: Dnd5eSrdRollCalculationInput[] = dnd5eSrdQuickRolls(actor, actorItems)
    .filter((roll) => !coreRollIds.has(roll.id))
    .map((roll) => {
      const item = actorItems.find((candidate) => roll.id.startsWith(`item-${candidate.id}-`) || roll.id.startsWith(`spell-${candidate.id}-`));
      const source = item ? itemSource(item.id) : roll.id.startsWith("monster-") ? actorSource : featureSource(roll.label.replace(/ (Attack|Damage|Healing|Check|Effect)$/, ""));
      const manual = roll.formula === "0";
      return {
        id: `roll.${roll.id}`,
        label: roll.label,
        result: roll.formula,
        formula: roll.formula,
        terms: [{ label: "Authoritative action formula", formula: roll.formula, source }],
        flags: manual ? { manual: true, reasons: ["This action has no numeric roll formula and requires its feature/effect instructions to resolve."] } : {}
      };
    });

  return buildDnd5eSrdCalculationExplanation({
    actorId: actor.id,
    systemId: DND_5E_SRD_SYSTEM_ID,
    systemVersion: DND_5E_SRD_COMPENDIUM_PROVENANCE.systemVersion,
    rulesVersion: DND_5E_SRD_VERSION,
    sourceName: DND_5E_SRD_COMPENDIUM_PROVENANCE.sourceName,
    sourceVersion: DND_5E_SRD_COMPENDIUM_PROVENANCE.sourceVersion,
    license: DND_5E_SRD_COMPENDIUM_PROVENANCE.license,
    abilities,
    proficiency: proficiencyInput,
    armorClass: armorInput,
    hitPoints: { maximum: hpValue("max"), current: hpValue("current"), temporary: temporaryHpInput },
    initiative: initiativeInput,
    savingThrows,
    skills: skillCalculations.map((entry) => entry.input),
    passivePerception: passivePerceptionInput,
    speed: speedInput,
    ...(spellcasting ? { spellcasting } : {}),
    actionRolls
  });
}

export function genericFantasyActionFormula(actor: Actor, items: Item[] = [], rollId: string, options: SystemActionUseOptions = {}): string | undefined {
  const item = actionItemForRoll(actor, items, rollId, ["spell", "item"]);
  if (!item) return undefined;
  const data = recordValue(item.data);
  const prefix = item.type === "spell" ? "spell" : "item";
  if (rollId === `${prefix}-${item.id}-damage` && stringValue(data.damageFormula)) {
    return genericFantasyDamageFormula(actor, data, options.spellSlotLevel);
  }
  if (rollId === `${prefix}-${item.id}-secondary-damage` && stringValue(data.secondaryDamageFormula)) {
    return genericFantasyDamageFormula(actor, data, options.spellSlotLevel, "secondaryDamageFormula", "secondaryUpcastFormula");
  }
  if (rollId === `${prefix}-${item.id}-healing` && stringValue(data.healingFormula)) {
    return genericFantasyHealingFormula(actor, data, options.spellSlotLevel);
  }
  return genericFantasyActionRolls(actor, items).find((roll) => roll.id === rollId)?.formula;
}

export function dnd5eSrdActionFormula(actor: Actor, items: Item[] = [], rollId: string, options: SystemActionUseOptions = {}): string | undefined {
  const monkWeaponFormula = dnd5eSrdMonkWeaponDamageFormulaForRoll(actor, items, rollId);
  if (monkWeaponFormula) {
    const rageDamageBonus = dnd5eSrdRageDamageBonusForRoll(actor, items, rollId);
    return rageDamageBonus > 0 ? appendFormulaBonus(monkWeaponFormula, rageDamageBonus) : monkWeaponFormula;
  }
  if (rollId === DND_5E_SRD_UNARMED_STRIKE_ROLL_ID) return appendFormulaBonus(dnd5eSrdUnarmedStrike(actor).formula, dnd5eSrdRageDamageBonusForRoll(actor, items, rollId));
  if (rollId === DND_5E_SRD_SECOND_WIND_ROLL_ID) return dnd5eSrdSecondWindFormula(actor);
  if (rollId === DND_5E_SRD_ACTION_SURGE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_TACTICAL_MIND_ROLL_ID) return "1d10";
  if (rollId === DND_5E_SRD_CHAMPION_CRITICAL_ROLL_ID || rollId === DND_5E_SRD_CHAMPION_REMARKABLE_ATHLETE_ROLL_ID || rollId === DND_5E_SRD_CHAMPION_HEROIC_WARRIOR_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_CHAMPION_SURVIVOR_ROLL_ID) return dnd5eSrdChampionSurvivorFormula(actor);
  if (rollId === DND_5E_SRD_RAGE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_RAGE_DAMAGE_ROLL_ID) return String(dnd5eSrdRageDamageBonus(actor));
  if (rollId === DND_5E_SRD_RAGE_EXTEND_ROLL_ID || rollId === DND_5E_SRD_RAGE_END_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_RECKLESS_ATTACK_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_BERSERKER_FRENZY_ROLL_ID) return dnd5eSrdBerserkerFrenzyFormula(actor);
  if (
    rollId === DND_5E_SRD_BERSERKER_MINDLESS_RAGE_ROLL_ID ||
    rollId === DND_5E_SRD_BERSERKER_RETALIATION_ROLL_ID ||
    rollId === DND_5E_SRD_BERSERKER_INTIMIDATING_PRESENCE_ROLL_ID
  ) return "0";
  if (rollId === DND_5E_SRD_BARDIC_INSPIRATION_ROLL_ID) return dnd5eSrdBardicInspirationFormula(actor);
  if (rollId === DND_5E_SRD_FONT_OF_INSPIRATION_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_LORE_CUTTING_WORDS_ROLL_ID || rollId === DND_5E_SRD_LORE_PEERLESS_SKILL_ROLL_ID) return dnd5eSrdBardicInspirationFormula(actor);
  if (rollId === DND_5E_SRD_LORE_MAGICAL_DISCOVERIES_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_LAY_ON_HANDS_ROLL_ID) return dnd5eSrdLayOnHandsFormula(actor, options.resourceAmount);
  if (rollId === DND_5E_SRD_DIVINE_SMITE_ROLL_ID) return dnd5eSrdDivineSmiteFormula(actor, options.useFreeResource ? 1 : options.spellSlotLevel);
  if (rollId === DND_5E_SRD_FAITHFUL_STEED_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_DEVOTION_HOLY_NIMBUS_ROLL_ID) return dnd5eSrdDevotionHolyNimbusFormula(actor);
  if (rollId === DND_5E_SRD_DEVOTION_SACRED_WEAPON_ROLL_ID || rollId === DND_5E_SRD_DEVOTION_AURA_ROLL_ID || rollId === DND_5E_SRD_DEVOTION_SMITE_PROTECTION_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_HUNTERS_MARK_DAMAGE_ROLL_ID) return dnd5eSrdHuntersMarkFormula(actor);
  if (rollId === DND_5E_SRD_HUNTER_PREY_ROLL_ID) return "1d8";
  if (rollId === DND_5E_SRD_HUNTER_SUPERIOR_PREY_ROLL_ID) return dnd5eSrdHuntersMarkFormula(actor);
  if (rollId === DND_5E_SRD_HUNTER_LORE_ROLL_ID || rollId === DND_5E_SRD_HUNTER_DEFENSIVE_TACTICS_ROLL_ID || rollId === DND_5E_SRD_HUNTER_SUPERIOR_DEFENSE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_MARTIAL_ARTS_DAMAGE_ROLL_ID) return dnd5eSrdMartialArtsFormula(actor);
  if (rollId === DND_5E_SRD_FLURRY_OF_BLOWS_ROLL_ID || rollId === DND_5E_SRD_PATIENT_DEFENSE_ROLL_ID || rollId === DND_5E_SRD_STEP_OF_THE_WIND_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_UNCANNY_METABOLISM_ROLL_ID) return dnd5eSrdUncannyMetabolismFormula(actor);
  if (rollId === DND_5E_SRD_DEFLECT_ATTACKS_DAMAGE_ROLL_ID) return dnd5eSrdDeflectAttacksDamageFormula(actor);
  if (rollId === DND_5E_SRD_STUNNING_STRIKE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_OPEN_HAND_TECHNIQUE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_OPEN_HAND_WHOLENESS_ROLL_ID) return dnd5eSrdOpenHandWholenessFormula(actor);
  if (rollId === DND_5E_SRD_OPEN_HAND_FLEET_STEP_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_OPEN_HAND_QUIVERING_PALM_ROLL_ID) return "10d12";
  if (
    rollId === DND_5E_SRD_INNATE_SORCERY_ROLL_ID ||
    rollId === DND_5E_SRD_CONVERT_SPELL_SLOT_ROLL_ID ||
    rollId === DND_5E_SRD_CREATE_SPELL_SLOT_ROLL_ID ||
    rollId === DND_5E_SRD_METAMAGIC_EMPOWERED_ROLL_ID ||
    rollId === DND_5E_SRD_METAMAGIC_QUICKENED_ROLL_ID
  )
    return "0";
  if (rollId === DND_5E_SRD_DRACONIC_RESILIENCE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_DRACONIC_ELEMENTAL_AFFINITY_ROLL_ID) return String(genericFantasyAttributeModifier(actor, "charisma"));
  if (rollId === DND_5E_SRD_DRACONIC_WINGS_ROLL_ID || rollId === DND_5E_SRD_DRACONIC_COMPANION_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_EVOKER_EMPOWERED_EVOCATION_ROLL_ID) return dnd5eSrdEvokerEmpoweredEvocationFormula(actor);
  if (rollId === DND_5E_SRD_EVOKER_POTENT_CANTRIP_ROLL_ID || rollId === DND_5E_SRD_EVOKER_SCULPT_SPELLS_ROLL_ID || rollId === DND_5E_SRD_EVOKER_OVERCHANNEL_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_ELDRITCH_INVOCATIONS_ROLL_ID || rollId === DND_5E_SRD_MAGICAL_CUNNING_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_FIEND_DARK_BLESSING_ROLL_ID) return dnd5eSrdFiendDarkBlessingFormula(actor);
  if (rollId === DND_5E_SRD_FIEND_DARK_LUCK_ROLL_ID) return "1d10";
  if (rollId === DND_5E_SRD_FIEND_RESILIENCE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_FIEND_HURL_THROUGH_HELL_ROLL_ID) return "8d10";
  if (
    rollId === DND_5E_SRD_WILD_SHAPE_ROLL_ID ||
    rollId === DND_5E_SRD_WILD_COMPANION_ROLL_ID ||
    rollId === DND_5E_SRD_WILD_RESURGENCE_WILD_SHAPE_ROLL_ID ||
    rollId === DND_5E_SRD_WILD_RESURGENCE_SPELL_SLOT_ROLL_ID
  ) return "0";
  if (rollId === DND_5E_SRD_MOON_LUNAR_FORM_ROLL_ID) return "2d10";
  if (rollId === DND_5E_SRD_MOON_CIRCLE_FORMS_ROLL_ID || rollId === DND_5E_SRD_MOON_IMPROVED_CIRCLE_FORMS_ROLL_ID || rollId === DND_5E_SRD_MOON_MOONLIGHT_STEP_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_DIVINE_SPARK_HEALING_ROLL_ID || rollId === DND_5E_SRD_DIVINE_SPARK_DAMAGE_ROLL_ID) return dnd5eSrdDivineSparkFormula(actor);
  if (rollId === DND_5E_SRD_TURN_UNDEAD_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_SEAR_UNDEAD_DAMAGE_ROLL_ID) return dnd5eSrdSearUndeadFormula(actor);
  if (rollId === DND_5E_SRD_LIFE_DISCIPLE_ROLL_ID || rollId === DND_5E_SRD_LIFE_BLESSED_HEALER_ROLL_ID) return dnd5eSrdLifeSlotBonusFormula(spellActionSlotLevel(1, options.spellSlotLevel));
  if (rollId === DND_5E_SRD_LIFE_PRESERVE_LIFE_ROLL_ID) return dnd5eSrdPreserveLifeFormula(actor);
  if (rollId === DND_5E_SRD_LIFE_SUPREME_HEALING_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_SNEAK_ATTACK_DAMAGE_ROLL_ID) return dnd5eSrdSneakAttackFormula(actor);
  if (rollId === DND_5E_SRD_CUNNING_STRIKE_ROLL_ID) return "0";
  if (
    rollId === DND_5E_SRD_THIEF_FAST_HANDS_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_SECOND_STORY_WORK_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_SUPREME_SNEAK_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_REFLEXES_ROLL_ID
  ) return "0";
  if (rollId === DND_5E_SRD_THIEF_USE_MAGIC_DEVICE_ROLL_ID) return "1d6";
  if (rollId === DND_5E_SRD_DRAGONBORN_BREATH_WEAPON_ROLL_ID) return dnd5eSrdDragonbornBreathWeaponFormula(actor);
  if (rollId === DND_5E_SRD_GOLIATH_GIANT_ANCESTRY_ROLL_ID) return dnd5eSrdGiantAncestryFormula(actor);
  if (
    rollId === DND_5E_SRD_HUMAN_RESOURCEFUL_ROLL_ID ||
    rollId === DND_5E_SRD_HUMAN_SKILLFUL_ROLL_ID ||
    rollId === DND_5E_SRD_HUMAN_VERSATILE_ROLL_ID
  ) return "0";
  if (
    rollId === DND_5E_SRD_ELF_ELVEN_LINEAGE_ROLL_ID ||
    rollId === DND_5E_SRD_ELF_FEY_ANCESTRY_ROLL_ID ||
    rollId === DND_5E_SRD_ELF_TRANCE_ROLL_ID ||
    rollId === DND_5E_SRD_GNOME_GNOMISH_CUNNING_ROLL_ID ||
    rollId === DND_5E_SRD_GNOME_LINEAGE_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_LUCK_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_BRAVE_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_NIMBLENESS_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_NATURALLY_STEALTHY_ROLL_ID
  ) return "0";
  if (rollId === DND_5E_SRD_TIEFLING_FIENDISH_LEGACY_ROLL_ID || rollId === DND_5E_SRD_TIEFLING_OTHERWORLDLY_PRESENCE_ROLL_ID) return "0";
  if (rollId === DND_5E_SRD_ORC_ADRENALINE_RUSH_ROLL_ID) return dnd5eSrdAdrenalineRushFormula(actor);
  if (dnd5eSrdSpeciesResourceAction(rollId)) return "0";
  if (rollId.startsWith("monster-")) return dnd5eSrdMonsterActionRolls(actor).find((roll) => roll.id === rollId)?.formula;
  const actionItems = dnd5eSrdActionAvailableItems(actor, items);
  if (rollId.endsWith("-attack") || rollId.endsWith("-effect")) return dnd5eSrdActionRolls(actor, actionItems).find((roll) => roll.id === rollId)?.formula;
  const slotLevel = dnd5eSrdSpellActionSlotLevel(actor, actionItems, rollId, options);
  const formula = genericFantasyActionFormula(actor, actionItems, rollId, slotLevel ? { ...options, spellSlotLevel: slotLevel } : options);
  const rageDamageBonus = dnd5eSrdRageDamageBonusForRoll(actor, actionItems, rollId);
  return formula && rageDamageBonus > 0 ? appendFormulaBonus(formula, rageDamageBonus) : formula;
}

export function resolveDnd5eSrdAction(input: Dnd5eSrdActionResolutionInput): RulesActionResolutionResult {
  const items = input.items ?? [];
  const targets = input.targets ?? [];
  const options = input.options ?? {};
  const now = input.now ?? new Date().toISOString();
  const commitMode: RulesResolutionCommitMode = options.commit === false ? "preview" : "commit";
  const metadata = cloneJsonRecord(recordValue(input.roll.metadata));
  const actionKind = dnd5eSrdActionKind(input.roll);
  const warnings: string[] = [];
  const conditions: RulesResolutionConditionChange[] = [];
  const pendingSaves: RulesResolutionPendingSave[] = [];
  const pendingReactions: RulesResolutionPendingReaction[] = [];
  const auditEvents: RulesResolutionAuditEvent[] = [];
  const concentrationCleanups: Dnd5eSrdConcentrationCleanup[] = [];
  const effects: RulesResolutionEffectResult[] = [];
  const actorUpdates = new Map<string, RulesResolutionActorUpdate>();
  const itemUpdates = new Map<string, Item>();
  const targetDataByActorId = new Map<string, Record<string, unknown>>();
  let actorData = cloneJsonRecord(input.actor.data);
  let usage: SystemActionUseResult | undefined;
  let actionLedger: Dnd5eSrdTurnActionLedger | undefined;
  let weaponMastery: Dnd5eSrdWeaponMasteryResolution | undefined;
  const calculationOverride = recordValue(metadata.calculationOverride);
  if (stringValue(calculationOverride.id)) auditEvents.push({ code: "calculation.override.applied", actorId: input.actor.id, rollId: input.roll.id, message: `Applied calculation override to ${input.roll.label}`, data: { ...cloneJsonRecord(calculationOverride), overrideId: stringValue(calculationOverride.id) } });
  const requestedItem = actionItemForRoll(input.actor, items, input.roll.id, ["spell", "item"]);
  if (
    requestedItem &&
    dnd5eSrdRollEffectType(input.roll) === "damage" &&
    !stringValue(metadata.damageType) &&
    normalizeStringArray(metadata.damageTypes).length === 0 &&
    normalizeStringArray(metadata.damageTypeOptions).length === 0 &&
    Object.keys(recordValue(metadata.damageBreakdown)).length === 0
  ) {
    const itemData = recordValue(requestedItem.data);
    const storedDamageType = stringValue(input.roll.id.endsWith("-secondary-damage") ? itemData.secondaryDamageType : itemData.damageType);
    // Basic weapon/item damage rolls historically omitted redundant metadata.
    // Recover the authoritative stored type at resolution so defenses and
    // temporary Hit Points are never bypassed by that presentation shortcut.
    if (storedDamageType) metadata.damageType = storedDamageType;
  }
  const ritualAvailable = requestedItem?.type === "spell" && dnd5eSrdWizardRitualSpellAvailable(input.actor, requestedItem);
  let blocked = options.ritualCast && requestedItem?.type === "spell" && !ritualAvailable
    ? { code: "ritual_cast_unavailable", reason: `${requestedItem.name} is not an eligible Wizard ritual in this actor's stored spellbook.` }
    : requestedItem?.type === "spell" && recordValue(requestedItem.data).prepared === false && !(options.ritualCast && ritualAvailable)
    ? { code: "spell_not_prepared", reason: `${requestedItem.name} must be prepared or explicitly cast as an eligible Wizard ritual before its actions can be used.` }
    : requestedItem && dnd5eSrdItemRequiresAttunement(requestedItem) && !dnd5eSrdItemModifiersAreActive(input.actor, requestedItem)
    ? { code: "attunement_required", reason: `${requestedItem.name} requires active attunement before its actions can be used.` }
    : options.ignoreSourceActionRestrictions
    ? undefined
    : dnd5eSrdResolutionBlock(input.actor, actionKind);
  if (!blocked) blocked = dnd5eSrdRagePreflight({ actor: input.actor, items, ...(requestedItem ? { requestedItem } : {}), roll: { id: input.roll.id, metadata }, consumeResources: Boolean(options.consumeResources) });
  const targetInputs = targets.length > 0 ? targets : [];
  if (!blocked) blocked = dnd5eSrdWeaponMasteryPreflight({ actor: input.actor, data: actorData, ...(requestedItem ? { item: requestedItem } : {}), roll: { id: input.roll.id, metadata }, targets: targetInputs.map((target) => ({ ...target, armorClass: dnd5eSrdArmorClass(target.actor, target.items ?? []).value, proneImmune: dnd5eSrdConditionImmunities(target.actor, target.items).includes("prone") })), combat: input.combat, options: options.weaponMastery });
  const rolls = dnd5eSrdResolutionRolls(input.actor, targetInputs, input.roll, options);
  const targetActorForResolution = (target: RulesResolutionTargetInput): Actor => ({
    ...target.actor,
    data: target.actor.id === input.actor.id ? actorData : targetDataByActorId.get(target.actor.id) ?? target.actor.data
  });
  const setResolvedTargetData = (target: RulesResolutionTargetInput, data: Record<string, unknown>, reason: string) => {
    if (target.actor.id === input.actor.id) {
      actorData = data;
      return;
    }
    targetDataByActorId.set(target.actor.id, data);
    actorUpdates.set(target.actor.id, {
      actorId: target.actor.id,
      before: cloneJsonRecord(target.actor.data),
      after: data,
      reason
    });
  };

  if ((options.reactionUse || actionKind === "reaction") && !blocked) {
    const reactionResult = dnd5eSrdApplyReactionUse(actorData, input.actor.id, input.roll.id, input.combat, now);
    actorData = reactionResult.data;
    auditEvents.push(...reactionResult.auditEvents);
    if (reactionResult.blocked) blocked = reactionResult.blocked;
  }

  if (actionKind === "bonusAction" && !blocked) {
    const bonusActionResult = dnd5eSrdApplyBonusActionUse(actorData, input.actor.id, input.roll.id, input.combat, now);
    actorData = bonusActionResult.data;
    auditEvents.push(...bonusActionResult.auditEvents);
    if (bonusActionResult.blocked) blocked = bonusActionResult.blocked;
  }

  if (actionKind === "action" && !blocked && !dnd5eSrdNickExtraAttackRequested(metadata, options.weaponMastery)) {
    const actionResult = applyDnd5eSrdStandardActionUse(actorData, input.actor.id, input.roll.id, input.combat, now);
    actorData = actionResult.data; actionLedger = actionResult.ledger;
    auditEvents.push(...actionResult.auditEvents);
    if (actionResult.blocked) blocked = actionResult.blocked;
  }
  if (options.consumeResources && !blocked) {
    try {
      usage = useDnd5eSrdAction({ ...input.actor, data: actorData }, items, input.roll.id, options);
      actorData = cloneJsonRecord(usage.data);
      for (const updatedItem of usage.items) itemUpdates.set(updatedItem.id, updatedItem);
    } catch (error) {
      blocked = {
        code: "resource_unavailable",
        reason: error instanceof Error ? error.message : "System action resources are unavailable"
      };
    }
  }
  if (input.roll.id === DND_5E_SRD_ACTION_SURGE_ROLL_ID && usage && !blocked) {
    const actionSurge = grantDnd5eSrdActionSurge(actorData, input.actor.id, input.roll.id, input.combat, now);
    actorData = actionSurge.data; actionLedger = actionSurge.ledger;
    auditEvents.push(...actionSurge.auditEvents);
    if (actionSurge.blocked) blocked = actionSurge.blocked;
  }
  if (!blocked) {
    const rage = resolveDnd5eSrdRageLifecycle({ actor: { ...input.actor, data: actorData }, items, roll: { id: input.roll.id, metadata }, targetActorIds: targetInputs.map((target) => target.actor.id), combat: input.combat, now });
    actorData = rage.data;
    effects.push(...rage.effects); conditions.push(...rage.conditions); warnings.push(...rage.warnings); auditEvents.push(...rage.auditEvents); concentrationCleanups.push(...rage.concentrationCleanups);
    if (rage.blocked) blocked = rage.blocked;
  }
  if (!blocked) {
    const masteryTargets = targetInputs.map((target) => { const actor = targetActorForResolution(target); return { ...target, actor, armorClass: dnd5eSrdArmorClass(actor, target.items ?? []).value, proneImmune: dnd5eSrdConditionImmunities(actor, target.items).includes("prone") }; });
    const mastery = resolveDnd5eSrdWeaponMastery({ actor: { ...input.actor, data: actorData }, data: actorData, ...(requestedItem ? { item: requestedItem } : {}), roll: { id: input.roll.id, label: input.roll.label, metadata }, targets: masteryTargets, combat: input.combat, now, abilityModifier: genericFantasyAttributeModifier(input.actor, stringValue(metadata.ability) ?? "strength"), proficiencyBonus: dnd5eSrdProficiencyBonus(input.actor), options: options.weaponMastery, applyGrazeDamage: (target, amount, damageType) => dnd5eSrdApplyRollTotalEffectResolution(target.actor, target.items ?? [], { id: `${input.roll.id}-graze-damage`, label: `${input.roll.label} Graze Damage`, formula: String(amount), metadata: { effectType: "damage", damageType } }, { damageType }, amount, undefined, { ...options, applyEffect: true }, now) });
    actorData = mastery.data; weaponMastery = mastery.resolution;
    if (mastery.actionLedger) actionLedger = mastery.actionLedger;
    effects.push(...mastery.effects); conditions.push(...mastery.conditions); pendingSaves.push(...mastery.pendingSaves); warnings.push(...mastery.warnings); auditEvents.push(...mastery.auditEvents); concentrationCleanups.push(...mastery.concentrationCleanups);
    for (const update of mastery.targetData) { const target = targetInputs.find((candidate) => candidate.actor.id === update.actorId); if (target) setResolvedTargetData(target, update.data, `weapon-mastery:${weaponMastery?.property ?? "effect"}`); }
    if (mastery.blocked) blocked = mastery.blocked;
  }
  const recharge = stringValue(metadata.recharge);
  if (recharge && !blocked) {
    const rechargeResult = dnd5eSrdApplyRechargeResolution(actorData, input.roll, recharge, options, now);
    actorData = rechargeResult.data;
    warnings.push(...rechargeResult.warnings);
    auditEvents.push(...rechargeResult.auditEvents);
    if (rechargeResult.blocked) blocked = rechargeResult.blocked;
  }

  if (metadata.concentration === true && !blocked) {
    const concentrationResult = dnd5eSrdStartConcentration(actorData, input.actor, input.roll, targetInputs.map((target) => target.actor.id), input.combat, now);
    actorData = concentrationResult.data;
    conditions.push(...concentrationResult.conditions);
    warnings.push(...concentrationResult.warnings);
    auditEvents.push(...concentrationResult.auditEvents);
    if (concentrationResult.cleanup) concentrationCleanups.push(concentrationResult.cleanup);
  }

  // Blocked before dice for ineligible actors; mutates only on the post-roll
  // commit pass that carries the authoritative rolled result.
  let deathSave: Dnd5eSrdDeathSaveSummary | undefined;
  if (input.roll.id === DND_5E_SRD_DEATH_SAVE_ROLL_ID && !blocked) {
    const applied = applyDnd5eSrdDeathSaveRoll({ ...input.actor, data: actorData }, commitMode === "commit" ? options.selfRollResult : undefined);
    if (applied.blocked) blocked = applied.blocked;
    if (applied.resolved) {
      actorData = applied.resolved.data;
      deathSave = applied.resolved.deathSave;
      auditEvents.push({ code: "death-save", actorId: input.actor.id, rollId: input.roll.id, message: `${input.actor.name} Death Saving Throw: ${dnd5eSrdDeathSaveChatSuffix(deathSave)}`, data: { ...deathSave } });
      if (deathSave.hitPointsRestored) effects.push({ type: "healing", targetActorId: input.actor.id, targetActorName: input.actor.name, pool: "hp", amount: deathSave.hitPointsRestored, before: 0, after: deathSave.hitPointsRestored });
    }
  }

  for (const target of targetInputs) {
    const damageTaken = Math.floor(numericValue(target.damageTaken, Number.NaN));
    if (!Number.isFinite(damageTaken) || damageTaken <= 0) continue;
    const resolvedTarget = targetActorForResolution(target);
    const concentrationDamage = resolveDnd5eSrdConcentrationDamage(resolvedTarget, damageTaken, dnd5eSrdTargetSaveOutcome(target.actor.id, target, options), now, input.roll.id);
    if (concentrationDamage.pendingSave) pendingSaves.push(concentrationDamage.pendingSave);
    if (concentrationDamage.condition) conditions.push(concentrationDamage.condition);
    if (concentrationDamage.auditEvent) auditEvents.push(concentrationDamage.auditEvent);
    if (concentrationDamage.cleanup) concentrationCleanups.push(concentrationDamage.cleanup);
    if (JSON.stringify(concentrationDamage.data) !== JSON.stringify(resolvedTarget.data)) {
      setResolvedTargetData(target, concentrationDamage.data, "concentration-damage");
    }
  }

  const save = recordValue(metadata.save);
  const saveAbility = stringValue(save.ability);
  if (saveAbility) {
    for (const target of targetInputs) {
      const outcome = dnd5eSrdTargetSaveOutcome(target.actor.id, target, options);
      if (outcome) continue;
      pendingSaves.push({
        actorId: target.actor.id,
        ability: saveAbility,
        dc: Number.isFinite(numericValue(save.dc, Number.NaN)) ? numericValue(save.dc, Number.NaN) : undefined,
        reason: `${input.roll.label} requires a ${titleCaseWords(saveAbility)} save`,
        success: save.success,
        requiredForCommit: Boolean(options.applyEffect)
      });
    }
  }

  if (options.applyEffect && !blocked) {
    for (const target of targetInputs) {
      const resolvedTarget = targetActorForResolution(target);
      const effectResult = dnd5eSrdApplyTargetEffectResolution(resolvedTarget, target.items ?? [], input.actor.id, input.roll, metadata, target.rollTotal, dnd5eSrdTargetSaveOutcome(target.actor.id, target, options), options, input.combat, now);
      if (!effectResult) continue;
      effects.push(...effectResult.effects);
      conditions.push(...effectResult.conditions);
      pendingSaves.push(...effectResult.pendingSaves);
      auditEvents.push(...effectResult.auditEvents);
      concentrationCleanups.push(...effectResult.concentrationCleanups);
      if (JSON.stringify(effectResult.data) !== JSON.stringify(resolvedTarget.data)) {
        setResolvedTargetData(target, effectResult.data, "target-effect");
      }
    }
  }

  const reactionPrompt = dnd5eSrdPendingReaction(input.actor, input.roll, metadata);
  if (reactionPrompt) pendingReactions.push(reactionPrompt);

  const pendingChoice = dnd5eSrdPendingChoice(metadata, options);
  const manualResolutionRequired = dnd5eSrdManualResolution(input.roll, metadata, pendingChoice, options);
  if (manualResolutionRequired) warnings.push(manualResolutionRequired.reason);

  const attunement = dnd5eSrdAttunementStateForData(actorData);
  if (attunement.overLimitBy > 0) {
    warnings.push(attunement.overrideReason
      ? `Attunement limit exceeded by ${attunement.overLimitBy} under override: ${attunement.overrideReason}.`
      : `Attunement limit exceeded by ${attunement.overLimitBy}; ${attunement.inactiveAttunedItemIds.length} over-limit item effect${attunement.inactiveAttunedItemIds.length === 1 ? " is" : "s are"} inactive.`);
  }

  if (JSON.stringify(actorData) !== JSON.stringify(input.actor.data)) {
    actorUpdates.set(input.actor.id, {
      actorId: input.actor.id,
      before: cloneJsonRecord(input.actor.data),
      after: actorData,
      reason: "action-resolution"
    });
  }

  return {
    systemId: DND_5E_SRD_SYSTEM_ID,
    actorId: input.actor.id,
    rollId: input.roll.id,
    commitMode,
    action: {
      label: input.roll.label,
      kind: actionKind,
      metadata,
      ...(actionLedger ? { ledger: actionLedger } : {})
    },
    rolls,
    resourceConsumption: usage?.consumed ?? [],
    ...(usage ? { usage } : {}),
    actorUpdates: [...actorUpdates.values()],
    itemUpdates: [...itemUpdates.values()],
    effects,
    conditions,
    pendingSaves,
    pendingReactions,
    warnings,
    auditEvents,
    ...(blocked ? { blocked } : {}),
    ...(pendingChoice ? { pendingChoice } : {}),
    ...(manualResolutionRequired ? { manualResolutionRequired } : {}),
    attunement,
    ...(concentrationCleanups.length > 0 ? { concentrationCleanups: [...new Map(concentrationCleanups.map((cleanup) => [`${cleanup.sourceActorId}:${cleanup.rollId}:${cleanup.startedAt ?? "legacy"}:${cleanup.reason}`, cleanup])).values()] } : {}),
    ...(deathSave ? { deathSave } : {}),
    ...(weaponMastery ? { weaponMastery } : {})
  };
}

function dnd5eSrdConcentrationCleanupDescriptor(
  fallbackSourceActorId: string,
  concentration: Record<string, unknown>,
  reason: Dnd5eSrdConcentrationCleanup["reason"]
): Dnd5eSrdConcentrationCleanup | undefined {
  const rollId = stringValue(concentration.rollId);
  if (!rollId) return undefined;
  return {
    sourceActorId: stringValue(concentration.sourceActorId) ?? fallbackSourceActorId,
    rollId,
    ...(stringValue(concentration.startedAt) ? { startedAt: stringValue(concentration.startedAt) } : {}),
    targetActorIds: uniqueStrings(normalizeStringArray(concentration.targetActorIds)),
    reason
  };
}

export function resolveDnd5eSrdConcentrationDamage(
  actor: Actor,
  damageTaken: number,
  saveOutcome?: RulesSaveOutcome,
  now = new Date().toISOString(),
  sourceRollId = "damage"
): Dnd5eSrdConcentrationDamageResult {
  const data = cloneJsonRecord(actor.data);
  const rules = dnd5eSrdRulesEngineState(data);
  const concentration = recordValue(rules.concentration);
  const rollId = stringValue(concentration.rollId) ?? "concentration";
  if (!Object.keys(concentration).length) return { data };
  const dc = dnd5eSrdConcentrationDc(damageTaken);
  const concentrationBreakingCondition = dnd5eSrdConditionIds(data.conditions).some((conditionId) => ["incapacitated", "paralyzed", "petrified", "stunned", "unconscious", "dead"].includes(conditionId));
  const resolvedOutcome = concentrationBreakingCondition ? "failure" : saveOutcome;
  if (!resolvedOutcome) {
    return {
      data,
      pendingSave: {
        actorId: actor.id,
        ability: "constitution",
        dc,
        reason: `Concentration save for ${damageTaken} damage`,
        success: "concentration maintained"
      }
    };
  }
  if (resolvedOutcome === "success") return { data };
  const cleanup = dnd5eSrdConcentrationCleanupDescriptor(actor.id, concentration, "broken");
  delete rules.concentration;
  if (Array.isArray(rules.activeEffects)) {
    rules.activeEffects = rules.activeEffects.filter((effect) => recordValue(effect).concentration !== true);
  }
  const nextData = dnd5eSrdDataWithRulesEngineState(data, rules);
  return {
    data: nextData,
    condition: {
      actorId: actor.id,
      operation: "breakConcentration",
      conditionId: "concentration",
      conditionName: "Concentration",
      reason: concentrationBreakingCondition ? "An incapacitating condition ended concentration" : `Failed DC ${dc} Constitution save after ${damageTaken} damage`
    },
    auditEvent: {
      code: "concentration.broken",
      actorId: actor.id,
      rollId: sourceRollId,
      message: `${actor.name} lost concentration on ${stringValue(concentration.label) ?? rollId}`,
      data: { damageTaken, dc, concentration: cloneJsonRecord(concentration) }
    },
    ...(cleanup ? { cleanup } : {})
  };
}

function dnd5eSrdConditionValueId(value: unknown): string | undefined {
  if (typeof value === "string") return dnd5eSrdConditionId(value);
  return stringValue(recordValue(value).id);
}

export function applyDnd5eSrdConcentrationCleanup(target: Actor, cleanup: Dnd5eSrdConcentrationCleanup): Dnd5eSrdConcentrationCleanupResult {
  const data = cloneJsonRecord(target.data);
  if (!cleanup.targetActorIds.includes(target.id)) return { data, removedEffectIds: [], removedConditionIds: [] };
  const rules = dnd5eSrdRulesEngineState(data);
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.map((effect) => cloneJsonRecord(recordValue(effect))) : [];
  const removedEffects = activeEffects.filter((effect) =>
    stringValue(effect.sourceActorId) === cleanup.sourceActorId &&
    stringValue(effect.rollId) === cleanup.rollId &&
    (!cleanup.startedAt || stringValue(effect.startedAt) === cleanup.startedAt)
  );
  if (removedEffects.length === 0) return { data, removedEffectIds: [], removedConditionIds: [] };
  const remainingEffects = activeEffects.filter((effect) => !removedEffects.includes(effect));
  rules.activeEffects = remainingEffects;
  const removedOwnedConditionIds = uniqueStrings(removedEffects.flatMap((effect) => normalizeStringArray(effect.ownedConditionIds)));
  const remainingOwnedConditionIds = new Set(remainingEffects.flatMap((effect) => normalizeStringArray(effect.ownedConditionIds)));
  const removedConditionIds = removedOwnedConditionIds.filter((conditionId) => !remainingOwnedConditionIds.has(conditionId));
  const nextData: Record<string, unknown> = dnd5eSrdDataWithRulesEngineState(data, rules);
  if (removedConditionIds.length > 0 && Array.isArray(data.conditions)) {
    nextData.conditions = data.conditions.filter((condition) => {
      const conditionId = dnd5eSrdConditionValueId(condition);
      return !conditionId || !removedConditionIds.includes(conditionId);
    });
  }
  return {
    data: nextData,
    removedEffectIds: removedEffects.map((effect) => stringValue(effect.id)).filter((effectId): effectId is string => Boolean(effectId)),
    removedConditionIds
  };
}

export function dnd5eSrdConcentrationCleanupActorUpdates(
  actors: Actor[],
  cleanups: Dnd5eSrdConcentrationCleanup[]
): RulesResolutionActorUpdate[] {
  const updates: RulesResolutionActorUpdate[] = [];
  for (const actor of actors) {
    const before = cloneJsonRecord(actor.data);
    let data = before;
    const applied: string[] = [];
    for (const cleanup of cleanups) {
      const result = applyDnd5eSrdConcentrationCleanup({ ...actor, data }, cleanup);
      data = result.data;
      if (result.removedEffectIds.length > 0) applied.push(`${cleanup.sourceActorId}:${cleanup.rollId}`);
    }
    if (JSON.stringify(data) !== JSON.stringify(before)) {
      updates.push({ actorId: actor.id, before, after: data, reason: `concentration-cleanup:${applied.join(",")}` });
    }
  }
  return updates;
}

export function dnd5eSrdAttunementLimit(actor: Actor): number {
  const features = normalizeStringArray(actor.data.features).map((feature) => feature.toLowerCase());
  const thiefUseMagicDevice = dnd5eSrdHasSelectedSubclassLevel(actor, "Rogue", 13, "thief")
    || (dnd5eSrdClassLevel(actor, "Rogue") >= 13 && features.some((feature) => feature.includes("use magic device") || feature.includes("thief")));
  return thiefUseMagicDevice ? 4 : 3;
}

export function dnd5eSrdAttunementState(actor: Actor): Dnd5eSrdAttunementState {
  return dnd5eSrdAttunementStateForData(actor.data);
}

function dnd5eSrdResolutionBlock(actor: Actor, actionKind: RulesActionResolutionResult["action"]["kind"]): RulesResolutionBlocked | undefined {
  const effects = dnd5eSrdConditionEffects(normalizeConditionRecords(actor.data.conditions));
  const blockingSources = effects.filter((effect) => {
    if (actionKind === "reaction") return effect.data.reactions === false;
    if (actionKind === "bonusAction") return effect.data.bonusActions === false || effect.data.actions === false;
    if (actionKind === "action") return effect.data.actions === false;
    return false;
  });
  if (blockingSources.length === 0) return undefined;
  const names = blockingSources.map((effect) => dnd5eSrdCompendiumEntry(effect.sourceId)?.name ?? titleCaseWords(effect.sourceId));
  const label = actionKind === "bonusAction" ? "bonus action" : actionKind;
  return {
    code: `${actionKind}_blocked`,
    reason: `${names.join(", ")} prevents this ${label}.`
  };
}

function dnd5eSrdResolutionRolls(actor: Actor, targets: RulesResolutionTargetInput[], roll: QuickRoll, options: RulesResolverOptions): RulesResolutionRoll[] {
  const rollTargets = dnd5eSrdIsAttackRoll(roll) && targets.length > 0 ? targets : [targets[0]].filter((target): target is RulesResolutionTargetInput => Boolean(target));
  if (rollTargets.length === 0) return [dnd5eSrdResolutionRollForTarget(actor, undefined, roll, options)];
  return rollTargets.map((target) => dnd5eSrdResolutionRollForTarget(actor, target, roll, options));
}

function dnd5eSrdResolutionRollForTarget(actor: Actor, target: RulesResolutionTargetInput | undefined, roll: QuickRoll, options: RulesResolverOptions): RulesResolutionRoll {
  const targetAware = dnd5eSrdTargetAwareRoll(actor, target?.actor, roll);
  return {
    rollId: roll.id,
    label: roll.label,
    baseFormula: stringValue(recordValue(recordValue(roll.metadata).calculationOverride).baseFormula) ?? roll.formula,
    formula: targetAware.formula,
    ...(target ? { targetActorId: target.actor.id } : {}),
    ...(targetAware.d20Mode ? { d20Mode: targetAware.d20Mode } : {}),
    advantageSources: targetAware.advantageSources,
    disadvantageSources: targetAware.disadvantageSources,
    ...(target ? { saveOutcome: dnd5eSrdTargetSaveOutcome(target.actor.id, target, options) } : {})
  };
}

function dnd5eSrdIsAttackRoll(roll: QuickRoll): boolean {
  const metadata = recordValue(roll.metadata);
  return roll.id.endsWith("-attack") || stringValue(metadata.attackType) !== undefined;
}

function dnd5eSrdTargetAwareRoll(actor: Actor, target: Actor | undefined, roll: QuickRoll): { formula: string; d20Mode?: RulesD20Mode; advantageSources: string[]; disadvantageSources: string[] } {
  if (!dnd5eSrdIsAttackRoll(roll)) {
    const metadata = recordValue(roll.metadata);
    const declaredMode = stringValue(metadata.d20Mode);
    const formulaMode = dnd5eSrdFormulaD20Mode(roll.formula);
    const d20Mode = declaredMode && formulaMode ? formulaMode : undefined;
    return {
      formula: roll.formula,
      ...(d20Mode ? { d20Mode } : {}),
      advantageSources: d20Mode ? normalizeStringArray(metadata.advantageSources) : [],
      disadvantageSources: d20Mode ? normalizeStringArray(metadata.disadvantageSources) : [],
    };
  }
  const advantageSources: string[] = [];
  const disadvantageSources: string[] = [];
  const masterySources = dnd5eSrdWeaponMasteryRollModeSources(actor, target);
  advantageSources.push(...masterySources.advantageSources);
  disadvantageSources.push(...masterySources.disadvantageSources);
  for (const effect of dnd5eSrdConditionEffects(normalizeConditionRecords(actor.data.conditions))) {
    const source = dnd5eSrdCompendiumEntry(effect.sourceId)?.name ?? titleCaseWords(effect.sourceId);
    if (stringValue(effect.data.attackRolls) === "advantage" || stringValue(effect.data.attackRollsWhileSourceVisible) === "advantage") advantageSources.push(source);
    if (stringValue(effect.data.attackRolls) === "disadvantage" || stringValue(effect.data.attackRollsWhileSourceVisible) === "disadvantage") disadvantageSources.push(source);
  }
  if (target) {
    for (const effect of dnd5eSrdConditionEffects(normalizeConditionRecords(target.data.conditions))) {
      const source = dnd5eSrdCompendiumEntry(effect.sourceId)?.name ?? titleCaseWords(effect.sourceId);
      if (stringValue(effect.data.attacksAgainst) === "advantage") advantageSources.push(`${target.name}: ${source}`);
      if (stringValue(effect.data.attacksAgainst) === "disadvantage") disadvantageSources.push(`${target.name}: ${source}`);
    }
  }
  const d20Mode: RulesD20Mode = advantageSources.length > 0 && disadvantageSources.length === 0 ? "advantage" : disadvantageSources.length > 0 && advantageSources.length === 0 ? "disadvantage" : "normal";
  const d20 = d20Mode === "advantage" ? "2d20kh1" : d20Mode === "disadvantage" ? "2d20kl1" : "1d20";
  return {
    formula: roll.formula.replace(/^(?:1d20|2d20k[hl]1)/, d20),
    d20Mode,
    advantageSources: uniqueStrings(advantageSources),
    disadvantageSources: uniqueStrings(disadvantageSources)
  };
}

function dnd5eSrdTargetSaveOutcome(actorId: string, target: RulesResolutionTargetInput | undefined, options: RulesResolverOptions): RulesSaveOutcome | undefined {
  return target?.saveOutcome ?? options.saveOutcomes?.[actorId];
}

function dnd5eSrdStartConcentration(
  data: Record<string, unknown>,
  actor: Actor,
  roll: QuickRoll,
  targetActorIds: string[],
  combat: Combat | undefined,
  now: string
): { data: Record<string, unknown>; conditions: RulesResolutionConditionChange[]; warnings: string[]; auditEvents: RulesResolutionAuditEvent[]; cleanup?: Dnd5eSrdConcentrationCleanup } {
  const rules = dnd5eSrdRulesEngineState(data);
  const previous = recordValue(rules.concentration);
  const previousRollId = stringValue(previous.rollId);
  const cleanup = Object.keys(previous).length > 0 ? dnd5eSrdConcentrationCleanupDescriptor(actor.id, previous, "replaced") : undefined;
  const metadata = recordValue(roll.metadata);
  const duration = stringValue(metadata.duration);
  const durationRounds = dnd5eSrdDurationRounds(duration);
  const expiresAtRound = durationRounds && combat ? combat.round + durationRounds : undefined;
  const concentration = {
    rollId: roll.id,
    label: roll.label,
    startedAt: now,
    targetActorIds,
    duration,
    sourceActorId: actor.id,
    ...(combat ? { startedAtRound: combat.round } : {}),
    ...(durationRounds ? { durationRounds } : {}),
    ...(expiresAtRound ? { expiresAtRound } : {})
  };
  rules.concentration = concentration;
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.filter((effect) => recordValue(effect).concentration !== true) : [];
  rules.activeEffects = [
    ...activeEffects,
    {
      id: `${roll.id}:${now}`,
      rollId: roll.id,
      label: roll.label,
      startedAt: now,
      targetActorIds,
      sourceActorId: actor.id,
      concentration: true,
      duration,
      ...(combat ? { startedAtRound: combat.round } : {}),
      ...(durationRounds ? { durationRounds } : {}),
      ...(expiresAtRound ? { expiresAtRound } : {})
    }
  ];
  const replaced = Object.keys(previous).length > 0;
  return {
    data: dnd5eSrdDataWithRulesEngineState(data, rules),
    conditions: [
      {
        actorId: actor.id,
        operation: replaced ? "replaceConcentration" : "startConcentration",
        conditionId: "concentration",
        conditionName: "Concentration",
        reason: replaced ? `Replaced concentration on ${stringValue(previous.label) ?? previousRollId}` : `Started concentration on ${roll.label}`
      }
    ],
    warnings: replaced ? [`Starting ${roll.label} replaces concentration on ${stringValue(previous.label) ?? previousRollId}.`] : [],
    auditEvents: [
      {
        code: replaced ? "concentration.replaced" : "concentration.started",
        actorId: actor.id,
        rollId: roll.id,
        message: replaced ? `${actor.name} replaced concentration with ${roll.label}` : `${actor.name} started concentration on ${roll.label}`,
        data: { previous: previousRollId ? cloneJsonRecord(previous) : undefined, concentration }
      }
    ],
    ...(cleanup ? { cleanup } : {})
  };
}

function dnd5eSrdApplyReactionUse(
  data: Record<string, unknown>,
  actorId: string,
  rollId: string,
  combat: Combat | undefined,
  now: string
): { data: Record<string, unknown>; blocked?: RulesResolutionBlocked; auditEvents: RulesResolutionAuditEvent[] } {
  // Outside initiative there is no persistent reaction interval to consume.
  if (!combat) return { data, auditEvents: [] };
  const rules = dnd5eSrdRulesEngineState(data);
  const combatId = combat.id;
  const round = combat.round;
  const reactions = recordValue(rules.reactions);
  const used = recordValue(reactions[combatId]);
  if (stringValue(used.rollId)) {
    return {
      data,
      blocked: { code: "reaction_already_used", reason: "Reaction already used since the start of this actor's last turn." },
      auditEvents: []
    };
  }
  reactions[combatId] = { round, turnIndex: combat.turnIndex, actorId, rollId, usedAt: now };
  rules.reactions = reactions;
  return {
    data: dnd5eSrdDataWithRulesEngineState(data, rules),
    auditEvents: [
      {
        code: "reaction.used",
        actorId,
        rollId,
        message: "Reaction marked as used for this combat round",
        data: { combatId, round }
      }
    ]
  };
}

function dnd5eSrdApplyBonusActionUse(
  data: Record<string, unknown>,
  actorId: string,
  rollId: string,
  combat: Combat | undefined,
  now: string
): { data: Record<string, unknown>; blocked?: RulesResolutionBlocked; auditEvents: RulesResolutionAuditEvent[] } {
  if (!combat) return { data, auditEvents: [] };
  if (combat.combatants[combat.turnIndex]?.actorId !== actorId) {
    return {
      data,
      blocked: { code: "bonus_action_out_of_turn", reason: "A Bonus Action can be taken only on this actor's turn." },
      auditEvents: []
    };
  }
  const rules = dnd5eSrdRulesEngineState(data);
  const actionEconomy = recordValue(rules.actionEconomy);
  const bonusActions = recordValue(actionEconomy.bonusActions);
  const used = recordValue(bonusActions[combat.id]);
  if (numericValue(used.round, Number.NaN) === combat.round && numericValue(used.turnIndex, Number.NaN) === combat.turnIndex && stringValue(used.rollId)) {
    return {
      data,
      blocked: { code: "bonus_action_already_used", reason: "Bonus Action already used on this turn." },
      auditEvents: []
    };
  }
  bonusActions[combat.id] = { round: combat.round, turnIndex: combat.turnIndex, actorId, rollId, usedAt: now };
  actionEconomy.bonusActions = bonusActions;
  rules.actionEconomy = actionEconomy;
  return {
    data: dnd5eSrdDataWithRulesEngineState(data, rules),
    auditEvents: [{ code: "bonus_action.used", actorId, rollId, message: "Bonus Action used", data: { combatId: combat.id, round: combat.round, turnIndex: combat.turnIndex } }]
  };
}

export interface Dnd5eSrdRechargeProfile {
  kind: "roll" | "uses";
  label: string;
  minimumRoll?: number;
  maximumRoll?: number;
  maxUses?: number;
  recovery?: "short" | "long";
}

/** Parses every recharge form shipped by the SRD catalog. Unknown forms fail closed. */
export function dnd5eSrdRechargeProfile(recharge: string): Dnd5eSrdRechargeProfile | undefined {
  const normalized = recharge.trim().toLowerCase().replace(/\s+/g, " ");
  const range = /^(\d+)\s*-\s*(\d+)$/.exec(normalized);
  if (range) {
    const minimumRoll = Number(range[1]);
    const maximumRoll = Number(range[2]);
    return minimumRoll >= 1 && maximumRoll <= 6 && minimumRoll <= maximumRoll
      ? { kind: "roll", label: recharge, minimumRoll, maximumRoll }
      : undefined;
  }
  const single = /^(\d+)$/.exec(normalized);
  if (single) {
    const minimumRoll = Number(single[1]);
    return minimumRoll >= 1 && minimumRoll <= 6 ? { kind: "roll", label: recharge, minimumRoll, maximumRoll: 6 } : undefined;
  }
  const daily = /^(\d+)\s*\/\s*day$/.exec(normalized);
  if (daily) {
    const maxUses = Number(daily[1]);
    return maxUses > 0 ? { kind: "uses", label: recharge, maxUses, recovery: "long" } : undefined;
  }
  if (["short/long rest", "short or long rest", "short rest"].includes(normalized)) {
    return { kind: "uses", label: recharge, maxUses: 1, recovery: "short" };
  }
  if (normalized === "long rest") return { kind: "uses", label: recharge, maxUses: 1, recovery: "long" };
  return undefined;
}

export function dnd5eSrdRecoverRechargeState(
  data: Record<string, unknown>,
  restType: SystemRestType
): { data: Record<string, unknown>; recoveredActionIds: string[] } {
  const rules = dnd5eSrdRulesEngineState(data);
  const rechargeState = recordValue(rules.recharge);
  const recoveredActionIds: string[] = [];
  const nextState: Record<string, unknown> = { ...rechargeState };
  for (const [rollId, raw] of Object.entries(rechargeState)) {
    const current = recordValue(raw);
    const recharge = stringValue(current.recharge);
    const profile = recharge ? dnd5eSrdRechargeProfile(recharge) : undefined;
    if (!profile || profile.kind !== "uses" || !profile.recovery) continue;
    const recovers = profile.recovery === "short" || restType === "long";
    if (!recovers) continue;
    const maxUses = profile.maxUses ?? 1;
    if (numericValue(current.remaining, maxUses) >= maxUses && current.available !== false) continue;
    nextState[rollId] = { ...current, available: true, remaining: maxUses, recoveredBy: restType };
    recoveredActionIds.push(rollId);
  }
  if (recoveredActionIds.length === 0) return { data, recoveredActionIds };
  return {
    data: dnd5eSrdDataWithRulesEngineState(data, { ...rules, recharge: nextState }),
    recoveredActionIds: recoveredActionIds.sort()
  };
}

function dnd5eSrdApplyRechargeResolution(
  data: Record<string, unknown>,
  roll: QuickRoll,
  recharge: string,
  options: RulesResolverOptions,
  now: string
): { data: Record<string, unknown>; blocked?: RulesResolutionBlocked; warnings: string[]; auditEvents: RulesResolutionAuditEvent[] } {
  const rules = dnd5eSrdRulesEngineState(data);
  const rechargeState = recordValue(rules.recharge);
  const current = recordValue(rechargeState[roll.id]);
  const profile = dnd5eSrdRechargeProfile(recharge);
  const warnings: string[] = [];
  const auditEvents: RulesResolutionAuditEvent[] = [];
  if (!profile) {
    return {
      data,
      blocked: { code: "recharge_unsupported", reason: `${roll.label} uses an unsupported recharge form (${recharge}); resolve it manually.`, supportStatus: "unsupported" },
      warnings,
      auditEvents
    };
  }
  let remaining = profile.kind === "uses" ? Math.max(0, Math.min(profile.maxUses ?? 1, Math.floor(numericValue(current.remaining, profile.maxUses ?? 1)))) : undefined;
  let available = profile.kind === "uses" ? (remaining ?? 0) > 0 : current.available !== false;
  if (profile.kind === "roll" && Number.isFinite(numericValue(options.rechargeCheck, Number.NaN))) {
    const check = Math.floor(numericValue(options.rechargeCheck, 0));
    if (check < 1 || check > 6) {
      return { data, blocked: { code: "recharge_check_invalid", reason: "Recharge checks must be whole-number d6 results from 1 to 6." }, warnings, auditEvents };
    }
    available = check >= (profile.minimumRoll ?? 7) && check <= (profile.maximumRoll ?? 6);
    rechargeState[roll.id] = { ...current, recharge, available, lastCheck: check, checkedAt: now };
    auditEvents.push({
      code: available ? "recharge.available" : "recharge.unavailable",
      actorId: "",
      rollId: roll.id,
      message: `${roll.label} recharge check ${check} ${available ? "succeeded" : "failed"}`,
      data: { recharge, check }
    });
  }
  if (!available) {
    return {
      data: dnd5eSrdDataWithRulesEngineState(data, { ...rules, recharge: rechargeState }),
      blocked: { code: "recharge_unavailable", reason: `${roll.label} is not recharged (${recharge}).` },
      warnings,
      auditEvents
    };
  }
  if (profile.kind === "uses") {
    remaining = Math.max(0, (remaining ?? profile.maxUses ?? 1) - 1);
    rechargeState[roll.id] = { ...current, recharge, remaining, maxUses: profile.maxUses, available: remaining > 0, spentAt: now };
  } else {
    rechargeState[roll.id] = { ...current, recharge, available: false, spentAt: now };
  }
  rules.recharge = rechargeState;
  if (profile.kind === "roll" || remaining === 0) warnings.push(`${roll.label} will need recharge ${recharge} before it can be used again.`);
  return { data: dnd5eSrdDataWithRulesEngineState(data, rules), warnings, auditEvents };
}

function dnd5eSrdPendingReaction(actor: Actor, roll: QuickRoll, metadata: Record<string, unknown>): RulesResolutionPendingReaction | undefined {
  const reaction = stringValue(metadata.reaction) ?? (roll.id.includes("hellish-rebuke") ? "Hellish Rebuke reaction trigger" : undefined);
  if (!reaction) return undefined;
  return { actorId: actor.id, actionRollId: roll.id, reason: reaction };
}

function dnd5eSrdPendingChoice(metadata: Record<string, unknown>, options: RulesResolverOptions): RulesResolutionChoice | undefined {
  const found = dnd5eSrdChoiceGroups(metadata).find((choice) => choice.options.length > 0);
  if (!found) return undefined;
  const selected = dnd5eSrdResolvedChoice(metadata, options);
  if (selected?.kind === found.kind) return undefined;
  return { kind: found.kind, options: found.options, reason: "Choose one option before this action can be fully automated." };
}

function dnd5eSrdChoiceGroups(metadata: Record<string, unknown>): Array<{ kind: RulesResolutionChoice["kind"]; options: string[] }> {
  const damageTypeOptions = uniqueStrings([
    ...dnd5eSrdChoiceOptions(metadata.damageTypeOptions),
    ...(stringValue(metadata.damageType)?.toLowerCase() === "choice" ? dnd5eSrdChoiceOptions(metadata.damageTypes) : []),
    ...dnd5eSrdChoiceOptions(metadata.damageTypeChoices)
  ]);
  return [
    { kind: "effect", options: dnd5eSrdChoiceOptions(metadata.effectOptions) },
    { kind: "damageType", options: damageTypeOptions },
    { kind: "resistance", options: uniqueStrings([...dnd5eSrdChoiceOptions(metadata.resistanceChoice), ...dnd5eSrdChoiceOptions(metadata.resistanceChoices)]) }
  ];
}

function dnd5eSrdChoiceOptions(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return uniqueStrings(value.map(dnd5eSrdChoiceOptionLabel).filter((option): option is string => Boolean(option)));
}

function dnd5eSrdChoiceOptionLabel(value: unknown): string | undefined {
  if (typeof value === "string" && value.trim()) return value.trim();
  const record = recordValue(value);
  return stringValue(record.name) ?? stringValue(record.label) ?? stringValue(record.id) ?? stringValue(record.condition);
}

function dnd5eSrdResolvedChoice(metadata: Record<string, unknown>, options: RulesResolverOptions): { kind: RulesResolutionChoice["kind"]; value: string; options: string[] } | undefined {
  const selected = stringValue(options.effectChoice);
  if (!selected) return undefined;
  const normalizedSelected = selected.toLowerCase();
  for (const choice of dnd5eSrdChoiceGroups(metadata)) {
    const matched = choice.options.find((option) => option.toLowerCase() === normalizedSelected);
    if (matched) return { kind: choice.kind, value: matched, options: choice.options };
  }
  return undefined;
}

function dnd5eSrdSelectedEffectOption(metadata: Record<string, unknown>, options: RulesResolverOptions): Record<string, unknown> | undefined {
  const selected = dnd5eSrdResolvedChoice(metadata, options);
  if (selected?.kind !== "effect" || !Array.isArray(metadata.effectOptions)) return undefined;
  return metadata.effectOptions.map(recordValue).find((option) => dnd5eSrdChoiceOptionLabel(option)?.toLowerCase() === selected.value.toLowerCase());
}

function dnd5eSrdManualResolution(roll: QuickRoll, metadata: Record<string, unknown>, pendingChoice: RulesResolutionChoice | undefined, options: RulesResolverOptions): RulesActionResolutionResult["manualResolutionRequired"] | undefined {
  if (pendingChoice) return { reason: pendingChoice.reason, metadata, supportStatus: "manual" };
  if (metadata.requiresManualResolution === true) {
    return { reason: `${roll.label} has a selected SRD benefit that still needs GM/manual resolution.`, metadata, supportStatus: "manual" };
  }
  const damageTypes = dnd5eSrdRollEffectType(roll) === "damage"
    ? uniqueStrings([...dnd5eSrdDamageBreakdownTypes(metadata), ...dnd5eSrdDamageTypes(metadata, options)])
    : [];
  const unsupportedDamageTypes = damageTypes.filter((damageType) => !DND_5E_SRD_DAMAGE_TYPE_IDS.some((supported) => supported === damageType.toLowerCase()));
  if (unsupportedDamageTypes.length > 0) {
    return { reason: `${roll.label} uses unsupported damage type${unsupportedDamageTypes.length === 1 ? "" : "s"} ${unsupportedDamageTypes.join(", ")}; resolve it manually.`, metadata, supportStatus: "unsupported" };
  }
  if (damageTypes.length > 1) {
    const resolvedComponents = dnd5eSrdDamageBreakdownComponents(metadata);
    if (resolvedComponents.length !== damageTypes.length) return { reason: `${roll.label} has multiple typed damage components without an authoritative total for each component.`, metadata, supportStatus: "manual" };
  }
  const complexKeys = ["summon", "behaviorTable", "commandOptions", "spellcastingAbilityCheck", "blockedBy", "counteredBy", "rayRollFormula"];
  const hasComplexMetadata = complexKeys.some((key) => key in metadata);
  const effectType = stringValue(metadata.effectType);
  if (effectType === "utility" && dnd5eSrdUtilityTraits(metadata, options).hasTraits) return undefined;
  if (hasComplexMetadata || (roll.formula === "0" && effectType === "utility" && Object.keys(metadata).length > 0)) {
    return { reason: `${roll.label} has SRD metadata but still needs GM/manual resolution.`, metadata, supportStatus: "manual" };
  }
  return undefined;
}

function dnd5eSrdApplyTargetEffectResolution(
  target: Actor,
  targetItems: Item[],
  sourceActorId: string,
  roll: QuickRoll,
  metadata: Record<string, unknown>,
  rollTotal: number | undefined,
  saveOutcome: RulesSaveOutcome | undefined,
  options: RulesResolverOptions,
  combat: Combat | undefined,
  now: string
): { data: Record<string, unknown>; effects: RulesResolutionEffectResult[]; conditions: RulesResolutionConditionChange[]; pendingSaves: RulesResolutionPendingSave[]; auditEvents: RulesResolutionAuditEvent[]; concentrationCleanups: Dnd5eSrdConcentrationCleanup[] } | undefined {
  let data = cloneJsonRecord(target.data);
  const effects: RulesResolutionEffectResult[] = [];
  const conditions: RulesResolutionConditionChange[] = [];
  const pendingSaves: RulesResolutionPendingSave[] = [];
  const auditEvents: RulesResolutionAuditEvent[] = [];
  const concentrationCleanups: Dnd5eSrdConcentrationCleanup[] = [];

  const poolEffect = dnd5eSrdApplyRollTotalEffectResolution({ ...target, data }, targetItems, roll, metadata, rollTotal, saveOutcome, options, now);
  if (poolEffect) {
    data = poolEffect.data;
    effects.push(poolEffect.effect);
    if (poolEffect.condition) conditions.push(poolEffect.condition);
    if (poolEffect.pendingSave) pendingSaves.push(poolEffect.pendingSave);
    if (poolEffect.auditEvent) auditEvents.push(poolEffect.auditEvent);
    if (poolEffect.cleanup) concentrationCleanups.push(poolEffect.cleanup);
  }

  const conditionBefore = dnd5eSrdConditionIds(data.conditions);
  const conditionResult = dnd5eSrdApplyTargetConditionResolution({ ...target, data }, targetItems, sourceActorId, roll, metadata, saveOutcome, options, combat, now);
  if (conditionResult) {
    data = conditionResult.data;
    const conditionAfter = dnd5eSrdConditionIds(data.conditions);
    const resolvedChoice = dnd5eSrdResolvedChoice(metadata, options);
    for (const condition of conditionResult.conditions) {
      if (condition.operation !== "apply" || !condition.conditionId || !condition.conditionName) continue;
      effects.push({
        type: "condition",
        targetActorId: target.id,
        targetActorName: target.name,
        conditionId: condition.conditionId,
        conditionName: condition.conditionName,
        before: conditionBefore,
        after: conditionAfter,
        alreadyPresent: conditionBefore.includes(condition.conditionId),
        ...(resolvedChoice ? { effectChoice: resolvedChoice.value, choiceKind: resolvedChoice.kind } : {})
      });
    }
    conditions.push(...conditionResult.conditions);
    pendingSaves.push(...conditionResult.pendingSaves);
    auditEvents.push(...conditionResult.auditEvents);
  }

  const utilityResult = dnd5eSrdApplyUtilityEffectResolution({ ...target, data }, sourceActorId, roll, metadata, options, now);
  if (utilityResult) {
    data = utilityResult.data;
    effects.push(utilityResult.effect);
    auditEvents.push(utilityResult.auditEvent);
  }

  if (effects.length === 0 && conditions.length === 0 && pendingSaves.length === 0 && auditEvents.length === 0) return undefined;
  return { data, effects, conditions, pendingSaves, auditEvents, concentrationCleanups };
}

function dnd5eSrdUtilityTraits(metadata: Record<string, unknown>, options: RulesResolverOptions): { resistance: string[]; immunity: string[]; vulnerability: string[]; hasTraits: boolean } {
  const selected = dnd5eSrdResolvedChoice(metadata, options);
  const selectedEffectOption = dnd5eSrdSelectedEffectOption(metadata, options);
  const traitSource = selected?.kind === "effect" && Array.isArray(metadata.effectOptions) ? selectedEffectOption ?? {} : metadata;
  const resistance = uniqueStrings([
    ...normalizeStringArray(traitSource.resistance).map((value) => value.toLowerCase()),
    ...(selected?.kind === "resistance" ? [selected.value.toLowerCase()] : [])
  ]);
  const immunity = uniqueStrings([...normalizeStringArray(traitSource.immunity), ...normalizeStringArray(traitSource.immunities)].map((value) => value.toLowerCase()));
  const vulnerability = uniqueStrings([...normalizeStringArray(traitSource.vulnerability), ...normalizeStringArray(traitSource.vulnerabilities)].map((value) => value.toLowerCase()));
  return { resistance, immunity, vulnerability, hasTraits: resistance.length > 0 || immunity.length > 0 || vulnerability.length > 0 };
}

function dnd5eSrdApplyUtilityEffectResolution(
  target: Actor,
  sourceActorId: string,
  roll: QuickRoll,
  metadata: Record<string, unknown>,
  options: RulesResolverOptions,
  now: string
): { data: Record<string, unknown>; effect: RulesResolutionEffectResult; auditEvent: RulesResolutionAuditEvent } | undefined {
  const traits = dnd5eSrdUtilityTraits(metadata, options);
  if (!traits.hasTraits) return undefined;
  const resolvedChoice = dnd5eSrdResolvedChoice(metadata, options);
  const duration = stringValue(metadata.duration);
  const rules = dnd5eSrdRulesEngineState(target.data);
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.map((effect) => cloneJsonRecord(recordValue(effect))) : [];
  const nextEffect = {
    id: `${roll.id}:${target.id}:${now}`,
    rollId: roll.id,
    label: roll.label,
    sourceActorId,
    targetActorId: target.id,
    startedAt: now,
    ...(metadata.concentration === true ? { concentration: true } : {}),
    ...(duration ? { duration } : {}),
    ...(traits.resistance.length > 0 ? { resistance: traits.resistance } : {}),
    ...(traits.immunity.length > 0 ? { immunity: traits.immunity } : {}),
    ...(traits.vulnerability.length > 0 ? { vulnerability: traits.vulnerability } : {}),
    ...(resolvedChoice ? { effectChoice: resolvedChoice.value, choiceKind: resolvedChoice.kind } : {})
  };
  rules.activeEffects = [...activeEffects.filter((effect) => stringValue(effect.id) !== nextEffect.id), nextEffect];
  return {
    data: dnd5eSrdDataWithRulesEngineState(target.data, rules),
    effect: {
      type: "utility",
      targetActorId: target.id,
      targetActorName: target.name,
      ...(duration ? { duration } : {}),
      ...(traits.resistance.length > 0 ? { resistance: traits.resistance } : {}),
      ...(traits.immunity.length > 0 ? { immunity: traits.immunity } : {}),
      ...(traits.vulnerability.length > 0 ? { vulnerability: traits.vulnerability } : {}),
      ...(resolvedChoice ? { effectChoice: resolvedChoice.value, choiceKind: resolvedChoice.kind } : {})
    },
    auditEvent: {
      code: "utility.applied",
      actorId: sourceActorId,
      targetActorId: target.id,
      rollId: roll.id,
      message: `${roll.label} applied utility traits to ${target.name}`,
      data: nextEffect
    }
  };
}


function dnd5eSrdDamageDefenseValues(data: Record<string, unknown>, keys: string[]): string[] {
  return uniqueStrings(keys.flatMap((key) => {
    const value = data[key];
    if (typeof value === "string") return dnd5eSrdSplitDamageTypes(value);
    return normalizeStringArray(value).flatMap(dnd5eSrdSplitDamageTypes);
  }).map((value) => value.toLowerCase()));
}

function dnd5eSrdMonsterTraitDamageDefenses(actor: Actor): { resistance: string[]; immunity: string[]; vulnerability: string[] } {
  const statBlock = recordValue(recordValue(actor.data.monster).statBlock);
  const traits = Array.isArray(statBlock.traits) ? statBlock.traits.map((trait) => recordValue(trait)) : [];
  const result = { resistance: [] as string[], immunity: [] as string[], vulnerability: [] as string[] };
  for (const trait of traits) {
    const text = `${stringValue(trait.name) ?? ""}. ${stringValue(trait.summary) ?? ""}`.toLowerCase();
    for (const damageType of DND_5E_SRD_DAMAGE_TYPE_IDS) {
      const escapedType = damageType.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
      if (new RegExp(`(?:${escapedType} immunity|immune to [^.]*\\b${escapedType}\\b[^.]* damage)`).test(text)) result.immunity.push(damageType);
      if (new RegExp(`(?:${escapedType} resistance|resistant to [^.]*\\b${escapedType}\\b[^.]* damage)`).test(text)) result.resistance.push(damageType);
      if (new RegExp(`(?:${escapedType} vulnerability|vulnerable to [^.]*\\b${escapedType}\\b[^.]* damage)`).test(text)) result.vulnerability.push(damageType);
    }
  }
  return {
    resistance: uniqueStrings(result.resistance),
    immunity: uniqueStrings(result.immunity),
    vulnerability: uniqueStrings(result.vulnerability)
  };
}

function dnd5eSrdActorDamageDefenses(actor: Actor, items: Item[] = []): { resistance: string[]; immunity: string[]; vulnerability: string[] } {
  const rules = dnd5eSrdRulesEngineState(actor.data);
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.map((effect) => recordValue(effect)) : [];
  const activeItems = items
    .filter((item) => itemBelongsToActor(actor, item))
    .filter((item) => itemQuantity(recordValue(item.data)) > 0)
    .filter((item) => recordValue(item.data).equipped !== false)
    .filter((item) => dnd5eSrdItemModifiersAreActive(actor, item))
    .map((item) => recordValue(item.data));
  const monster = dnd5eSrdMonsterTraitDamageDefenses(actor);
  return {
    resistance: uniqueStrings([
      ...dnd5eSrdDamageDefenseValues(actor.data, ["resistance", "resistances", "damageResistance", "damageResistances"]),
      ...activeEffects.flatMap((effect) => dnd5eSrdDamageDefenseValues(effect, ["resistance", "resistances"])),
      ...activeItems.flatMap((item) => dnd5eSrdDamageDefenseValues(item, ["resistance", "resistances", "damageResistance", "damageResistances"])),
      ...monster.resistance
    ]),
    immunity: uniqueStrings([
      ...dnd5eSrdDamageDefenseValues(actor.data, ["immunity", "immunities", "damageImmunity", "damageImmunities"]),
      ...activeEffects.flatMap((effect) => dnd5eSrdDamageDefenseValues(effect, ["immunity", "immunities"])),
      ...activeItems.flatMap((item) => dnd5eSrdDamageDefenseValues(item, ["immunity", "immunities", "damageImmunity", "damageImmunities"])),
      ...monster.immunity
    ]),
    vulnerability: uniqueStrings([
      ...dnd5eSrdDamageDefenseValues(actor.data, ["vulnerability", "vulnerabilities", "damageVulnerability", "damageVulnerabilities"]),
      ...activeEffects.flatMap((effect) => dnd5eSrdDamageDefenseValues(effect, ["vulnerability", "vulnerabilities"])),
      ...activeItems.flatMap((item) => dnd5eSrdDamageDefenseValues(item, ["vulnerability", "vulnerabilities", "damageVulnerability", "damageVulnerabilities"])),
      ...monster.vulnerability
    ])
  };
}

function dnd5eSrdAdjustedTypedDamage(actor: Actor, items: Item[], amount: number, damageTypes: string[]): { amount: number; resistance: string[]; immunity: string[]; vulnerability: string[] } {
  const result = { amount, resistance: [] as string[], immunity: [] as string[], vulnerability: [] as string[] };
  // A single combined total with multiple damage types cannot be partitioned
  // safely. Keep it unmodified so the existing GM/manual path remains usable.
  if (damageTypes.length !== 1) return result;
  const damageType = damageTypes[0]!.toLowerCase();
  const defenses = dnd5eSrdActorDamageDefenses(actor, items);
  if (defenses.immunity.includes(damageType)) {
    result.immunity = [damageType];
    result.amount = 0;
    return result;
  }
  if (defenses.resistance.includes(damageType)) {
    result.resistance = [damageType];
    result.amount = Math.floor(result.amount / 2);
  }
  if (defenses.vulnerability.includes(damageType)) {
    result.vulnerability = [damageType];
    result.amount *= 2;
  }
  return result;
}

function dnd5eSrdTemporaryHitPoints(data: Record<string, unknown>): { key: "temporaryHitPoints" | "temporaryHp" | "tempHp"; current: number; record?: Record<string, unknown> } {
  for (const key of ["temporaryHitPoints", "temporaryHp", "tempHp"] as const) {
    if (!(key in data)) continue;
    const value = data[key];
    const record = recordValue(value);
    const current = typeof value === "number" ? value : numericValue(record.current, 0);
    return { key, current: Math.max(0, Math.floor(current)), ...(typeof value === "object" && value !== null ? { record } : {}) };
  }
  return { key: "temporaryHitPoints", current: 0 };
}

export function dnd5eSrdResolveDamageComponents(
  actor: Actor,
  items: Item[],
  components: readonly Dnd5eSrdDamageComponent[],
  options: { criticalHit?: boolean } = {}
): Dnd5eSrdDamageResolution {
  const hp = recordValue(actor.data.hp);
  const current = numericValue(hp.current, Number.NaN);
  const max = numericValue(hp.max, Number.NaN);
  if (!Number.isFinite(current) || !Number.isFinite(max)) throw new Error("Damage resolution requires finite current and maximum Hit Points");
  const temporaryHitPoints = dnd5eSrdTemporaryHitPoints(actor.data);
  const defenses = dnd5eSrdActorDamageDefenses(actor, items);
  const deathSaves = recordValue(actor.data.deathSaves);
  return resolveDnd5eSrdDamageComponents({
    actor,
    hitPoints: { current, max },
    temporaryHitPoints: temporaryHitPoints.current,
    components,
    defenses,
    deathSaves: { successes: numericValue(deathSaves.successes, 0), failures: numericValue(deathSaves.failures, 0) },
    criticalHit: options.criticalHit
  });
}

function dnd5eSrdApplyRollTotalEffectResolution(
  target: Actor,
  targetItems: Item[],
  roll: QuickRoll,
  metadata: Record<string, unknown>,
  rollTotal: number | undefined,
  saveOutcome: RulesSaveOutcome | undefined,
  options: RulesResolverOptions,
  now: string
): { data: Record<string, unknown>; effect: RulesResolutionEffectResult; pendingSave?: RulesResolutionPendingSave; condition?: RulesResolutionConditionChange; auditEvent?: RulesResolutionAuditEvent; cleanup?: Dnd5eSrdConcentrationCleanup } | undefined {
  const type = dnd5eSrdRollEffectType(roll);
  if (!type || !Number.isFinite(numericValue(rollTotal, Number.NaN))) return undefined;
  const damageTypes = type === "damage" ? uniqueStrings([...dnd5eSrdDamageBreakdownTypes(metadata), ...dnd5eSrdDamageTypes(metadata, options)]) : [];
  if (damageTypes.some((damageType) => !DND_5E_SRD_DAMAGE_TYPE_IDS.some((supported) => supported === damageType.toLowerCase()))) return undefined;
  const damageComponents = type === "damage" ? dnd5eSrdDamageBreakdownComponents(metadata) : [];
  if (damageTypes.length > 1 && damageComponents.length !== damageTypes.length) return undefined;
  const saveAbility = stringValue(recordValue(metadata.save).ability);
  if (saveAbility && !saveOutcome) return undefined;
  const adjustedTotal = dnd5eSrdRollEffectTotalForSave(type, metadata, numericValue(rollTotal, 0), saveOutcome);
  if (adjustedTotal === undefined) return undefined;
  const temporaryHitPointHealing = type === "healing" && (
    stringValue(metadata.healing)?.toLowerCase() === "temporaryhitpoints" ||
    metadata.temporaryHitPoints !== undefined ||
    metadata.temporaryHitPointsFormula !== undefined
  );
  if (temporaryHitPointHealing) {
    const temporaryHitPoints = dnd5eSrdTemporaryHitPoints(target.data);
    const amount = Math.max(0, Math.floor(adjustedTotal));
    const after = Math.max(temporaryHitPoints.current, amount);
    const data = {
      ...target.data,
      [temporaryHitPoints.key]: temporaryHitPoints.record ? { ...temporaryHitPoints.record, current: after } : after
    };
    return {
      data,
      effect: {
        type: "healing",
        targetActorId: target.id,
        targetActorName: target.name,
        pool: temporaryHitPoints.key,
        amount,
        before: temporaryHitPoints.current,
        after,
        max: after
      }
    };
  }
  const pool = dnd5eSrdEffectPool(target);
  if (!pool) return undefined;
  const poolValue = recordValue(target.data[pool]);
  const current = numericValue(poolValue.current, Number.NaN);
  const max = numericValue(poolValue.max, Number.NaN);
  if (!Number.isFinite(current) || !Number.isFinite(max)) return undefined;
  const damageResolution = type === "damage"
    ? dnd5eSrdResolveDamageComponents(
        target,
        targetItems,
        damageComponents.length > 0
          ? damageComponents.map((component) => ({ ...component, amount: dnd5eSrdRollEffectTotalForSave("damage", metadata, component.amount, saveOutcome) ?? 0 }))
          : [{ amount: Math.max(0, Math.floor(adjustedTotal)), damageType: damageTypes[0] ?? "untyped" }],
        { criticalHit: options.criticalHit === true || metadata.criticalHit === true }
      )
    : undefined;
  const typedDamage = damageResolution
    ? {
        amount: damageResolution.totalDamage,
        resistance: damageResolution.components.filter((component) => component.defense === "resistance" || component.defense === "resistance-and-vulnerability").map((component) => component.damageType),
        immunity: damageResolution.components.filter((component) => component.defense === "immunity").map((component) => component.damageType),
        vulnerability: damageResolution.components.filter((component) => component.defense === "vulnerability" || component.defense === "resistance-and-vulnerability").map((component) => component.damageType)
      }
    : { amount: Math.max(0, Math.floor(adjustedTotal)), resistance: [] as string[], immunity: [] as string[], vulnerability: [] as string[] };
  const amount = typedDamage.amount;
  const temporaryHitPoints = dnd5eSrdTemporaryHitPoints(target.data);
  const absorbedByTemporaryHitPoints = damageResolution?.absorbedByTemporaryHitPoints ?? 0;
  const after = type === "healing" ? Math.min(max, current + amount) : damageResolution?.hitPointsAfter ?? current;
  let data: Record<string, unknown> = {
    ...target.data,
    [pool]: {
      ...poolValue,
      current: after
    }
  };
  if (type === "damage" && damageResolution && temporaryHitPoints.current !== damageResolution.temporaryHitPointsAfter) {
    const remaining = damageResolution.temporaryHitPointsAfter;
    data = {
      ...data,
      [temporaryHitPoints.key]: temporaryHitPoints.record ? { ...temporaryHitPoints.record, current: remaining } : remaining
    };
  }
  let pendingSave: RulesResolutionPendingSave | undefined;
  let condition: RulesResolutionConditionChange | undefined;
  let auditEvent: RulesResolutionAuditEvent | undefined;
  let cleanup: Dnd5eSrdConcentrationCleanup | undefined;
  if (type === "damage" && damageResolution && damageResolution.totalDamage > 0) {
    const transient = new Set(["unconscious", "stable", "dead"]);
    const nextConditions = normalizeConditionRecords(data.conditions).filter((entry) => !transient.has(entry.id));
    for (const conditionId of damageResolution.lifecycle.conditionIds) nextConditions.push({ id: conditionId, appliedAt: now });
    data = {
      ...data,
      conditions: nextConditions,
      deathSaves: {
        successes: damageResolution.lifecycle.deathSaveSuccesses,
        failures: damageResolution.lifecycle.deathSaveFailures
      },
      lifeState: damageResolution.lifecycle.state,
      ...(damageResolution.lifecycle.state === "defeated" || damageResolution.lifecycle.state === "dead" ? { defeated: true } : {})
    };
    const conditionId = damageResolution.lifecycle.conditionIds[0];
    if (conditionId) {
      condition = {
        actorId: target.id,
        operation: "apply",
        conditionId,
        conditionName: titleCaseWords(conditionId),
        reason: damageResolution.lifecycle.massiveDamage ? "Massive damage caused instant death" : `Damage reduced ${target.name} to 0 Hit Points`
      };
    }
  } else if (type === "healing" && current === 0 && after > 0) {
    const transient = new Set(["unconscious", "stable"]);
    data = {
      ...data,
      conditions: normalizeConditionRecords(data.conditions).filter((entry) => !transient.has(entry.id)),
      deathSaves: { successes: 0, failures: 0 },
      lifeState: "conscious",
      defeated: false
    };
  }
  if (type === "damage" && amount > 0) {
    const concentration = resolveDnd5eSrdConcentrationDamage({ ...target, data }, amount, options.saveOutcomes?.[`${target.id}:concentration`], now, roll.id);
    data = concentration.data;
    pendingSave = concentration.pendingSave;
    condition = concentration.condition ?? condition;
    auditEvent = concentration.auditEvent;
    cleanup = concentration.cleanup;
  }
  const resolvedChoice = dnd5eSrdResolvedChoice(metadata, options);
  return {
    data,
    effect: {
      type,
      targetActorId: target.id,
      targetActorName: target.name,
      pool,
      amount,
      before: current,
      after,
      max,
      ...(damageTypes.length === 1 ? { damageType: damageTypes[0] } : {}),
      ...(damageTypes.length > 1 ? { damageTypes } : {}),
      ...(typedDamage.resistance.length > 0 ? { resistance: typedDamage.resistance } : {}),
      ...(typedDamage.immunity.length > 0 ? { immunity: typedDamage.immunity } : {}),
      ...(typedDamage.vulnerability.length > 0 ? { vulnerability: typedDamage.vulnerability } : {}),
      ...(resolvedChoice ? { effectChoice: resolvedChoice.value, choiceKind: resolvedChoice.kind } : {})
    },
    ...(pendingSave ? { pendingSave } : {}),
    ...(condition ? { condition } : {}),
    ...(auditEvent ? { auditEvent } : {}),
    ...(cleanup ? { cleanup } : {})
  };
}

function dnd5eSrdRollEffectType(roll: QuickRoll): "damage" | "healing" | undefined {
  const id = roll.id.toLowerCase();
  const label = roll.label.toLowerCase();
  if (id.endsWith("-healing") || /\bhealing\b/.test(label)) return "healing";
  if (id.endsWith("-damage") || /\bdamage\b/.test(label)) return "damage";
  return undefined;
}

function dnd5eSrdRollEffectTotalForSave(type: "damage" | "healing", metadata: Record<string, unknown>, total: number, saveOutcome?: RulesSaveOutcome): number | undefined {
  if (saveOutcome !== "success") return total;
  const success = stringValue(recordValue(metadata.save).success)?.toLowerCase() ?? "";
  if (success.includes("half")) return Math.floor(total / 2);
  if (type === "damage") return 0;
  return undefined;
}

function dnd5eSrdDamageTypes(metadata: Record<string, unknown>, options: RulesResolverOptions): string[] {
  const selected = dnd5eSrdResolvedChoice(metadata, options);
  if (selected?.kind === "damageType") return [selected.value.toLowerCase()];
  const damageType = stringValue(metadata.damageType);
  if (damageType && damageType.toLowerCase() !== "choice") return dnd5eSrdSplitDamageTypes(damageType);
  const singleOption = dnd5eSrdChoiceOptions(metadata.damageTypes);
  return singleOption.length === 1 ? [singleOption[0]!.toLowerCase()] : [];
}

function dnd5eSrdDamageBreakdownTypes(metadata: Record<string, unknown>): string[] {
  return Object.keys(recordValue(metadata.damageBreakdown)).map((damageType) => damageType.toLowerCase());
}

function dnd5eSrdDamageBreakdownComponents(metadata: Record<string, unknown>): Dnd5eSrdDamageComponent[] {
  return Object.entries(recordValue(metadata.damageBreakdown)).flatMap(([damageType, rawAmount]) => {
    const amount = numericValue(rawAmount, Number.NaN);
    return Number.isInteger(amount) && amount >= 0 ? [{ damageType: damageType.toLowerCase(), amount }] : [];
  });
}

function dnd5eSrdSplitDamageTypes(value: string): string[] {
  return uniqueStrings(
    value
      .split(/[\/,]/)
      .map((item) => item.trim().toLowerCase())
      .filter(Boolean)
  );
}

function dnd5eSrdEffectPool(actor: Actor): "hp" | undefined {
  const hp = recordValue(actor.data.hp);
  return Number.isFinite(numericValue(hp.current, Number.NaN)) && Number.isFinite(numericValue(hp.max, Number.NaN)) ? "hp" : undefined;
}

function dnd5eSrdConditionIds(value: unknown): string[] {
  return normalizeConditionRecords(value).map((condition) => condition.id);
}

function dnd5eSrdApplyTargetConditionResolution(
  target: Actor,
  targetItems: Item[],
  sourceActorId: string,
  roll: QuickRoll,
  metadata: Record<string, unknown>,
  saveOutcome: RulesSaveOutcome | undefined,
  options: RulesResolverOptions,
  combat: Combat | undefined,
  now: string
): { data: Record<string, unknown>; conditions: RulesResolutionConditionChange[]; pendingSaves: RulesResolutionPendingSave[]; auditEvents: RulesResolutionAuditEvent[] } | undefined {
  const conditionNames = dnd5eSrdConditionNamesFromMetadata(metadata, options);
  if (conditionNames.length === 0) return undefined;
  const save = recordValue(metadata.save);
  const saveAbility = stringValue(save.ability) ?? stringValue(metadata.repeatSaveAbility);
  const saveDc = Number.isFinite(numericValue(save.dc, Number.NaN)) ? numericValue(save.dc, Number.NaN) : undefined;
  if (saveAbility && saveOutcome !== "failure") return undefined;
  const requestedConditionIds = conditionNames.map(dnd5eSrdConditionId);
  const immunities = new Set(dnd5eSrdConditionImmunities(target, targetItems));
  const conditionIds = requestedConditionIds.filter((conditionId) => !immunities.has(conditionId));
  const appliedConditionNames = conditionNames.filter((_conditionName, index) => conditionIds.includes(requestedConditionIds[index]!));
  const immunityAuditEvents: RulesResolutionAuditEvent[] = requestedConditionIds.flatMap((conditionId, index) => immunities.has(conditionId) ? [{
    code: "condition.immune",
    actorId: sourceActorId,
    targetActorId: target.id,
    rollId: roll.id,
    message: `${target.name} is immune to ${conditionNames[index] ?? titleCaseWords(conditionId)}`,
    data: { conditionId }
  }] : []);
  if (conditionIds.length === 0) return { data: target.data, conditions: [], pendingSaves: [], auditEvents: immunityAuditEvents };
  const duration = stringValue(metadata.conditionDuration) ?? stringValue(metadata.duration);
  const durationRounds = dnd5eSrdDurationRounds(duration);
  const repeatSave = dnd5eSrdRepeatSaveTiming(metadata);
  const expiresAtRound = durationRounds && combat ? combat.round + durationRounds : undefined;
  const resolvedChoice = dnd5eSrdResolvedChoice(metadata, options);
  const rules = dnd5eSrdRulesEngineState(target.data);
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.map((effect) => cloneJsonRecord(recordValue(effect))) : [];
  const existingConditionIds = dnd5eSrdConditionIds(target.data.conditions);
  const ownedConditionIds = conditionIds.filter((conditionId) => !existingConditionIds.includes(conditionId));
  const nextEffect = {
    id: `${roll.id}:${target.id}:${now}`,
    rollId: roll.id,
    label: roll.label,
    sourceActorId,
    targetActorId: target.id,
    conditionIds,
    conditionNames: appliedConditionNames,
    ownedConditionIds,
    startedAt: now,
    ...(metadata.concentration === true ? { concentration: true } : {}),
    ...(duration ? { duration } : {}),
    ...(durationRounds ? { durationRounds } : {}),
    ...(expiresAtRound ? { expiresAtRound } : {}),
    ...(repeatSave ? { repeatSave } : {}),
    ...(saveAbility ? { saveAbility } : {}),
    ...(saveDc !== undefined ? { saveDc } : {}),
    ...(resolvedChoice ? { effectChoice: resolvedChoice.value, choiceKind: resolvedChoice.kind } : {})
  };
  rules.activeEffects = [...activeEffects.filter((effect) => stringValue(effect.id) !== nextEffect.id), nextEffect];
  let data = dnd5eSrdDataWithRulesEngineState(target.data, rules);
  for (const conditionId of conditionIds) {
    data = applyDnd5eSrdCondition({ ...target, data }, conditionId, now);
  }
  const pendingSaves: RulesResolutionPendingSave[] = repeatSave && saveAbility
    ? [
        {
          actorId: target.id,
          ability: saveAbility,
          ...(saveDc !== undefined ? { dc: saveDc } : {}),
          reason: `${roll.label} grants a repeat save (${repeatSave})`,
          success: "ends effect",
          recurring: true,
          timing: repeatSave,
          conditionIds
        }
      ]
    : [];
  const reasonParts = [duration ? `duration ${duration}` : undefined, repeatSave ? `repeat save ${repeatSave}` : undefined].filter((part): part is string => Boolean(part));
  return {
    data,
    conditions: appliedConditionNames.map((conditionName, index) => ({
      actorId: target.id,
      operation: "apply",
      conditionId: conditionIds[index],
      conditionName,
      ...(duration ? { duration } : {}),
      ...(durationRounds ? { durationRounds } : {}),
      ...(expiresAtRound ? { expiresAtRound } : {}),
      ...(repeatSave ? { repeatSave } : {}),
      reason: reasonParts.length > 0 ? `${roll.label} applies ${conditionName} (${reasonParts.join(", ")})` : `${roll.label} applies ${conditionName}`
    })),
    pendingSaves,
    auditEvents: [...immunityAuditEvents,
      {
        code: "condition.applied",
        actorId: sourceActorId,
        targetActorId: target.id,
        rollId: roll.id,
        message: `${roll.label} applied ${appliedConditionNames.join(", ")} to ${target.name}`,
        data: nextEffect
      }
    ]
  };
}

function dnd5eSrdConditionNamesFromMetadata(metadata: Record<string, unknown>, options: RulesResolverOptions): string[] {
  const failure = recordValue(metadata.failure);
  const selectedEffectOption = dnd5eSrdSelectedEffectOption(metadata, options);
  return uniqueStrings([
    ...dnd5eSrdSplitConditionNames(stringValue(metadata.condition)),
    ...dnd5eSrdSplitConditionNames(stringValue(failure.condition)),
    ...dnd5eSrdSplitConditionNames(stringValue(selectedEffectOption?.condition)),
    ...normalizeStringArray(metadata.conditions).flatMap(dnd5eSrdSplitConditionNames),
    ...normalizeStringArray(metadata.additionalConditions).flatMap(dnd5eSrdSplitConditionNames),
    ...normalizeStringArray(selectedEffectOption?.conditions).flatMap(dnd5eSrdSplitConditionNames),
    ...normalizeStringArray(selectedEffectOption?.additionalConditions).flatMap(dnd5eSrdSplitConditionNames)
  ]);
}

function dnd5eSrdSplitConditionNames(value: string | undefined): string[] {
  return value
    ? value
        .split(/[\/,]/)
        .map((item) => item.trim())
        .filter(Boolean)
    : [];
}

function dnd5eSrdConditionId(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function dnd5eSrdDurationRounds(duration: string | undefined): number | undefined {
  if (!duration) return undefined;
  const normalized = duration.toLowerCase().replace(/^up to\s+/, "").trim();
  if (normalized.includes("current turn") || normalized.includes("next turn")) return 1;
  const match = normalized.match(/(\d+)\s*(round|minute|hour|day)s?/);
  if (!match) return undefined;
  const amount = Math.max(1, Math.floor(Number(match[1])));
  const unit = match[2];
  if (unit === "round") return amount;
  if (unit === "minute") return amount * 10;
  if (unit === "hour") return amount * 600;
  return amount * 14_400;
}

function dnd5eSrdRepeatSaveTiming(metadata: Record<string, unknown>): string | undefined {
  const repeatSave = metadata.repeatSave;
  if (typeof repeatSave === "string" && repeatSave.trim()) return repeatSave.trim();
  const repeatSaveRecord = recordValue(repeatSave);
  const repeatSaveTiming = stringValue(repeatSaveRecord.timing);
  if (repeatSaveTiming) return repeatSaveTiming;
  const timing = metadata.repeatSaveTiming;
  if (typeof timing === "string" && timing.trim()) return timing.trim();
  const timingValues = normalizeStringArray(timing);
  return timingValues.length > 0 ? timingValues.join(", ") : undefined;
}

function dnd5eSrdRulesEngineState(data: Record<string, unknown>): Record<string, unknown> {
  return cloneJsonRecord(recordValue(data.rulesEngine));
}

function dnd5eSrdDataWithRulesEngineState(data: Record<string, unknown>, rules: Record<string, unknown>): Record<string, unknown> {
  return { ...data, rulesEngine: rules };
}

function dnd5eSrdAttunementStateForData(data: Record<string, unknown>): Dnd5eSrdAttunementState {
  const rules = dnd5eSrdRulesEngineState(data);
  const source = normalizeStringArray(data.attunedItemIds).length > 0 ? data.attunedItemIds : rules.attunedItemIds;
  const attunedItemIds = uniqueStrings(normalizeStringArray(source));
  const pseudoActor = { data } as Actor;
  const limit = dnd5eSrdAttunementLimit(pseudoActor);
  const overLimitBy = Math.max(0, attunedItemIds.length - limit);
  const overrideReason = stringValue(recordValue(rules.attunementOverride).reason);
  const activeAttunedItemIds = overrideReason ? [...attunedItemIds] : attunedItemIds.slice(0, limit);
  const inactiveAttunedItemIds = attunedItemIds.filter((itemId) => !activeAttunedItemIds.includes(itemId));
  return {
    limit,
    attunedItemIds,
    activeAttunedItemIds,
    inactiveAttunedItemIds,
    overLimitBy,
    canAttuneMore: attunedItemIds.length < limit,
    ...(overrideReason ? { overrideReason } : {})
  };
}

export function applyDnd5eSrdAttunement(
  actor: Actor,
  item: Item,
  attuned: boolean,
  options: Dnd5eSrdAttunementChangeOptions = {}
): Record<string, unknown> {
  const normalizedItemId = item.id.trim();
  if (!normalizedItemId) throw new Error("An item is required to change attunement");
  if (!itemBelongsToActor(actor, item) || item.campaignId !== actor.campaignId || item.systemId !== actor.systemId) {
    throw new Error(`${item.name || normalizedItemId} does not belong to ${actor.name}`);
  }
  if (!dnd5eSrdItemRequiresAttunement(item)) throw new Error(`${item.name || normalizedItemId} does not require attunement`);
  if (attuned) {
    const prerequisite = dnd5eSrdAttunementPrerequisite(actor, item);
    if (!prerequisite.eligible && !stringValue(options.overrideReason)) throw new Error(prerequisite.reason ?? `${actor.name} does not meet the attunement prerequisite for ${item.name}`);
  } else {
    const itemData = recordValue(item.data);
    if ((booleanValue(itemData.cursed) || booleanValue(itemData.cursePersistsAfterRemovingShield) || booleanValue(itemData.cannotUnattune)) && !options.breakCurse) {
      throw new Error(`${item.name || normalizedItemId} is cursed and cannot be unattuned until the curse is broken`);
    }
  }
  const state = dnd5eSrdAttunementStateForData(actor.data);
  const isAdding = attuned && !state.attunedItemIds.includes(normalizedItemId);
  const nextIds = state.attunedItemIds.filter((candidate) => candidate !== normalizedItemId);
  if (isAdding) nextIds.push(normalizedItemId);
  const overrideReason = stringValue(options.overrideReason)?.trim() || state.overrideReason;
  if (isAdding && nextIds.length > state.limit && !overrideReason) {
    throw new Error(`Attuning ${normalizedItemId} would exceed the attunement limit of ${state.limit}; an override reason is required`);
  }
  const rules = dnd5eSrdRulesEngineState(actor.data);
  rules.attunedItemIds = nextIds;
  if (nextIds.length > state.limit && overrideReason) rules.attunementOverride = { reason: overrideReason };
  else delete rules.attunementOverride;
  const data: Record<string, unknown> = { ...actor.data, rulesEngine: rules };
  if (normalizeStringArray(actor.data.attunedItemIds).length > 0) data.attunedItemIds = nextIds;
  return data;
}

const DND_5E_SRD_SPELLCASTER_CLASSES = new Set(["bard", "cleric", "druid", "paladin", "ranger", "sorcerer", "warlock", "wizard"]);
const DND_5E_SRD_CLASS_NAMES = [...Object.keys(dnd5eSrdMulticlassPrerequisites)];

/**
 * Evaluates prerequisites that the bundled SRD data can represent without
 * guessing. Unknown/homebrew requirement prose is preserved and reported as
 * unsupported so callers can leave it to the GM instead of rejecting it on a
 * brittle text interpretation.
 */
export function dnd5eSrdAttunementPrerequisite(actor: Actor, item: Item): Dnd5eSrdAttunementPrerequisiteResult {
  const requirement = stringValue(recordValue(item.data).attunementRequirement)?.trim();
  if (!requirement) return { supported: true, eligible: true };
  const normalized = requirement.toLowerCase();
  const actorClasses = new Set(dnd5eSrdActorClassLevels(actor).map((entry) => entry.className.toLowerCase()));
  if (normalized === "spellcaster") {
    const spellSlots = recordValue(actor.data.spellSlots);
    const eligible = [...actorClasses].some((className) => DND_5E_SRD_SPELLCASTER_CLASSES.has(className)) || Object.keys(spellSlots).length > 0 || Object.keys(recordValue(actor.data.spellcasting)).length > 0;
    return {
      requirement,
      supported: true,
      eligible,
      ...(eligible ? {} : { reason: `${item.name} requires attunement by a spellcaster` })
    };
  }
  const requiredClasses = DND_5E_SRD_CLASS_NAMES.filter((className) => new RegExp(`\\b${className}\\b`, "i").test(requirement));
  const remainder = requiredClasses.reduce((value, className) => value.replace(new RegExp(`\\b${className}\\b`, "gi"), ""), requirement)
    .replace(/\bor\b/gi, "")
    .replace(/[,&/\s]+/g, "");
  if (requiredClasses.length > 0 && remainder.length === 0) {
    const eligible = requiredClasses.some((className) => actorClasses.has(className.toLowerCase()));
    return {
      requirement,
      supported: true,
      eligible,
      ...(eligible ? {} : { reason: `${item.name} requires attunement by ${requirement}` })
    };
  }
  const species = stringValue(actor.data.species) ?? stringValue(recordValue(actor.data.origin).species);
  if (species && normalized === species.toLowerCase()) return { requirement, supported: true, eligible: true };
  const knownSpecies = ["dragonborn", "dwarf", "elf", "gnome", "goliath", "halfling", "human", "orc", "tiefling"];
  if (knownSpecies.includes(normalized)) {
    return {
      requirement,
      supported: true,
      eligible: false,
      reason: `${item.name} requires attunement by a ${requirement}`
    };
  }
  return { requirement, supported: false, eligible: false, reason: `${item.name} has an unsupported attunement prerequisite (${requirement}); a reviewed override is required` };
}

function dnd5eSrdItemRequiresAttunement(item: Item): boolean {
  const data = recordValue(item.data);
  return booleanValue(data.requiresAttunement) || Boolean(stringValue(data.attunementRequirement));
}

function dnd5eSrdItemModifiersAreActive(actor: Actor, item: Item): boolean {
  if (!dnd5eSrdItemRequiresAttunement(item)) return true;
  return dnd5eSrdAttunementStateForData(actor.data).activeAttunedItemIds.includes(item.id);
}


function dnd5eSrdItemWithActiveModifiers(actor: Actor, item: Item): Item {
  if (dnd5eSrdItemModifiersAreActive(actor, item)) return item;
  const data = { ...recordValue(item.data) };
  for (const key of DND_5E_SRD_ATTUNEMENT_MODIFIER_KEYS) delete data[key];
  return { ...item, data };
}

export function useGenericFantasyAction(actor: Actor, items: Item[] = [], rollId: string, options: SystemActionUseOptions = {}): SystemActionUseResult {
  const item = actionItemForRoll(actor, items, rollId, ["spell", "item"]);
  const consumed: SystemActionConsumption[] = [];
  let data = { ...actor.data };
  let slotLevel: number | undefined;
  let slotPool: SystemActionUseResult["slotPool"];
  const updatedItems: Item[] = [];
  if (item?.type === "spell" && rollId.startsWith(`spell-${item.id}-`)) {
    const level = Math.floor(numericValue(recordValue(item.data).level, 0));
    if (level > 0) {
      slotLevel = spellActionSlotLevel(level, options.spellSlotLevel);
      const result = consumeResourcePool(data.spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
      data = { ...data, spellSlots: result.pools };
      consumed.push(result.consumed);
      slotPool = "spellSlots";
    }
  } else if (item?.type === "item" && rollId.startsWith(`item-${item.id}-`) && booleanValue(recordValue(item.data).consumable)) {
    const itemData = recordValue(item.data);
    const quantity = Math.floor(itemQuantity(itemData));
    if (quantity < 1) throw new Error(`${item.name} has no remaining uses`);
    const remaining = quantity - 1;
    updatedItems.push({ ...item, data: { ...itemData, quantity: remaining } });
    consumed.push({ type: "itemQuantity", key: item.id, label: item.name, amount: 1, remaining });
  }
  if (item) {
    const itemData = recordValue(item.data);
    const resourceCost = recordValue(itemData.resourceCost);
    const resource = stringValue(resourceCost.resource);
    const amount = Math.floor(numericValue(resourceCost.amount, 0));
    if (resource && amount > 0) {
      const label = stringValue(resourceCost.label) || titleCaseWords(resource);
      const result = consumeResourcePool(data.resources, resource, amount, label, "resource");
      data = { ...data, resources: result.pools };
      consumed.push(result.consumed);
    }
    data = applyGenericFantasyActionSideEffects(data, itemData);
  }
  return { systemId: "generic-fantasy", actorId: actor.id, rollId, slotLevel, ...(slotPool ? { slotPool } : {}), consumed, data, items: updatedItems };
}

function applyGenericFantasyActionSideEffects(data: Record<string, unknown>, itemData: Record<string, unknown>): Record<string, unknown> {
  const conditions = normalizeConditionRecords(data.conditions);
  const clearsCondition = stringValue(itemData.clearsCondition);
  const keptConditions = clearsCondition ? conditions.filter((condition) => condition.id !== clearsCondition) : conditions;
  const appliesCondition = stringValue(itemData.appliesCondition);
  if (appliesCondition) {
    const entry = genericFantasyCompendiumEntry(appliesCondition);
    if (!entry || entry.type !== "condition") throw new Error(`Unknown Generic Fantasy condition: ${appliesCondition}`);
    if (!keptConditions.some((condition) => condition.id === appliesCondition)) keptConditions.push({ id: appliesCondition });
  }
  return { ...data, conditions: keptConditions };
}

export function useDnd5eSrdAction(actor: Actor, items: Item[] = [], rollId: string, options: SystemActionUseOptions = {}): SystemActionUseResult {
  const requestedItem = actionItemForRoll(actor, items, rollId, ["spell", "item"]);
  if (dnd5eSrdActiveRageEffect(actor) && (requestedItem?.type === "spell" || rollId.startsWith("spell-"))) {
    throw new Error("Rage is active, so this actor cannot cast spells. End Rage before using this spell action");
  }
  if (dnd5eSrdActiveRageEffect(actor) && rollId === DND_5E_SRD_CONCENTRATION_ROLL_ID) {
    throw new Error("Rage is active, so this actor cannot maintain Concentration. End Rage before using this concentration action");
  }
  const ritualAvailable = requestedItem?.type === "spell" && dnd5eSrdWizardRitualSpellAvailable(actor, requestedItem);
  if (options.ritualCast && requestedItem?.type === "spell" && !ritualAvailable) {
    throw new Error(`${requestedItem.name} is not an eligible Wizard ritual in this actor's stored spellbook`);
  }
  if (requestedItem?.type === "spell" && recordValue(requestedItem.data).prepared === false && !(options.ritualCast && ritualAvailable)) {
    throw new Error(`${requestedItem.name} must be prepared or explicitly cast as an eligible Wizard ritual before its actions can be used`);
  }
  if (requestedItem && dnd5eSrdItemRequiresAttunement(requestedItem) && !dnd5eSrdItemModifiersAreActive(actor, requestedItem)) {
    throw new Error(`${requestedItem.name} requires active attunement before its actions can be used`);
  }
  if (rollId === DND_5E_SRD_SECOND_WIND_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Fighter";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data);
    const result = consumeResourcePool(resources, "secondWind", 1, "Second Wind", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_ACTION_SURGE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Fighter";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data);
    const result = consumeResourcePool(resources, "actionSurge", 1, "Action Surge", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_TACTICAL_MIND_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Fighter";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data);
    const result = consumeResourcePool(resources, "secondWind", 1, "Second Wind", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_RAGE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Barbarian";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data);
    const result = consumeResourcePool(resources, "rage", 1, "Rage", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (
    rollId === DND_5E_SRD_RAGE_DAMAGE_ROLL_ID ||
    rollId === DND_5E_SRD_RAGE_EXTEND_ROLL_ID ||
    rollId === DND_5E_SRD_RAGE_END_ROLL_ID ||
    rollId === DND_5E_SRD_RECKLESS_ATTACK_ROLL_ID ||
    rollId === DND_5E_SRD_BERSERKER_FRENZY_ROLL_ID ||
    rollId === DND_5E_SRD_BERSERKER_MINDLESS_RAGE_ROLL_ID ||
    rollId === DND_5E_SRD_BERSERKER_RETALIATION_ROLL_ID ||
    rollId === DND_5E_SRD_BERSERKER_INTIMIDATING_PRESENCE_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_BARDIC_INSPIRATION_ROLL_ID || rollId === DND_5E_SRD_LORE_CUTTING_WORDS_ROLL_ID || rollId === DND_5E_SRD_LORE_PEERLESS_SKILL_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Bard";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data);
    const result = consumeResourcePool(resources, "bardicInspiration", 1, "Bardic Inspiration", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_LORE_MAGICAL_DISCOVERIES_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_FONT_OF_INSPIRATION_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Bard";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const bardicInspiration = resources.bardicInspiration;
    if (!bardicInspiration || bardicInspiration.current >= bardicInspiration.max) throw new Error("Bardic Inspiration is already full");
    const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
    resources.bardicInspiration = { ...bardicInspiration, current: Math.min(bardicInspiration.max, bardicInspiration.current + 1) };
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, resources, spellSlots: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_LAY_ON_HANDS_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Paladin";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const amount = dnd5eSrdResourceActionAmount(options.resourceAmount, dnd5eSrdDefaultLayOnHandsAmount(actor));
    const result = consumeResourcePool(resources, "layOnHands", amount, "Lay On Hands", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DIVINE_SMITE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Paladin";
    const level = numericValue(actor.data.level, 1);
    const slotLevel = options.useFreeResource ? 1 : spellActionSlotLevel(1, options.spellSlotLevel);
    if (options.useFreeResource) {
      const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
      const result = consumeResourcePool(resources, "paladinsSmite", 1, "Paladin's Smite", "resource");
      return {
        systemId: DND_5E_SRD_SYSTEM_ID,
        actorId: actor.id,
        rollId,
        slotLevel,
        consumed: [result.consumed],
        data: { ...actor.data, resources: result.pools },
        items: []
      };
    }
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, spellSlots: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_FAITHFUL_STEED_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Paladin";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "faithfulSteed", 1, "Faithful Steed", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DEVOTION_SACRED_WEAPON_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Paladin";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "channelDivinity", 1, "Channel Divinity", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DEVOTION_HOLY_NIMBUS_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Paladin";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "holyNimbus", 1, "Holy Nimbus", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DEVOTION_AURA_ROLL_ID || rollId === DND_5E_SRD_DEVOTION_SMITE_PROTECTION_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_HUNTERS_MARK_DAMAGE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Ranger";
    const level = numericValue(actor.data.level, 1);
    const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
    if (options.useFreeResource) {
      const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
      const result = consumeResourcePool(resources, "favoredEnemy", 1, "Favored Enemy", "resource");
      return {
        systemId: DND_5E_SRD_SYSTEM_ID,
        actorId: actor.id,
        rollId,
        slotLevel: 1,
        consumed: [result.consumed],
        data: { ...actor.data, resources: result.pools },
        items: []
      };
    }
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, spellSlots: result.pools },
      items: []
    };
  }
  if (
    rollId === DND_5E_SRD_HUNTER_LORE_ROLL_ID ||
    rollId === DND_5E_SRD_HUNTER_PREY_ROLL_ID ||
    rollId === DND_5E_SRD_HUNTER_DEFENSIVE_TACTICS_ROLL_ID ||
    rollId === DND_5E_SRD_HUNTER_SUPERIOR_PREY_ROLL_ID ||
    rollId === DND_5E_SRD_HUNTER_SUPERIOR_DEFENSE_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_MARTIAL_ARTS_DAMAGE_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_FLURRY_OF_BLOWS_ROLL_ID || rollId === DND_5E_SRD_PATIENT_DEFENSE_ROLL_ID || rollId === DND_5E_SRD_STEP_OF_THE_WIND_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Monk";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "focus", 1, "Focus Point", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_UNCANNY_METABOLISM_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Monk";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "uncannyMetabolism", 1, "Uncanny Metabolism", "resource");
    const focus = result.pools.focus;
    if (focus) result.pools.focus = { ...focus, current: focus.max };
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DEFLECT_ATTACKS_DAMAGE_ROLL_ID || rollId === DND_5E_SRD_STUNNING_STRIKE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Monk";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "focus", 1, "Focus Point", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_OPEN_HAND_TECHNIQUE_ROLL_ID || rollId === DND_5E_SRD_OPEN_HAND_FLEET_STEP_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_OPEN_HAND_WHOLENESS_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Monk";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "wholenessOfBody", 1, "Wholeness of Body", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_OPEN_HAND_QUIVERING_PALM_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Monk";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "focus", 4, "Focus Point", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_INNATE_SORCERY_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Sorcerer";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "innateSorcery", 1, "Innate Sorcery", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_CONVERT_SPELL_SLOT_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Sorcerer";
    const level = numericValue(actor.data.level, 1);
    const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const sorceryPoints = resources.sorceryPoints;
    if (!sorceryPoints) throw new Error("Sorcery Points are unavailable");
    if (sorceryPoints.current >= sorceryPoints.max) throw new Error("Sorcery Points are already full");
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
    resources.sorceryPoints = { ...sorceryPoints, current: Math.min(sorceryPoints.max, sorceryPoints.current + slotLevel) };
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, resources, spellSlots: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_CREATE_SPELL_SLOT_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Sorcerer";
    const level = numericValue(actor.data.level, 1);
    const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
    const cost = dnd5eSrdCreateSpellSlotCost(slotLevel, level);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const slotKey = `level${slotLevel}`;
    const slot = spellSlots[slotKey];
    if (!slot) throw new Error(`No ${formatOrdinal(slotLevel)}-level spell slot pool is available`);
    if (slot.current >= slot.max) throw new Error(`Level ${slotLevel} Spell Slot is already full`);
    const result = consumeResourcePool(resources, "sorceryPoints", cost, "Sorcery Points", "resource");
    spellSlots[slotKey] = { ...slot, current: Math.min(slot.max, slot.current + 1) };
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools, spellSlots },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_METAMAGIC_EMPOWERED_ROLL_ID || rollId === DND_5E_SRD_METAMAGIC_QUICKENED_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Sorcerer";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const cost = rollId === DND_5E_SRD_METAMAGIC_QUICKENED_ROLL_ID ? 2 : 1;
    const result = consumeResourcePool(resources, "sorceryPoints", cost, "Sorcery Points", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DRACONIC_RESILIENCE_ROLL_ID || rollId === DND_5E_SRD_DRACONIC_ELEMENTAL_AFFINITY_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_DRACONIC_WINGS_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Sorcerer";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    if (options.resourceAmount === 3) {
      const result = consumeResourcePool(resources, "sorceryPoints", 3, "Sorcery Points", "resource");
      const dragonWings = result.pools.dragonWings;
      if (dragonWings) result.pools.dragonWings = { ...dragonWings, current: Math.min(dragonWings.max, dragonWings.current + 1) };
      return {
        systemId: DND_5E_SRD_SYSTEM_ID,
        actorId: actor.id,
        rollId,
        consumed: [result.consumed],
        data: { ...actor.data, resources: result.pools },
        items: []
      };
    }
    const result = consumeResourcePool(resources, "dragonWings", 1, "Dragon Wings", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DRACONIC_COMPANION_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Sorcerer";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "dragonCompanion", 1, "Dragon Companion", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (
    rollId === DND_5E_SRD_EVOKER_POTENT_CANTRIP_ROLL_ID ||
    rollId === DND_5E_SRD_EVOKER_SCULPT_SPELLS_ROLL_ID ||
    rollId === DND_5E_SRD_EVOKER_EMPOWERED_EVOCATION_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_EVOKER_OVERCHANNEL_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Wizard";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "overchannel", 1, "Overchannel", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_ELDRITCH_INVOCATIONS_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_MAGICAL_CUNNING_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Warlock";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const recoverableEntries = Object.entries(spellSlots)
      .filter(([, slot]) => stringValue(slot.recovery) === "short")
      .sort(([left], [right]) => Number(right.replace("level", "")) - Number(left.replace("level", "")));
    const expended = recoverableEntries.reduce((total, [, slot]) => total + Math.max(0, slot.max - slot.current), 0);
    if (expended <= 0) throw new Error("Pact Magic spell slots are already full");
    const cunningResult = consumeResourcePool(resources, "magicalCunning", 1, "Magical Cunning", "resource");
    let remainingRecovery = dnd5eSrdMagicalCunningLimit(level);
    for (const [key, slot] of recoverableEntries) {
      if (remainingRecovery <= 0) break;
      const recovered = Math.min(remainingRecovery, Math.max(0, slot.max - slot.current));
      if (recovered <= 0) continue;
      spellSlots[key] = { ...slot, current: Math.min(slot.max, slot.current + recovered) };
      remainingRecovery -= recovered;
    }
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [cunningResult.consumed],
      data: { ...actor.data, resources: cunningResult.pools, spellSlots },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_WILD_SHAPE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Druid";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "wildShape", 1, "Wild Shape", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_WILD_COMPANION_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Druid";
    const level = numericValue(actor.data.level, 1);
    if (options.useFreeResource) {
      const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
      const result = consumeResourcePool(resources, "wildShape", 1, "Wild Shape", "resource");
      return {
        systemId: DND_5E_SRD_SYSTEM_ID,
        actorId: actor.id,
        rollId,
        consumed: [result.consumed],
        data: { ...actor.data, resources: result.pools },
        items: []
      };
    }
    const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, spellSlots: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_FIEND_DARK_BLESSING_ROLL_ID || rollId === DND_5E_SRD_FIEND_RESILIENCE_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_FIEND_DARK_LUCK_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Warlock";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "fiendLuck", 1, "Dark One's Own Luck", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_FIEND_HURL_THROUGH_HELL_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Warlock";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    if (typeof options.spellSlotLevel === "number") {
      const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
      const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
      const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
      const hurl = resources.hurlThroughHell;
      if (hurl) resources.hurlThroughHell = { ...hurl, current: Math.min(hurl.max, hurl.current + 1) };
      return {
        systemId: DND_5E_SRD_SYSTEM_ID,
        actorId: actor.id,
        rollId,
        slotLevel,
        consumed: [result.consumed],
        data: { ...actor.data, resources, spellSlots: result.pools },
        items: []
      };
    }
    const result = consumeResourcePool(resources, "hurlThroughHell", 1, "Hurl Through Hell", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_WILD_RESURGENCE_WILD_SHAPE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Druid";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const wildShape = resources.wildShape;
    if (!wildShape || wildShape.max <= 0) throw new Error("Wild Shape is unavailable");
    if (wildShape.current > 0) throw new Error("Wild Shape uses remain");
    const slotLevel = spellActionSlotLevel(1, options.spellSlotLevel);
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
    resources.wildShape = { ...wildShape, current: Math.min(wildShape.max, wildShape.current + 1) };
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel,
      consumed: [result.consumed],
      data: { ...actor.data, resources, spellSlots: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_WILD_RESURGENCE_SPELL_SLOT_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Druid";
    const level = numericValue(actor.data.level, 1);
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
    const levelOne = spellSlots.level1;
    if (!levelOne) throw new Error("Level 1 Spell Slot is unavailable");
    if (levelOne.current >= levelOne.max) throw new Error("Level 1 Spell Slot is already full");
    const wildShapeResult = consumeResourcePool(resources, "wildShape", 1, "Wild Shape", "resource");
    const resurgenceResult = consumeResourcePool(wildShapeResult.pools, "wildResurgence", 1, "Wild Resurgence", "resource");
    spellSlots.level1 = { ...levelOne, current: Math.min(levelOne.max, levelOne.current + 1) };
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      slotLevel: 1,
      consumed: [wildShapeResult.consumed, resurgenceResult.consumed],
      data: { ...actor.data, resources: resurgenceResult.pools, spellSlots },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_MOON_CIRCLE_FORMS_ROLL_ID || rollId === DND_5E_SRD_MOON_IMPROVED_CIRCLE_FORMS_ROLL_ID || rollId === DND_5E_SRD_MOON_LUNAR_FORM_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_MOON_MOONLIGHT_STEP_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Druid";
    const level = numericValue(actor.data.level, 1);
    if (typeof options.spellSlotLevel === "number") {
      const slotLevel = spellActionSlotLevel(2, options.spellSlotLevel);
      if (slotLevel < 2) throw new Error("Moonlight Step restoration requires a level 2 or higher spell slot");
      const spellSlots = normalizeDnd5eSrdSpellSlots(actor.data.spellSlots, className, level, { raiseMaxToDefault: true });
      const result = consumeResourcePool(spellSlots, `level${slotLevel}`, 1, `Level ${slotLevel} Spell Slot`, "spellSlot");
      const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
      const moonlightStep = resources.moonlightStep;
      if (moonlightStep) resources.moonlightStep = { ...moonlightStep, current: Math.min(moonlightStep.max, moonlightStep.current + 1) };
      return {
        systemId: DND_5E_SRD_SYSTEM_ID,
        actorId: actor.id,
        rollId,
        slotLevel,
        consumed: [result.consumed],
        data: { ...actor.data, resources, spellSlots: result.pools },
        items: []
      };
    }
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, level, actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, "moonlightStep", 1, "Moonlight Step", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_DIVINE_SPARK_HEALING_ROLL_ID || rollId === DND_5E_SRD_DIVINE_SPARK_DAMAGE_ROLL_ID || rollId === DND_5E_SRD_TURN_UNDEAD_ROLL_ID || rollId === DND_5E_SRD_LIFE_PRESERVE_LIFE_ROLL_ID) {
    const className = stringValue(actor.data.class) || "Cleric";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data);
    const result = consumeResourcePool(resources, "channelDivinity", 1, "Channel Divinity", "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  if (rollId === DND_5E_SRD_SEAR_UNDEAD_DAMAGE_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_LIFE_DISCIPLE_ROLL_ID || rollId === DND_5E_SRD_LIFE_BLESSED_HEALER_ROLL_ID || rollId === DND_5E_SRD_LIFE_SUPREME_HEALING_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_SNEAK_ATTACK_DAMAGE_ROLL_ID || rollId === DND_5E_SRD_CUNNING_STRIKE_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (
    rollId === DND_5E_SRD_THIEF_FAST_HANDS_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_SECOND_STORY_WORK_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_SUPREME_SNEAK_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_USE_MAGIC_DEVICE_ROLL_ID ||
    rollId === DND_5E_SRD_THIEF_REFLEXES_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (
    rollId === DND_5E_SRD_HUMAN_RESOURCEFUL_ROLL_ID ||
    rollId === DND_5E_SRD_HUMAN_SKILLFUL_ROLL_ID ||
    rollId === DND_5E_SRD_HUMAN_VERSATILE_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (
    rollId === DND_5E_SRD_ELF_ELVEN_LINEAGE_ROLL_ID ||
    rollId === DND_5E_SRD_ELF_FEY_ANCESTRY_ROLL_ID ||
    rollId === DND_5E_SRD_ELF_TRANCE_ROLL_ID ||
    rollId === DND_5E_SRD_GNOME_GNOMISH_CUNNING_ROLL_ID ||
    rollId === DND_5E_SRD_GNOME_LINEAGE_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_LUCK_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_BRAVE_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_NIMBLENESS_ROLL_ID ||
    rollId === DND_5E_SRD_HALFLING_NATURALLY_STEALTHY_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (
    rollId === DND_5E_SRD_CHAMPION_CRITICAL_ROLL_ID ||
    rollId === DND_5E_SRD_CHAMPION_REMARKABLE_ATHLETE_ROLL_ID ||
    rollId === DND_5E_SRD_CHAMPION_HEROIC_WARRIOR_ROLL_ID ||
    rollId === DND_5E_SRD_CHAMPION_SURVIVOR_ROLL_ID
  ) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  if (rollId === DND_5E_SRD_TIEFLING_FIENDISH_LEGACY_ROLL_ID || rollId === DND_5E_SRD_TIEFLING_OTHERWORLDLY_PRESENCE_ROLL_ID) {
    return { systemId: DND_5E_SRD_SYSTEM_ID, actorId: actor.id, rollId, consumed: [], data: { ...actor.data }, items: [] };
  }
  const speciesAction = dnd5eSrdSpeciesResourceAction(rollId);
  if (speciesAction) {
    const className = stringValue(actor.data.class) || "Fighter";
    const resources = normalizeDnd5eSrdResources(actor.data.resources, className, numericValue(actor.data.level, 1), actor.data, { raiseMaxToDefault: true });
    const result = consumeResourcePool(resources, speciesAction.key, 1, speciesAction.label, "resource");
    return {
      systemId: DND_5E_SRD_SYSTEM_ID,
      actorId: actor.id,
      rollId,
      consumed: [result.consumed],
      data: { ...actor.data, resources: result.pools },
      items: []
    };
  }
  const actionItems = dnd5eSrdActionAvailableItems(actor, items);
  const spellAction = useDnd5eSrdSpellAction(actor, actionItems, rollId, options);
  if (spellAction) return spellAction;
  return { ...useGenericFantasyAction(actor, actionItems, rollId, options), systemId: DND_5E_SRD_SYSTEM_ID };
}

export function dnd5eSrdEquipmentPurchase(actor: Actor, entry: GenericFantasyCompendiumEntry, quantity = 1): Dnd5eSrdEquipmentPurchaseResult {
  if (entry.type === "condition") throw new Error(`Compendium entry is not purchasable: ${entry.id}`);
  const unitCostGp = numericValue(entry.data.costGp, Number.NaN);
  if (!Number.isFinite(unitCostGp) || unitCostGp < 0) throw new Error(`Compendium entry has no SRD equipment cost: ${entry.id}`);
  const purchaseQuantity = clampInteger(quantity, 1, 99, 1);
  const unitCostCopper = Math.round(unitCostGp * 100);
  const totalCostCopper = unitCostCopper * purchaseQuantity;
  const availableCopper = dnd5eSrdCurrencyToCopper(actor.data.currency);
  if (availableCopper < totalCostCopper) throw new Error(`Insufficient currency: requires ${dnd5eSrdFormatGp(totalCostCopper)}, available ${dnd5eSrdFormatGp(availableCopper)}`);
  const currency = dnd5eSrdCurrencyFromCopper(availableCopper - totalCostCopper);
  const totalCostGp = totalCostCopper / 100;
  return {
    systemId: DND_5E_SRD_SYSTEM_ID,
    actorId: actor.id,
    entryId: entry.id,
    quantity: purchaseQuantity,
    unitCostGp,
    totalCostGp,
    currency,
    data: { ...actor.data, currency },
    itemData: { ...entry.data, compendiumId: entry.id, quantity: purchaseQuantity, purchasedForGp: totalCostGp }
  };
}

export function genericFantasyActorConditions(actor: Actor): AppliedCondition[] {
  const rawConditions = normalizeConditionRecords(actor.data.conditions);
  return rawConditions.map((condition) => {
    const entry = genericFantasyCompendiumEntry(condition.id);
    return {
      id: condition.id,
      name: entry?.name ?? condition.id,
      summary: entry?.summary ?? "",
      appliedAt: condition.appliedAt,
      ...(condition.level ? { level: condition.level } : {})
    };
  });
}

export function dnd5eSrdActorConditions(actor: Actor): AppliedCondition[] {
  const rawConditions = normalizeConditionRecords(actor.data.conditions);
  return rawConditions.map((condition) => {
    const entry = dnd5eSrdCompendiumEntry(condition.id);
    return {
      id: condition.id,
      name: entry?.name ?? condition.id,
      summary: entry?.summary ?? "",
      appliedAt: condition.appliedAt,
      ...(condition.level ? { level: condition.level } : {})
    };
  });
}

export function dnd5eSrdConditionImmunities(actor: Actor, items: Item[] = []): string[] {
  const conditionIds = new Set(dnd5eSrdCompendium().filter((entry) => entry.type === "condition").map((entry) => entry.id));
  const collect = (data: Record<string, unknown>): string[] => uniqueStrings([
    ...normalizeStringArray(data.conditionImmunity),
    ...normalizeStringArray(data.conditionImmunities),
    ...normalizeStringArray(data.immunity),
    ...normalizeStringArray(data.immunities)
  ].map((value) => dnd5eSrdConditionId(value)).filter((value) => conditionIds.has(value)));
  const rules = dnd5eSrdRulesEngineState(actor.data);
  const activeEffects = Array.isArray(rules.activeEffects) ? rules.activeEffects.map((effect) => recordValue(effect)) : [];
  const activeItems = items
    .filter((item) => itemBelongsToActor(actor, item) && itemQuantity(recordValue(item.data)) > 0 && recordValue(item.data).equipped !== false)
    .filter((item) => dnd5eSrdItemModifiersAreActive(actor, item));
  const statBlock = recordValue(recordValue(actor.data.monster).statBlock);
  return uniqueStrings([
    ...collect(actor.data),
    ...collect(statBlock),
    ...activeEffects.flatMap(collect),
    ...activeItems.flatMap((item) => collect(recordValue(item.data)))
  ]);
}

export function applyGenericFantasyCondition(actor: Actor, conditionId: string, appliedAt?: string): Record<string, unknown> {
  const entry = genericFantasyCompendiumEntry(conditionId);
  if (!entry || entry.type !== "condition") throw new Error(`Unknown condition: ${conditionId}`);
  const conditions = normalizeConditionRecords(actor.data.conditions);
  if (!conditions.some((condition) => condition.id === conditionId)) conditions.push({ id: conditionId, appliedAt });
  return { ...actor.data, conditions };
}

export function applyDnd5eSrdCondition(actor: Actor, conditionId: string, appliedAt?: string, options: Dnd5eSrdConditionApplyOptions = {}): Record<string, unknown> {
  const entry = dnd5eSrdCompendiumEntry(conditionId);
  if (!entry || entry.type !== "condition") throw new Error(`Unknown condition: ${conditionId}`);
  const normalizedConditionId = dnd5eSrdConditionId(conditionId);
  if (dnd5eSrdConditionImmunities(actor, options.items).includes(normalizedConditionId) && !stringValue(options.overrideReason)) {
    throw new Error(`${actor.name} is immune to ${entry.name}`);
  }
  const conditions = normalizeConditionRecords(actor.data.conditions);
  if (conditionId === "exhaustion") {
    const existing = conditions.find((condition) => condition.id === conditionId);
    const currentLevel = existing ? clampInteger(existing.level, 1, 6, 1) : 0;
    const nextLevel = clampInteger(options.level, 1, 6, currentLevel + 1);
    if (existing) {
      existing.level = nextLevel;
      existing.appliedAt = appliedAt ?? existing.appliedAt;
    } else {
      conditions.push({ id: conditionId, appliedAt, level: nextLevel });
    }
  } else if (!conditions.some((condition) => condition.id === conditionId)) {
    conditions.push({ id: conditionId, appliedAt });
  }
  return { ...actor.data, conditions };
}

export function removeGenericFantasyCondition(actor: Actor, conditionId: string): Record<string, unknown> {
  const conditions = normalizeConditionRecords(actor.data.conditions).filter((condition) => condition.id !== conditionId);
  return { ...actor.data, conditions };
}

export function removeDnd5eSrdCondition(actor: Actor, conditionId: string): Record<string, unknown> {
  return removeGenericFantasyCondition(actor, conditionId);
}

export function stellarFrontiersAptitudeCheck(actor: Actor, aptitude: string): QuickRoll {
  const modifier = stellarFrontiersAptitudeModifier(actor, aptitude);
  const label = `${aptitude.charAt(0).toUpperCase()}${aptitude.slice(1)} Check`;
  const conditions = stellarFrontiersActorConditions(actor);
  const d20 = conditions.some((condition) => condition.id === "jammed") ? "2d20kl1" : "1d20";
  const bonus = conditions.some((condition) => condition.id === "locked-in") ? "+1d6" : "";
  return {
    id: `aptitude-${aptitude}`,
    label,
    formula: `${d20}${formatSignedNumber(modifier)}${bonus}`
  };
}

function stellarFrontiersActionMetadata(data: Record<string, unknown>, actionType: string, aptitude?: string): Record<string, unknown> {
  const metadata: Record<string, unknown> = { actionType };
  if (aptitude) metadata.aptitude = aptitude;
  const strainCost = Math.floor(numericValue(data.strainCost, 0));
  if (strainCost > 0) metadata.strainCost = strainCost;
  const resourceCost = recordValue(data.resourceCost);
  const resource = stringValue(resourceCost.resource);
  const amount = Math.floor(numericValue(resourceCost.amount, 0));
  if (resource && amount > 0) metadata.resourceCost = { resource, amount };
  const clearsCondition = stringValue(data.clearsCondition);
  if (clearsCondition) metadata.clearsCondition = clearsCondition;
  const appliesCondition = stringValue(data.appliesCondition);
  if (appliesCondition) metadata.appliesCondition = appliesCondition;
  if (stringValue(data.category) === "consumable") metadata.consumable = true;
  const tags = normalizeStringArray(data.tags);
  if (tags.length > 0) metadata.tags = tags;
  return metadata;
}

export function stellarFrontiersActionRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  return items.filter((item) => itemBelongsToActor(actor, item)).flatMap((item) => {
    const data = recordValue(item.data);
    const rolls: QuickRoll[] = [];
    const prefix = item.type === "talent" ? "talent" : "gear";
    const aptitude = stringValue(data.aptitude);
    const damage = stringValue(data.damage);
    if (damage) {
      rolls.push({
        id: `${prefix}-${item.id}-damage`,
        label: `${item.name} Damage`,
        formula: aptitude ? appendFormulaBonus(damage, stellarFrontiersAptitudeModifier(actor, aptitude)) : damage,
        metadata: stellarFrontiersActionMetadata(data, "damage", aptitude)
      });
    }
    const healingFormula = stringValue(data.healingFormula);
    if (healingFormula) {
      rolls.push({
        id: `${prefix}-${item.id}-healing`,
        label: `${item.name} Healing`,
        formula: aptitude ? appendFormulaBonus(healingFormula, stellarFrontiersAptitudeModifier(actor, aptitude)) : healingFormula,
        metadata: stellarFrontiersActionMetadata(data, "healing", aptitude)
      });
    }
    const bonusFormula = stringValue(data.bonusFormula);
    if (bonusFormula) {
      rolls.push({
        id: `${prefix}-${item.id}-boost`,
        label: `${item.name} Boost`,
        formula: aptitude ? appendFormulaBonus(bonusFormula, stellarFrontiersAptitudeModifier(actor, aptitude)) : bonusFormula,
        metadata: stellarFrontiersActionMetadata(data, "boost", aptitude)
      });
    }
    return rolls;
  });
}

export function stellarFrontiersQuickRolls(actor: Actor, items: Item[] = []): QuickRoll[] {
  const aptitudes = actor.data.aptitudes as Record<string, number> | undefined;
  return [
    ...Object.keys(aptitudes ?? { combat: 2, tech: 2, pilot: 1, science: 1, charm: 0 }).map((aptitude) => stellarFrontiersAptitudeCheck(actor, aptitude)),
    ...stellarFrontiersActionRolls(actor, items)
  ];
}

