function defaultDnd5eSrdAttributes(): Record<string, number> {
  return { strength: 10, dexterity: 10, constitution: 10, intelligence: 10, wisdom: 10, charisma: 10 };
}

function dnd5eSrdProficiencyBonus(actor: Actor): number {
  return dnd5eSrdProficiencyBonusForLevel(numericValue(actor.data.level, 1), actor.data.proficiencyBonus);
}

function dnd5eSrdProficiencyBonusForLevel(level: number, explicit: unknown): number {
  return Math.max(2, Math.floor(numericValue(explicit, 2 + Math.floor((Math.max(1, level) - 1) / 4))));
}

function dnd5eSrdSaveProficiencies(actor: Actor): string[] {
  return dnd5eSrdSaveProficienciesForClass(stringValue(actor.data.class), actor.data.saveProficiencies);
}

function dnd5eSrdSaveProficienciesForClass(className: string | undefined, explicit: unknown): string[] {
  const defaultAttributes = defaultDnd5eSrdAttributes();
  const explicitProficiencies = normalizeStringArray(explicit).map((ability) => ability.toLowerCase()).filter((ability) => ability in defaultAttributes);
  if (Array.isArray(explicit)) return explicitProficiencies;
  if (!className) return [];
  const normalizedClass = className.toLowerCase();
  if (normalizedClass === "barbarian" || normalizedClass === "fighter") return ["strength", "constitution"];
  if (normalizedClass === "bard") return ["dexterity", "charisma"];
  if (normalizedClass === "cleric") return ["wisdom", "charisma"];
  if (normalizedClass === "druid") return ["intelligence", "wisdom"];
  if (normalizedClass === "paladin") return ["wisdom", "charisma"];
  if (normalizedClass === "ranger") return ["strength", "dexterity"];
  if (normalizedClass === "monk") return ["strength", "dexterity"];
  if (normalizedClass === "sorcerer") return ["constitution", "charisma"];
  if (normalizedClass === "warlock") return ["wisdom", "charisma"];
  if (normalizedClass === "wizard") return ["intelligence", "wisdom"];
  if (normalizedClass === "rogue") return ["dexterity", "intelligence"];
  return [];
}

function dnd5eSrdSkillProficiencyMultiplier(actor: Actor, skillId: string): number {
  const normalizedSkillId = normalizeDnd5eSrdSkillId(skillId);
  if (dnd5eSrdSkillProficiencies(actor, "skillExpertise").includes(normalizedSkillId)) return 2;
  return dnd5eSrdSkillProficiencies(actor, "skillProficiencies").includes(normalizedSkillId) ? 1 : 0;
}

function dnd5eSrdSkillProficiencies(actor: Actor, field: "skillProficiencies" | "skillExpertise"): string[] {
  if (field === "skillExpertise") return dnd5eSrdSkillProficienciesFromExplicit(actor.data.skillExpertise);
  return dnd5eSrdSkillProficienciesForClass(stringValue(actor.data.class), actor.data.skillProficiencies);
}

function dnd5eSrdSkillProficienciesForClass(className: string | undefined, explicit: unknown): string[] {
  const explicitProficiencies = dnd5eSrdSkillProficienciesFromExplicit(explicit);
  if (Array.isArray(explicit)) return explicitProficiencies;
  if (!className) return [];
  const normalizedClass = className.toLowerCase();
  if (normalizedClass === "bard") return ["performance", "persuasion", "perception"];
  if (normalizedClass === "cleric") return ["medicine", "religion"];
  if (normalizedClass === "paladin") return ["athletics", "persuasion"];
  if (normalizedClass === "ranger") return ["nature", "perception", "survival"];
  if (normalizedClass === "monk") return ["acrobatics", "stealth"];
  if (normalizedClass === "sorcerer") return ["arcana", "persuasion"];
  if (normalizedClass === "warlock") return ["arcana", "intimidation"];
  if (normalizedClass === "wizard") return ["arcana", "history"];
  if (normalizedClass === "rogue") return ["stealth", "sleight-of-hand"];
  if (normalizedClass === "fighter" || normalizedClass === "barbarian") return ["athletics", "intimidation"];
  return [];
}

function dnd5eSrdSkillProficienciesFromExplicit(explicit: unknown): string[] {
  const skillIds = new Set(dnd5eSrdSkills().map((skill) => skill.id));
  return Array.from(
    new Set(
      normalizeStringArray(explicit)
        .map((skill) => normalizeDnd5eSrdSkillId(skill))
        .filter((skill) => skillIds.has(skill))
    )
  );
}

function normalizeDnd5eSrdSkillId(skill: string): string {
  return skill.trim().replace(/([a-z])([A-Z])/g, "$1-$2").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function dnd5eSrdToolProficiencyMultiplier(actor: Actor, toolId: string): number {
  const normalizedToolId = normalizeDnd5eSrdToolId(toolId);
  if (dnd5eSrdToolProficiencies(actor, "toolExpertise").includes(normalizedToolId)) return 2;
  return dnd5eSrdToolProficiencies(actor, "toolProficiencies").includes(normalizedToolId) ? 1 : 0;
}

function dnd5eSrdToolProficiencies(actor: Actor, field: "toolProficiencies" | "toolExpertise"): string[] {
  if (field === "toolExpertise") return dnd5eSrdToolProficienciesFromExplicit(actor.data.toolExpertise);
  return dnd5eSrdToolProficienciesForBackground(stringValue(actor.data.background) || "Soldier", actor.data.toolProficiencies);
}

function dnd5eSrdToolProficienciesForBackground(background: string, explicit: unknown): string[] {
  const explicitProficiencies = dnd5eSrdToolProficienciesFromExplicit(explicit);
  if (explicitProficiencies.length > 0) return explicitProficiencies;
  const normalizedBackground = background.toLowerCase();
  if (normalizedBackground === "acolyte" || normalizedBackground === "sage") return ["calligraphers-supplies"];
  if (normalizedBackground === "criminal") return ["thieves-tools"];
  if (normalizedBackground === "soldier") return ["gaming-set"];
  return [];
}

function dnd5eSrdToolProficienciesFromExplicit(explicit: unknown): string[] {
  const toolIds = new Set(dnd5eSrdTools().map((tool) => tool.id));
  return Array.from(
    new Set(
      normalizeStringArray(explicit)
        .map((tool) => normalizeDnd5eSrdToolId(tool))
        .filter((tool) => toolIds.has(tool))
    )
  );
}

function normalizeDnd5eSrdToolId(tool: string): string {
  return tool.trim().replace(/([a-z])([A-Z])/g, "$1-$2").toLowerCase().replace(/'/g, "").replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function dnd5eSrdBackgroundById(value: string): Dnd5eSrdCharacterBackground | undefined {
  const id = normalizeDnd5eSrdOriginId(value);
  return DND_5E_SRD_BACKGROUNDS.find((background) => background.id === id);
}

function dnd5eSrdSpeciesById(value: string): Dnd5eSrdCharacterSpecies | undefined {
  const id = normalizeDnd5eSrdOriginId(value);
  return DND_5E_SRD_SPECIES.find((species) => species.id === id);
}

function normalizeDnd5eSrdOriginId(value: string): string {
  return value.trim().replace(/([a-z])([A-Z])/g, "$1-$2").toLowerCase().replace(/'/g, "").replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
}

function dnd5eSrdSpeciesResources(species: Dnd5eSrdCharacterSpecies, proficiencyBonus: number, level = 1, data: Record<string, unknown> = {}): Record<string, Record<string, unknown> & { current: number; max: number }> {
  const normalizedLevel = Math.max(1, Math.floor(level));
  const origin = recordValue(data.origin);
  if (species.id === "dragonborn") {
    const resources: Record<string, Record<string, unknown> & { current: number; max: number }> = {
      breathWeapon: { current: proficiencyBonus, max: proficiencyBonus, recovery: "long" }
    };
    if (normalizedLevel >= 5) resources.draconicFlight = { current: 1, max: 1, recovery: "long" };
    return resources;
  }
  if (species.id === "dwarf") {
    return { stonecunning: { current: proficiencyBonus, max: proficiencyBonus, recovery: "long" } };
  }
  if (species.id === "elf") {
    const resources: Record<string, Record<string, unknown> & { current: number; max: number }> = {};
    if (normalizedLevel >= 3) resources.elfLineageLevel3 = { current: 1, max: 1, recovery: "long" };
    if (normalizedLevel >= 5) resources.elfLineageLevel5 = { current: 1, max: 1, recovery: "long" };
    return resources;
  }
  if (species.id === "gnome") {
    const lineage = dnd5eSrdGnomeLineageById(stringValue(origin.gnomeLineage) ?? "forest-gnome");
    if (lineage?.id === "forest-gnome") return { gnomeSpeakWithAnimals: { current: proficiencyBonus, max: proficiencyBonus, recovery: "long" } };
    return {};
  }
  if (species.id === "orc") {
    return {
      adrenalineRush: { current: proficiencyBonus, max: proficiencyBonus, recovery: "short" },
      relentlessEndurance: { current: 1, max: 1, recovery: "long" }
    };
  }
  if (species.id === "goliath") {
    const resources: Record<string, Record<string, unknown> & { current: number; max: number }> = {
      giantAncestry: { current: proficiencyBonus, max: proficiencyBonus, recovery: "long" }
    };
    if (normalizedLevel >= 5) resources.largeForm = { current: 1, max: 1, recovery: "long" };
    return resources;
  }
  if (species.id === "tiefling") {
    const resources: Record<string, Record<string, unknown> & { current: number; max: number }> = {};
    if (normalizedLevel >= 3) resources.tieflingLegacyLevel3 = { current: 1, max: 1, recovery: "long" };
    if (normalizedLevel >= 5) resources.tieflingLegacyLevel5 = { current: 1, max: 1, recovery: "long" };
    return resources;
  }
  return {};
}

function defaultDnd5eSrdSpeciesResourcesForData(data: Record<string, unknown>, level: number): Record<string, Record<string, unknown> & { current: number; max: number }> {
  const origin = recordValue(data.origin);
  const speciesId = stringValue(origin.speciesId) ?? stringValue(data.species);
  if (!speciesId) return {};
  const species = dnd5eSrdSpeciesById(speciesId);
  if (!species) return {};
  return dnd5eSrdSpeciesResources(species, dnd5eSrdProficiencyBonusForLevel(level, data.proficiencyBonus), level, data);
}

function dnd5eSrdApplyDwarvenToughness(data: Record<string, unknown>, levels: number): void {
  const hp = normalizePool(data.hp, 1);
  const bonus = Math.max(1, Math.floor(levels));
  data.hp = {
    current: hp.current + bonus,
    max: hp.max + bonus
  };
}

function dnd5eSrdDragonbornAncestryChoices(
  species: Dnd5eSrdCharacterSpecies,
  options: Dnd5eSrdCharacterOriginOptions
): { origin: Record<string, unknown>; resistances: string[] } {
  const value: unknown = options.draconicAncestry;
  if (species.id !== "dragonborn") {
    if (value !== undefined) throw new Error("D&D SRD Draconic Ancestry is only available to Dragonborn characters");
    return { origin: {}, resistances: [] };
  }
  if (value === undefined) return { origin: {}, resistances: [] };
  if (typeof value !== "string" || !value.trim()) throw new Error("D&D SRD Draconic Ancestry must be a supported dragon identifier");
  const ancestor = dnd5eSrdDraconicAncestorById(value);
  if (!ancestor) throw new Error("Unknown D&D SRD Draconic Ancestry");
  return {
    origin: {
      draconicAncestry: ancestor.id,
      draconicAncestryName: ancestor.name,
      draconicAncestryDamageType: ancestor.damageType
    },
    resistances: [ancestor.damageType]
  };
}

function dnd5eSrdGoliathAncestryChoices(
  species: Dnd5eSrdCharacterSpecies,
  options: Dnd5eSrdCharacterOriginOptions
): { origin: Record<string, unknown> } {
  const value: unknown = options.giantAncestry;
  if (species.id !== "goliath") {
    if (value !== undefined) throw new Error("D&D SRD Giant Ancestry is only available to Goliath characters");
    return { origin: {} };
  }
  if (value === undefined) return { origin: {} };
  if (typeof value !== "string" || !value.trim()) throw new Error("D&D SRD Giant Ancestry must be a supported giant identifier");
  const ancestry = dnd5eSrdGiantAncestryById(value);
  if (!ancestry) throw new Error("Unknown D&D SRD Giant Ancestry");
  return {
    origin: {
      giantAncestry: ancestry.id,
      giantAncestryBenefit: ancestry.name,
      giantAncestryType: ancestry.giantType
    }
  };
}

function dnd5eSrdHumanOriginChoices(
  species: Dnd5eSrdCharacterSpecies,
  options: Dnd5eSrdCharacterOriginOptions,
  background: Dnd5eSrdCharacterBackground,
  classSkillProficiencies: string[] = []
): { origin: Record<string, unknown>; skillProficiencies: string[]; feats: string[] } {
  const skillProficiency = stringValue(options.skillProficiency);
  const originFeat = stringValue(options.originFeat);
  if (species.id !== "human") {
    if (skillProficiency) throw new Error("D&D SRD Skillful skill choice is only available to Human characters");
    if (originFeat) throw new Error("D&D SRD Versatile origin feat choice is only available to Human characters");
    return { origin: {}, skillProficiencies: [], feats: [] };
  }
  const origin: Record<string, unknown> = { resourceful: true };
  const skillProficiencies: string[] = [];
  if (skillProficiency) {
    const skillId = normalizeDnd5eSrdSkillId(skillProficiency);
    const skill = dnd5eSrdSkills().find((candidate) => candidate.id === skillId);
    if (!skill) throw new Error("D&D SRD Human Skillful requires a valid skill proficiency");
    if (background.skillProficiencies.includes(skill.id)) throw new Error(`D&D SRD Human Skillful already has ${skill.label} from ${background.name}`);
    if (classSkillProficiencies.includes(skill.id)) throw new Error(`D&D SRD Human Skillful already has ${skill.label} from the character's class`);
    origin.humanSkillProficiency = skill.id;
    skillProficiencies.push(skill.id);
  }
  const feat = originFeat ?? "Skilled";
  origin.humanOriginFeat = feat;
  return { origin, skillProficiencies, feats: [feat] };
}

function dnd5eSrdAssertSpeciesSpellcastingAbilityAvailable(species: Dnd5eSrdCharacterSpecies, options: Dnd5eSrdCharacterOriginOptions): void {
  if (!stringValue(options.speciesSpellcastingAbility)) return;
  if (species.id !== "elf" && species.id !== "gnome" && species.id !== "tiefling") throw new Error("D&D SRD species spellcasting ability choice is only available to Elf, Gnome, or Tiefling characters");
}

function dnd5eSrdElfOriginChoices(
  species: Dnd5eSrdCharacterSpecies,
  options: Dnd5eSrdCharacterOriginOptions
): { origin: Record<string, unknown>; items: CharacterTemplateItem[]; senses?: string[]; speed?: number } {
  const lineageChoice = stringValue(options.elfLineage);
  const cantripChoice = stringValue(options.elfCantrip);
  if (species.id !== "elf") {
    if (lineageChoice) throw new Error("D&D SRD Elven Lineage choice is only available to Elf characters");
    if (cantripChoice) throw new Error("D&D SRD High Elf cantrip choice is only available to Elf characters");
    return { origin: {}, items: [] };
  }
  const lineageId = normalizeDnd5eSrdElfLineageId(lineageChoice ?? "high-elf");
  const lineage = DND_5E_SRD_ELF_LINEAGES[lineageId];
  if (!lineage) throw new Error("D&D SRD Elf Elven Lineage must be Drow, High Elf, or Wood Elf");
  if (cantripChoice && lineage.id !== "high-elf") throw new Error("D&D SRD Elf cantrip replacement is only available to High Elf characters");
  const cantrip = lineage.id === "high-elf" ? dnd5eSrdHighElfCantrip(cantripChoice ?? lineage.cantrip) : lineage.cantrip;
  const spellcastingAbility = dnd5eSrdSpeciesSpellcastingAbility(stringValue(options.speciesSpellcastingAbility) ?? "intelligence");
  const baseSpellData = {
    speciesSpell: true,
    originSpell: "elf",
    elfLineage: lineage.id,
    spellcastingAbility,
    prepared: true,
    alwaysPrepared: true,
    spellSources: [{ kind: "species", speciesId: "elf", lineageId: lineage.id, selectedAtLevel: 1 }]
  };
  return {
    origin: {
      elfLineage: lineage.id,
      elfLineageName: lineage.name,
      speciesSpellcastingAbility: spellcastingAbility,
      elfCantrip: cantrip,
      elfLevel3Spell: lineage.level3Spell,
      elfLevel5Spell: lineage.level5Spell
    },
    items: [
      { entryId: cantrip, data: { ...baseSpellData, trait: "Elven Lineage" } },
      { entryId: lineage.level3Spell, data: { ...baseSpellData, trait: "Elven Lineage", minimumCharacterLevel: 3, speciesSpellResource: "elfLineageLevel3", speciesSpellResourceLabel: "Elf Level 3 Lineage Spell" } },
      { entryId: lineage.level5Spell, data: { ...baseSpellData, trait: "Elven Lineage", minimumCharacterLevel: 5, speciesSpellResource: "elfLineageLevel5", speciesSpellResourceLabel: "Elf Level 5 Lineage Spell" } }
    ],
    senses: lineage.senses,
    speed: lineage.speed
  };
}

function dnd5eSrdGnomeOriginChoices(
  species: Dnd5eSrdCharacterSpecies,
  options: Dnd5eSrdCharacterOriginOptions
): { origin: Record<string, unknown>; items: CharacterTemplateItem[] } {
  const lineageChoice = stringValue(options.gnomeLineage);
  if (species.id !== "gnome") {
    if (lineageChoice) throw new Error("D&D SRD Gnomish Lineage choice is only available to Gnome characters");
    return { origin: {}, items: [] };
  }
  const lineageId = normalizeDnd5eSrdGnomeLineageId(lineageChoice ?? "forest-gnome");
  const lineage = DND_5E_SRD_GNOME_LINEAGES[lineageId];
  if (!lineage) throw new Error("D&D SRD Gnome Gnomish Lineage must be Forest Gnome or Rock Gnome");
  const spellcastingAbility = dnd5eSrdSpeciesSpellcastingAbility(stringValue(options.speciesSpellcastingAbility) ?? "intelligence");
  const baseSpellData = {
    speciesSpell: true,
    originSpell: "gnome",
    gnomeLineage: lineage.id,
    spellcastingAbility,
    prepared: true,
    alwaysPrepared: true,
    spellSources: [{ kind: "species", speciesId: "gnome", lineageId: lineage.id, selectedAtLevel: 1 }]
  };
  const items: CharacterTemplateItem[] = lineage.cantrips.map((entryId) => ({ entryId, data: { ...baseSpellData, trait: "Gnomish Lineage" } }));
  if (lineage.spell) {
    items.push({ entryId: lineage.spell, data: { ...baseSpellData, trait: "Gnomish Lineage", speciesSpellResource: "gnomeSpeakWithAnimals", speciesSpellResourceLabel: "Gnome Speak with Animals" } });
  }
  return {
    origin: {
      gnomeLineage: lineage.id,
      gnomeLineageName: lineage.name,
      speciesSpellcastingAbility: spellcastingAbility,
      gnomeCantrips: [...lineage.cantrips],
      ...(lineage.spell ? { gnomeSpell: lineage.spell } : {}),
      ...(lineage.clockworkDevice ? { gnomeClockworkDevice: true } : {})
    },
    items
  };
}

function dnd5eSrdTieflingOriginChoices(
  species: Dnd5eSrdCharacterSpecies,
  options: Dnd5eSrdCharacterOriginOptions
): { origin: Record<string, unknown>; resistances: string[]; items: CharacterTemplateItem[] } {
  const legacyChoice = stringValue(options.tieflingLegacy);
  const abilityChoice = stringValue(options.speciesSpellcastingAbility);
  if (species.id !== "tiefling") {
    if (legacyChoice) throw new Error("D&D SRD Fiendish Legacy choice is only available to Tiefling characters");
    return { origin: {}, resistances: [], items: [] };
  }
  const legacyId = normalizeDnd5eSrdOriginId(legacyChoice ?? "infernal") as Dnd5eSrdTieflingLegacyId;
  const legacy = DND_5E_SRD_TIEFLING_LEGACIES[legacyId];
  if (!legacy) throw new Error("D&D SRD Tiefling Fiendish Legacy must be Abyssal, Chthonic, or Infernal");
  const spellcastingAbility = dnd5eSrdSpeciesSpellcastingAbility(abilityChoice ?? "charisma");
  const baseSpellData = {
    speciesSpell: true,
    originSpell: "tiefling",
    tieflingLegacy: legacy.id,
    spellcastingAbility,
    prepared: true,
    alwaysPrepared: true,
    spellSources: [{ kind: "species", speciesId: "tiefling", legacyId: legacy.id, selectedAtLevel: 1 }]
  };
  const origin = {
    tieflingLegacy: legacy.id,
    tieflingLegacyName: legacy.name,
    speciesSpellcastingAbility: spellcastingAbility,
    tieflingResistance: legacy.resistance,
    tieflingCantrip: legacy.cantrip,
    tieflingLevel3Spell: legacy.level3Spell,
    tieflingLevel5Spell: legacy.level5Spell
  };
  return {
    origin,
    resistances: [legacy.resistance],
    items: [
      { entryId: "thaumaturgy", data: { ...baseSpellData, trait: "Otherworldly Presence" } },
      { entryId: legacy.cantrip, data: { ...baseSpellData, trait: "Fiendish Legacy" } },
      { entryId: legacy.level3Spell, data: { ...baseSpellData, trait: "Fiendish Legacy", minimumCharacterLevel: 3, speciesSpellResource: "tieflingLegacyLevel3", speciesSpellResourceLabel: "Tiefling Level 3 Legacy Spell" } },
      { entryId: legacy.level5Spell, data: { ...baseSpellData, trait: "Fiendish Legacy", minimumCharacterLevel: 5, speciesSpellResource: "tieflingLegacyLevel5", speciesSpellResourceLabel: "Tiefling Level 5 Legacy Spell" } }
    ]
  };
}

function dnd5eSrdSpeciesSpellcastingAbility(value: string): string {
  const ability = normalizeDnd5eSrdOriginId(value);
  if (!DND_5E_SRD_SPECIES_SPELLCASTING_ABILITIES.includes(ability)) throw new Error("D&D SRD species spellcasting ability must be Intelligence, Wisdom, or Charisma");
  return ability;
}

function normalizeDnd5eSrdElfLineageId(value: string): Dnd5eSrdElfLineageId {
  const id = normalizeDnd5eSrdOriginId(value);
  if (id === "high") return "high-elf";
  if (id === "wood") return "wood-elf";
  return id as Dnd5eSrdElfLineageId;
}

function normalizeDnd5eSrdGnomeLineageId(value: string): Dnd5eSrdGnomeLineageId {
  const id = normalizeDnd5eSrdOriginId(value);
  if (id === "forest") return "forest-gnome";
  if (id === "rock") return "rock-gnome";
  return id as Dnd5eSrdGnomeLineageId;
}

function dnd5eSrdGnomeLineageById(value: string): Dnd5eSrdGnomeLineage | undefined {
  return DND_5E_SRD_GNOME_LINEAGES[normalizeDnd5eSrdGnomeLineageId(value)];
}

function dnd5eSrdHighElfCantrip(value: string): string {
  const cantrip = normalizeDnd5eSrdOriginId(value);
  if (!DND_5E_SRD_HIGH_ELF_WIZARD_CANTRIPS.includes(cantrip)) throw new Error("D&D SRD High Elf cantrip must be a compendium-backed Wizard cantrip");
  return cantrip;
}

function dnd5eSrdApplyAbilityScoreIncreases(data: Record<string, unknown>, background: Dnd5eSrdCharacterBackground, increases: unknown): void {
  const source = recordValue(increases);
  const entries = Object.entries(source)
    .map(([ability, value]) => [normalizeDnd5eSrdOriginId(ability), Math.floor(numericValue(value, Number.NaN))] as const)
    .filter(([, value]) => Number.isFinite(value) && value > 0);
  if (entries.length === 0) return;
  const defaultAttributes = defaultDnd5eSrdAttributes();
  const allowedAbilities = new Set(background.abilityScores);
  const seen = new Set<string>();
  for (const [ability, value] of entries) {
    if (!(ability in defaultAttributes)) throw new Error("D&D SRD ability score increases must use a valid ability");
    if (!allowedAbilities.has(ability)) throw new Error(`D&D SRD ${background.name} ability increases can only use ${background.abilityScores.join(", ")}`);
    if (seen.has(ability)) throw new Error("D&D SRD ability score increases cannot repeat an ability");
    if (value !== 1 && value !== 2) throw new Error("D&D SRD ability score increases must be 1 or 2");
    seen.add(ability);
  }
  const values = entries.map(([, value]) => value).sort((a, b) => b - a);
  const validSpread = values.length === 2 && values[0] === 2 && values[1] === 1;
  const validThreeOnes = values.length === 3 && values.every((value) => value === 1);
  if (!validSpread && !validThreeOnes) throw new Error("D&D SRD ability score increases must be +2/+1 or +1/+1/+1");
  const attributes = normalizeNumberRecord(data.attributes, defaultAttributes);
  const applied: Record<string, number> = {};
  for (const [ability, value] of entries) {
    const nextScore = Math.min(20, numericValue(attributes[ability], 10) + value);
    attributes[ability] = nextScore;
    applied[ability] = value;
  }
  data.attributes = attributes;
  data.origin = { ...recordValue(data.origin), abilityScoreIncreases: applied };
}

function dnd5eSrdCurrency(value: unknown): Record<string, number> {
  if (typeof value === "number" && Number.isFinite(value)) return dnd5eSrdCurrencyFromCopper(Math.max(0, Math.floor(value * 100)));
  return dnd5eSrdCurrencyFromCopper(dnd5eSrdCurrencyToCopper(value));
}

function dnd5eSrdCurrencyToCopper(value: unknown): number {
  const source = recordValue(value);
  const cp = Math.max(0, Math.floor(numericValue(source.cp, 0)));
  const sp = Math.max(0, Math.floor(numericValue(source.sp, 0)));
  const ep = Math.max(0, Math.floor(numericValue(source.ep, 0)));
  const gp = Math.max(0, Math.floor(numericValue(source.gp, 0)));
  const pp = Math.max(0, Math.floor(numericValue(source.pp, 0)));
  return cp + sp * 10 + ep * 50 + gp * 100 + pp * 1000;
}

function dnd5eSrdCurrencyFromCopper(copper: number): Record<string, number> {
  const safeCopper = Math.max(0, Math.floor(copper));
  const gp = Math.floor(safeCopper / 100);
  const sp = Math.floor((safeCopper % 100) / 10);
  const cp = safeCopper % 10;
  return { gp, sp, cp };
}

function dnd5eSrdFormatGp(copper: number): string {
  const currency = dnd5eSrdCurrencyFromCopper(copper) as { gp: number; sp: number; cp: number };
  return `${currency.gp + currency.sp / 10 + currency.cp / 100} GP`;
}

function stellarFrontiersAptitudeModifier(actor: Actor, aptitude: string): number {
  const aptitudes = actor.data.aptitudes as Record<string, number> | undefined;
  return numericValue(aptitudes?.[aptitude], 0);
}

function mysticNoirSkillModifier(actor: Actor, skill: string): number {
  const skills = actor.data.skills as Record<string, number> | undefined;
  return numericValue(skills?.[skill], 1);
}

function resolveGenericFantasyFormulaTokens(formula: string, actor: Actor): string {
  return formula
    .replace(/([+-]?)@spellcasting\b/g, (_match, operator: string) => {
      const className = stringValue(actor.data.class) || "";
      const ability = actor.systemId === DND_5E_SRD_SYSTEM_ID ? dnd5eSrdPrimaryAbility(className) : className === "Mender" ? "wisdom" : "charisma";
      const modifier = genericFantasyAttributeModifier(actor, ability);
      const signedModifier = operator === "-" ? -modifier : modifier;
      return operator ? formatSignedNumber(signedModifier) : String(signedModifier);
    })
    .replace(/([+-]?)@attributes\.([A-Za-z0-9_-]+)/g, (_match, operator: string, ability: string) => {
      const modifier = genericFantasyAttributeModifier(actor, ability);
      const signedModifier = operator === "-" ? -modifier : modifier;
      return operator ? formatSignedNumber(signedModifier) : String(signedModifier);
    });
}

function genericFantasyHealingFormula(actor: Actor, data: Record<string, unknown>, spellSlotLevel?: number): string {
  const baseFormula = resolveGenericFantasyFormulaTokens(stringValue(data.healingFormula) ?? "0", actor);
  const spellLevel = Math.floor(numericValue(data.level, 0));
  const slotLevel = spellActionSlotLevel(spellLevel, spellSlotLevel);
  const upcastFormula = stringValue(data.upcastFormula);
  let formula = spellLevel <= 0 || slotLevel <= spellLevel || !upcastFormula ? baseFormula : appendFormulaTerm(baseFormula, scaleDiceFormula(resolveGenericFantasyFormulaTokens(upcastFormula, actor), slotLevel - spellLevel));
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID && spellLevel > 0 && dnd5eSrdHasLifeDisciple(actor)) {
    formula = appendFormulaTerm(formula, dnd5eSrdLifeSlotBonusFormula(slotLevel));
  }
  if (actor.systemId === DND_5E_SRD_SYSTEM_ID && dnd5eSrdHasLifeSupremeHealing(actor)) {
    formula = maximizeDiceTerms(formula);
  }
  return formula;
}

function maximizeDiceTerms(formula: string): string {
  return formula.replace(/\b(\d*)d(\d+)\b/gi, (_match, count: string, sides: string) => String(numericValue(count ? Number(count) : 1, 1) * numericValue(Number(sides), 0)));
}

function genericFantasyDamageFormula(actor: Actor, data: Record<string, unknown>, spellSlotLevel?: number, formulaKey = "damageFormula", upcastKey = "upcastFormula"): string {
  const baseFormula = resolveGenericFantasyFormulaTokens(stringValue(data[formulaKey]) ?? "0", actor);
  const spellLevel = Math.floor(numericValue(data.level, 0));
  const scaledBaseFormula = formulaKey === "damageFormula" && spellLevel <= 0 ? genericFantasyCantripDamageFormula(actor, data, baseFormula) : baseFormula;
  const slotLevel = spellActionSlotLevel(spellLevel, spellSlotLevel);
  const upcastFormula = stringValue(data[upcastKey]);
  let formula = spellLevel <= 0 || slotLevel <= spellLevel || !upcastFormula ? scaledBaseFormula : appendFormulaTerm(scaledBaseFormula, scaleDiceFormula(resolveGenericFantasyFormulaTokens(upcastFormula, actor), slotLevel - spellLevel));
  if (dnd5eSrdAppliesEmpoweredEvocation(actor, data, formulaKey)) {
    formula = appendFormulaTerm(formula, dnd5eSrdEvokerEmpoweredEvocationFormula(actor));
  }
  return formula;
}

function dnd5eSrdAppliesEmpoweredEvocation(actor: Actor, data: Record<string, unknown>, formulaKey: string): boolean {
  if (actor.systemId !== DND_5E_SRD_SYSTEM_ID || formulaKey !== "damageFormula") return false;
  if (!dnd5eSrdHasEvokerEmpoweredEvocation(actor)) return false;
  if ((stringValue(data.school) ?? "").toLowerCase() !== "evocation") return false;
  return Boolean(stringValue(data.damageFormula));
}

function genericFantasyCantripDamageFormula(actor: Actor, data: Record<string, unknown>, baseFormula: string): string {
  const scaling = recordValue(data.cantripScaling);
  const actorLevel = dnd5eSrdCharacterLevel(actor);
  for (const level of [17, 11, 5]) {
    if (actorLevel < level) continue;
    const formula = stringValue(scaling[`level${level}`]);
    if (formula) return resolveGenericFantasyFormulaTokens(formula, actor);
  }
  return baseFormula;
}

function dnd5eSrdSpeciesResourceAction(rollId: string): { key: string; label: string } | undefined {
  if (rollId === DND_5E_SRD_DRAGONBORN_BREATH_WEAPON_ROLL_ID) return { key: "breathWeapon", label: "Breath Weapon" };
  if (rollId === DND_5E_SRD_DRACONIC_FLIGHT_ROLL_ID) return { key: "draconicFlight", label: "Draconic Flight" };
  if (rollId === DND_5E_SRD_DWARF_STONECUNNING_ROLL_ID) return { key: "stonecunning", label: "Stonecunning" };
  if (rollId === DND_5E_SRD_GOLIATH_GIANT_ANCESTRY_ROLL_ID) return { key: "giantAncestry", label: "Giant Ancestry" };
  if (rollId === DND_5E_SRD_GOLIATH_LARGE_FORM_ROLL_ID) return { key: "largeForm", label: "Large Form" };
  if (rollId === DND_5E_SRD_ORC_ADRENALINE_RUSH_ROLL_ID) return { key: "adrenalineRush", label: "Adrenaline Rush" };
  if (rollId === DND_5E_SRD_ORC_RELENTLESS_ENDURANCE_ROLL_ID) return { key: "relentlessEndurance", label: "Relentless Endurance" };
  return undefined;
}

function dnd5eSrdHasSpeciesFeature(actor: Actor, featureName: string, resourceKey?: string): boolean {
  const features = normalizeStringArray(actor.data.features);
  const resources = recordValue(actor.data.resources);
  return features.includes(featureName) || Boolean(resourceKey && resourceKey in resources);
}

